import type { Phase } from "./curriculum";
import { PHASE0 } from "./phase0-data";

export const PHASES: Phase[] = [PHASE0,
{id:1,label:"Phase 1",name:"Drupal Fundamentals",color:"#7c6cf5",bg:"#1a1830",weeks:[
{label:"Week 1",name:"Mental model & environment",days:[
{day:"Day 1",title:"Drupal vs. WordPress vs. Laravel",goal:"Understand where Drupal sits in the CMS/framework landscape and why each tool exists.",
reading:[
{title:"What makes Drupal different",body:"Drupal is a <strong>structured content framework</strong> — not a blogging tool (WP) or a code framework (Laravel). It provides a full entity system, configuration management, and a hook/event system out of the box.",link:null},
{title:"WordPress",body:"Great for blogs and simple sites. PHP but minimal structure. Plugins are quick wins but become tech debt fast. No entity system, no CMI.",link:null},
{title:"Laravel",body:"A PHP framework — no CMS at all. You build everything from scratch. Maximum flexibility, maximum effort. Drupal sits between WP (easy) and Laravel (total control).",link:"https://www.drupal.org/docs/understanding-drupal"},
{title:"When to choose Drupal",body:"Enterprise content sites, multi-language, complex permissions, structured content with multiple entity types, decoupled frontends. Drupal shines when content is complex and structured.",link:null},
],
activity:{type:"quiz",questions:[
{q:"A client needs a marketing blog with 3 pages and a contact form, launching in 2 weeks. Which tool is most appropriate?",options:["Drupal","WordPress","Laravel","They're all equally good"],answer:1,explanation:"WordPress is the right call here. Drupal's learning curve and setup overhead are overkill for a simple marketing blog. Use the right tool for the job."},
{q:"Which of these is a core strength of Drupal that WordPress does NOT have natively?",options:["Blog post creation","A visual page builder","A structured entity system with configuration management","PHP support"],answer:2,explanation:"Drupal's entity system (nodes, taxonomy, users, custom entities) and CMI (configuration management) are built-in and production-grade. WordPress has neither natively."},
{q:"Drupal uses a hook system. What best describes what a hook does?",options:["It connects Drupal to external APIs","It lets modules react to or alter Drupal's behavior at defined points","It is a Git integration feature","It provides CSS styling hooks for themes"],answer:1,explanation:"Hooks are named functions Drupal calls at specific lifecycle points. Any module implementing a hook gets to participate — without modifying core code."},
{q:"You need to build a site with 8 content types, multilingual support, complex editorial workflows, and a React front-end consuming data via API. Which is the best fit?",options:["WordPress","Laravel","Drupal","Any of these with enough plugins"],answer:2,explanation:"This is Drupal's home territory — structured content, multilingual support via core, built-in JSON:API, and robust editorial workflows are all first-class Drupal features."},
]}},
{day:"Day 2",title:"Set up DDEV local environment",goal:"Get a fully working Drupal 10/11 site running locally with DDEV.",
reading:[
{title:"What DDEV is",body:"DDEV is a local development environment using Docker under the hood. For Drupal it provides PHP, MySQL, Nginx, and Drush pre-configured — no manual LAMP stack setup.",link:"https://ddev.readthedocs.io/en/stable/"},
{title:"Why not XAMPP/WAMP?",body:"DDEV gives you per-project PHP versions, isolated databases, and a workflow that matches production. Since you already have DDEV experience from previous projects, this should be fast.",link:null},
],
activity:{type:"hands_on",title:"Verify your DDEV + Drupal setup",intro:"Run through these steps and use the AI check to verify everything is working.",steps:[
{n:1,title:"Create a new project directory and configure DDEV",body:"Create a fresh folder and tell DDEV what kind of project it is. The project-type=drupal10 flag pre-configures the web root, PHP version, and nginx settings for Drupal.",code:"mkdir my-drupal && cd my-drupal\nddev config --project-type=drupal10 --project-name=my-drupal\nddev start"},
{n:2,title:"Scaffold the Drupal codebase with Composer",body:"Drupal's recommended-project template pulls core, vendor libraries, and the correct folder structure. The dot at the end installs into the current directory — not a subdirectory.",code:"ddev composer create drupal/recommended-project ."},
{n:3,title:"Run the Drupal installer",body:"site:install runs the full Drupal installation in one command. --account-pass=admin sets the admin user password. -y skips confirmation prompts. This creates all database tables and base configuration.",code:"ddev drush site:install --account-pass=admin -y"},
{n:4,title:"Launch the site in your browser",body:"ddev launch opens your default browser to the site. Your local URL is typically https://my-drupal.ddev.site. Log in at /user with admin / admin.",code:"ddev launch"},
{n:5,title:"Verify Drush and check system status",body:"drush status is your quick health check. Look for: Drupal bootstrap = Successful, Database = Connected, Drupal version = 10.x or 11.x. If bootstrap shows anything other than Successful, something is broken.",code:"ddev drush status\n# Expected: Drupal version: 10.x.x, Database: Connected, Bootstrap: Successful"},
{n:6,title:"Run a test Drush command",body:"This confirms Drush can execute PHP in context. The output should be a semantic version number like 10.3.6.",code:"ddev drush core:status | grep 'Drupal version'\n# Or directly:\nddev drush php:eval \"echo \\Drupal::VERSION;\""},
],aiCheck:{prompt:"Paste the output of `ddev drush status` below. I'll verify your setup is correct and flag any issues.",checkGoal:"Verify the student has a working DDEV + Drupal setup by checking drush status output for: Drupal version (10 or 11), database connected, bootstrap done. Give specific feedback on any issues found."}}},
{day:"Day 3",title:"The Entity System",goal:"Understand Drupal's entity system — the foundation of everything in Drupal.",
reading:[
{title:"What is an entity?",body:"In Drupal, almost everything is an entity. Nodes (content), taxonomy terms, users, comments, files, blocks — all are entities. They share a common API for CRUD operations, field support, and rendering.",link:"https://api.drupal.org/api/drupal/core!lib!Drupal!Core!Entity!entity.api.php/group/entity_api"},
{title:"Content entities vs. config entities",body:"<strong>Content entities</strong> store user data (nodes, users, taxonomy terms) in the database. <strong>Config entities</strong> store site configuration (content types, views, image styles) — exported to YAML files.",link:null},
{title:"Entity types and bundles",body:"An entity type is the base (e.g. Node). A bundle is a specific type of it (e.g. Article, Page). Fields are attached to bundles. This is your content model.",link:null},
{title:"The EntityTypeManager",body:"The primary service for working with entities in code. Use it to load, create, query, and delete entities. You'll use this constantly in custom modules.",link:null},
],
activity:{type:"combined",questions:[
{q:"You create a 'News Article' content type in Drupal. In entity terms, what is 'Node' and what is 'News Article'?",options:["Node is the bundle, News Article is the entity type","Node is the entity type, News Article is the bundle","They are both entity types","They are both bundles"],answer:1,explanation:"Node is the entity type — the base class. 'News Article' is a bundle — a specific configuration of the Node entity type with its own fields."},
{q:"You export your Drupal configuration and find a file called node.type.article.yml. What kind of entity is this?",options:["A content entity — it stores user data","A config entity — it defines site configuration","A field entity","A view entity"],answer:1,explanation:"Content type definitions are config entities. They define the structure (bundle) but don't contain the actual articles — those are content entities stored in the database."},
{q:"Which service would you use in a custom module to programmatically load a node with ID 42?",options:["\\Drupal::database()","\\Drupal::entityTypeManager()","\\Drupal::config()","\\Drupal::service('node')"],answer:1,explanation:"\\Drupal::entityTypeManager()->getStorage('node')->load(42) is the correct approach. Always use the Entity API rather than direct database queries for entity operations."},
],title:"Explore the Entity System",intro:"Build a Product content type and query it programmatically — the same pattern you'll use in every real Drupal project.",steps:[
{n:1,title:"Create a Product Category taxonomy vocabulary",body:"Taxonomy vocabularies organise content classification. The vocabulary machine name (product_category) is how you'll reference it when attaching the term reference field to your content type. Go to Admin → Structure → Taxonomy → Add vocabulary. Name: Product Category, machine name: product_category. Save. Then click 'List terms' and add three terms one at a time: Electronics, Clothing, Books.",},
{n:2,title:"Create the Product content type",body:"Content types are config entities — they define the structure of your content but don't hold the content itself. Go to Admin → Structure → Content types → Add content type. Name: Product, machine name: product, Description: A purchasable product. Under Submission form settings, change the Title field label to 'Product Name'. Click Save and manage fields.",},
{n:3,title:"Add a Price field (Number decimal)",body:"Decimal fields store precise monetary values without floating-point rounding errors. Click Add field → Number (decimal). Label: Price, machine name: field_price. Save and continue. Settings: Precision 10, Scale 2, Minimum 0. Save field settings. On the instance settings page: Required → YES. Save settings.",},
{n:4,title:"Add a Category reference field (Taxonomy term)",body:"Entity reference fields are how Drupal models relationships. Click Add field → Reference → Taxonomy term. Label: Category, machine name: field_category. Save and continue. Reference method: Default. Vocabularies: check Product Category. Save settings. This links a Product to one or more terms in your vocabulary.",},
{n:5,title:"Add a Featured boolean field",body:"Boolean fields are stored as 0/1 integers in the database, but exposed as checkboxes in the UI. Click Add field → General → Boolean. Label: Featured, machine name: field_featured. Save and continue. On label: Featured product, Off label: Not featured. Default value: No (unchecked). Save settings.",},
{n:6,title:"Add a Stock Count integer field",body:"Integer fields store whole numbers. Click Add field → Number (integer). Label: Stock Count, machine name: field_stock_count. Minimum: 0. Not required. Save settings.",},
{n:7,title:"Create a test Product node",body:"Go to Admin → Content → Add content → Product (or /node/add/product). Fill in: Product Name: MacBook Air M3, Price: 1299.00, Category: Electronics, Featured: checked, Stock Count: 50. Click Save. Note the node ID from the URL — you'll use it in the next step.",},
{n:8,title:"Load the node and read field values with Drush",body:"entityTypeManager()->getStorage('node')->load(ID) is the standard way to load any content entity. referencedEntities() resolves a taxonomy reference to the actual term object, letting you call getName(). This is the Entity API — never use raw SQL to read entity data.",code:"ddev drush php:eval \"\n\\$node = \\Drupal::entityTypeManager()->getStorage('node')->load(1);\nif (\\$node) {\n  echo 'Title: ' . \\$node->getTitle() . PHP_EOL;\n  echo 'Price: ' . \\$node->get('field_price')->value . PHP_EOL;\n  echo 'Featured: ' . (\\$node->get('field_featured')->value ? 'Yes' : 'No') . PHP_EOL;\n  \\$terms = \\$node->get('field_category')->referencedEntities();\n  if (!empty(\\$terms)) {\n    echo 'Category: ' . \\$terms[0]->getName() . PHP_EOL;\n  }\n}\n\"\n# Replace load(1) with your actual node ID if different\n# Expected:\n# Title: MacBook Air M3\n# Price: 1299.00\n# Featured: Yes\n# Category: Electronics"},
{n:9,title:"Query multiple nodes with EntityQuery",body:"EntityQuery is Drupal's safe, API-level way to query entity storage. It respects access control (accessCheck), supports conditions, sorting, and range limiting. Create 2 more Product nodes in the browser first, then run this query.",code:"ddev drush php:eval \"\n\\$storage = \\Drupal::entityTypeManager()->getStorage('node');\n\\$ids = \\$storage->getQuery()\n  ->accessCheck(TRUE)\n  ->condition('type', 'product')\n  ->condition('status', 1)\n  ->condition('field_price', 100, '>')\n  ->sort('field_price', 'DESC')\n  ->execute();\necho 'Found ' . count(\\$ids) . ' products over \\$100:' . PHP_EOL;\nforeach (\\$storage->loadMultiple(\\$ids) as \\$n) {\n  echo '  - ' . \\$n->getTitle() . ': \\$' . \\$n->get('field_price')->value . PHP_EOL;\n}\n\""},
{n:10,title:"Export the config",body:"The Product content type and all its fields are configuration — not content. Running cex captures them as YAML files in config/sync/. You should see separate files for field storage (how the data is stored) and field instance (how it behaves on this content type). Notice node.type.product.yml and field.field.node.product.field_price.yml both exist.",code:"ddev drush cex -y\nls config/sync/ | grep 'node.type.product'\nls config/sync/ | grep 'field.field.node.product'\n# Expected files:\n# node.type.product.yml\n# field.field.node.product.field_category.yml\n# field.field.node.product.field_featured.yml\n# field.field.node.product.field_price.yml\n# field.field.node.product.field_stock_count.yml"},
],aiCheck:{prompt:"Paste the complete output of the drush php:eval command that loaded the node (step 8). Does the price show as 1299.00? Does the category term name load as 'Electronics'? Also paste the output of `ls config/sync/ | grep 'field.field.node.product'`.",checkGoal:"Verify the student created a Product content type with correct field types and can load entity data programmatically. Check: node loads via entityTypeManager, field values are correct, taxonomy term loads via referencedEntities(), entity query filters and sorts work, and config was exported. Give specific feedback on entity API usage and field type choices."}}},
{day:"Day 4",title:"Composer Workflow for Drupal",goal:"Master the Composer workflow that every professional Drupal developer uses daily.",
reading:[
{title:"Why Composer?",body:"Drupal 8+ moved to Composer for dependency management. Every module, library, and core update goes through Composer. Understanding it is non-negotiable for professional Drupal development.",link:"https://www.drupal.org/docs/develop/using-composer"},
{title:"Key commands",body:"<strong>composer require drupal/module_name</strong> — install a module. <strong>composer update drupal/core-* --with-all-dependencies</strong> — update core. <strong>composer show drupal/*</strong> — list installed Drupal packages.",link:null},
{title:"composer.json vs. composer.lock",body:"composer.json defines what you want. composer.lock records exactly what was installed. Commit both to Git. Never edit composer.lock manually.",link:null},
],
activity:{type:"hands_on",title:"Install and enable a contrib module via Composer",intro:"Practice the full Composer → Drush workflow for adding a module.",steps:[
{n:1,title:"Initialize a Git repository first",body:"Always commit your clean Drupal install before adding modules. This way git diff shows exactly what Composer changed — which files were added and what changed in composer.lock.",code:"git init && git add . && git commit -m 'Initial Drupal install'"},
{n:2,title:"Require the Admin Toolbar module via Composer",body:"drupal/admin_toolbar is the module's Composer package name. Composer downloads the module into web/modules/contrib/ and updates both composer.json (what you want) and composer.lock (exact versions installed). Never manually download modules.",code:"ddev composer require drupal/admin_toolbar"},
{n:3,title:"Enable the module subcomponents with Drush",body:"Admin Toolbar ships with sub-modules: admin_toolbar (the base) and admin_toolbar_tools (extra menu items). You must enable both. pm:enable also runs hook_install for each module.",code:"ddev drush pm:enable admin_toolbar admin_toolbar_tools -y"},
{n:4,title:"Rebuild caches",body:"After enabling a module, always rebuild caches. New hooks, routes, and services won't be recognized until the cache is cleared. drush cr is the fastest way.",code:"ddev drush cr"},
{n:5,title:"Verify the module is enabled",body:"This confirms both sub-modules are active. You should see two lines with 'Enabled' status. If a module shows 'Disabled', re-run pm:enable.",code:"ddev drush pm:list --status=enabled | grep admin_toolbar\n# Expected output:\n# admin_toolbar    Admin Toolbar    Enabled\n# admin_toolbar_tools  Admin Toolbar Extra Tools  Enabled"},
{n:6,title:"Confirm composer.lock was updated",body:"composer.lock records the exact version installed. It should always be committed to Git so every developer and every server uses the exact same versions.",code:"git diff composer.lock | head -30\n# You should see new entries for drupal/admin_toolbar"},
],aiCheck:{prompt:"Paste the output of `ddev drush pm:list --status=enabled | grep admin_toolbar`. I'll confirm the module is correctly installed.",checkGoal:"Verify the student has correctly installed and enabled the admin_toolbar module. Output should show admin_toolbar and admin_toolbar_tools with 'Enabled' status. Give specific feedback."}}},
{day:"Day 5",title:"Core vs. Contrib vs. Custom Modules",goal:"Know when to use core, when to reach for contrib, and when to write custom.",
reading:[
{title:"Core modules",body:"Ship with Drupal. Maintained by the core team. Examples: Views, Layout Builder, JSON:API, Media. Use core first — it's battle-tested with no additional maintenance burden.",link:null},
{title:"Contrib modules",body:"Community-maintained on drupal.org. Over 50,000 exist. Quality varies. Check: install count, active maintenance, Drupal 10/11 compatibility, and last release date.",link:"https://www.drupal.org/project/project_module"},
{title:"Custom modules",body:"Code you write yourself. Only build custom when core/contrib can't do it. Custom code = your maintenance burden forever.",link:null},
{title:"The decision framework",body:"Core → Contrib → Custom. Never hack core or contrib — use hooks and event subscribers to alter behavior instead. This is non-negotiable.",link:null},
],
activity:{type:"quiz",questions:[
{q:"A client needs a simple contact form on their Drupal site. What should you do?",options:["Build a custom module with Form API","Install the Contact contrib module","Enable Drupal core's Contact module","Use Views to build a form"],answer:2,explanation:"Drupal core ships with a Contact module. Always check core first. Zero maintenance overhead and battle-tested."},
{q:"You find a contrib module that does 80% of what you need, but requires patching its code for your edge case. Best approach?",options:["Patch the module files directly","Fork the module and maintain your own version","Write a custom module that alters behavior using hooks","Use a different contrib module"],answer:2,explanation:"Use hooks or event subscribers to alter behavior without touching contrib files. Your customization survives module updates. Direct patching breaks on every update."},
{q:"When evaluating a contrib module on drupal.org, which factors matter MOST?",options:["Number of screenshots on the project page","Active maintenance, Drupal 10/11 compatibility, install count, recent releases","Whether it has a video tutorial","The module's color scheme in the admin UI"],answer:1,explanation:"Unmaintained modules are security liabilities. Check: compatible with your Drupal version? Recent release? How many sites use it? Active maintainer?"},
]}},
{day:"Day 6",title:"Drush CLI Essentials",goal:"Build muscle memory with the Drush commands you'll use every single day.",
reading:[
{title:"What Drush is",body:"Drush (Drupal Shell) is the command-line tool for Drupal — like artisan for Laravel or wp-cli for WordPress, but more powerful. You'll use it constantly.",link:"https://www.drush.org/"},
{title:"Most-used commands",body:"<strong>drush cr</strong> — rebuild caches. <strong>drush cex/cim</strong> — export/import config. <strong>drush updb</strong> — run database updates. <strong>drush uli</strong> — generate a one-time login URL. <strong>drush php:eval</strong> — run arbitrary PHP.",link:null},
],
activity:{type:"hands_on",title:"Drush command drill",intro:"Run each command and make sure you understand the output.",steps:[
{n:1,title:"Rebuild all caches",body:"drush cr (cache-rebuild) is the most-used Drush command. Run it after: enabling/disabling modules, changing routing, modifying services.yml, or any time something 'should work but doesn't'. Expected output: [success] Cache rebuild complete.",code:"ddev drush cr\n# Expected: [success] Cache rebuild complete."},
{n:2,title:"Check site status",body:"drush status gives you an instant health report. Bookmark this mental model: Drupal version, PHP version, database connection, and webserver. If bootstrap fails, Drupal can't load at all.",code:"ddev drush status\n# Key lines to check:\n# Drupal version : 10.x.x\n# Database       : Connected\n# Bootstrap      : Successful"},
{n:3,title:"List all enabled modules",body:"This shows every active module. Pipe through grep to find specific modules. The list will be long on a default Drupal install — that's normal. Core ships with many modules.",code:"ddev drush pm:list --status=enabled\n# To find a specific module:\nddev drush pm:list --status=enabled | grep views"},
{n:4,title:"Export configuration to YAML files",body:"drush cex exports the entire active configuration to config/sync/ as YAML files. Each config object becomes its own .yml file. These files are committed to Git and imported on other environments. This is the CMI workflow.",code:"ddev drush cex -y\nls config/sync/ | head -10\nls config/sync/ | wc -l\n# You should see 50-120 YAML files — this is normal for a default install"},
{n:5,title:"Generate a one-time admin login link",body:"drush uli (user-login) generates a temporary login URL for user 1. Invaluable when you're locked out or testing on a remote environment where you can't log in normally.",code:"ddev drush uli\n# Copy the URL and open it — you'll be logged in as admin instantly"},
{n:6,title:"Run arbitrary PHP in Drupal context",body:"php:eval executes PHP with the full Drupal bootstrap loaded. You can call any Drupal API, load entities, call services. Essential for quick debugging.",code:"ddev drush php:eval \"echo \\Drupal::VERSION;\"\n# Expected: 10.3.x (or your installed version)\n\n# More useful example — load and print a node title:\nddev drush php:eval \"\\$n = \\Drupal::entityTypeManager()->getStorage('node')->load(1); echo \\$n ? \\$n->getTitle() : 'No node with ID 1';\""},
],aiCheck:{prompt:"After running `ddev drush cex -y`, paste the result of `ls config/sync/ | wc -l` (the count of config files exported). I'll verify your config export is working correctly.",checkGoal:"Verify the student has successfully exported Drupal configuration. They should show a number above 30 (typically 50-100+ YAML files). Give feedback and explain why config export is important in the professional workflow."}}},
{day:"Day 7",title:"Week 1 Review",goal:"Consolidate everything from Week 1 with a comprehensive open-ended challenge.",
reading:[
{title:"Review checklist",body:"Before answering, mentally test yourself: (1) Can you explain Drupal vs WP vs Laravel in 30 seconds? (2) Can you name 5 entity types? (3) Do you know the Composer+Drush workflow for adding a module? (4) Can you name 5 Drush commands?",link:null},
{title:"What's coming in Week 2",body:"Hooks, event subscribers, and services — the three mechanisms that make Drupal extensible. This is where Drupal development really begins.",link:null},
],
activity:{type:"ai_open",prompt:"Without looking at any notes, answer all three: (1) A client asks why you'd recommend Drupal over WordPress for their enterprise intranet. What do you say? (2) What is the difference between a content entity and a config entity — give a concrete example of each. (3) Walk me through the exact steps to add a new contrib module to a DDEV Drupal project.",checkGoal:"Evaluate the student's understanding across three areas: Drupal positioning, entity types distinction, and the Composer+Drush workflow. Score 0-10 and give specific constructive feedback. Look for: correct entity distinction with examples, correct Composer require + drush pm:enable workflow, and a compelling business case for Drupal."}},
]},
{label:"Week 2",name:"Hooks, events & services",days:[
{day:"Day 8",title:"How Drupal's Hook System Works",goal:"Understand Drupal's hook system — the original extension mechanism.",
reading:[
{title:"What is a hook?",body:"A hook is a named PHP function that Drupal calls at specific points. If your module is called mymodule, implementing mymodule_node_presave($node) means Drupal calls your function every time a node is about to be saved.",link:"https://api.drupal.org/api/drupal/core%21core.api.php/group/hooks"},
{title:"How Drupal discovers hooks",body:"Drupal scans for functions matching {module_name}_{hook_name}. This is why your module machine name matters — it's the prefix for all your hooks.",link:null},
{title:"Common hooks",body:"<strong>hook_entity_presave</strong> — before any entity saves. <strong>hook_form_alter</strong> — modify any form. <strong>hook_theme</strong> — register theme functions. <strong>hook_install</strong> — run code on module install.",link:null},
],
activity:{type:"quiz",questions:[
{q:"Your module is named news_manager. What is the correct function name to implement hook_node_presave?",options:["function hook_node_presave($node)","function node_presave_news_manager($node)","function news_manager_node_presave($node)","function news_manager::node_presave($node)"],answer:2,explanation:"Hook implementations follow the pattern: {module_name}_{hook_name}. So news_manager_node_presave() is correct. Drupal's module system discovers it automatically."},
{q:"You want to add custom validation to Drupal's user registration form. Which hook is most appropriate?",options:["hook_user_presave","hook_form_alter or hook_form_user_register_form_alter","hook_user_login","hook_theme"],answer:1,explanation:"hook_form_alter (or the more specific hook_form_FORM_ID_alter) lets you add validators, modify fields, or change submission handlers on any form without touching core."},
{q:"What is the key limitation of hooks compared to event subscribers?",options:["Hooks can't modify entities","Hooks can only run once per request","Hooks don't support dependency injection — you can't easily inject services","Hooks are deprecated in Drupal 10"],answer:2,explanation:"Hooks are procedural functions — they can't use constructor injection. Event subscribers are classes that can inject services properly. This is why Drupal has been moving toward events for new functionality."},
]}},
{day:"Day 9",title:"Write Your First Hook",goal:"Build a real hook implementation in a custom module from scratch.",
reading:[
{title:"Minimum module structure",body:"A Drupal module needs: a folder in modules/custom/, a .info.yml file declaring it, and a .module file for hooks. That's it to get started.",link:null},
{title:"The .info.yml file",body:"Declares the module name, description, Drupal core compatibility, and package. Drupal won't recognize the module without it.",link:null},
],
activity:{type:"hands_on",title:"Build a custom module with a working hook",intro:"Create a Drupal module that reacts to node saves using hook_node_presave.",steps:[
{n:1,title:"Create the module directory",body:"Custom modules go in web/modules/custom/ — never in web/modules/contrib/ (that's for third-party modules). The folder name must exactly match the machine name you'll use for the module.",code:"mkdir -p web/modules/custom/my_first_module"},
{n:2,title:"Create the .info.yml file",body:"Every Drupal module must have a {machine_name}.info.yml file. This is how Drupal discovers your module. Without it, the module is completely invisible. The machine name in the file path must match the folder name.",code:"# web/modules/custom/my_first_module/my_first_module.info.yml\nname: 'My First Module'\ntype: module\ndescription: 'Learning hooks in Drupal'\ncore_version_requirement: ^10 || ^11\npackage: Custom"},
{n:3,title:"Create the .module file with the hook",body:"The .module file contains procedural code — hooks live here. The hook function name must be exactly {machine_name}_{hook_name}. Drupal scans all enabled modules for functions matching this pattern. The messenger service displays a status notification at the top of the page.",code:"<?php\n// web/modules/custom/my_first_module/my_first_module.module\n\n/**\n * Implements hook_node_presave().\n */\nfunction my_first_module_node_presave($node) {\n  \\Drupal::messenger()->addStatus(\n    t('Hook fired! Saving node: @title', ['@title' => $node->getTitle()])\n  );\n}"},
{n:4,title:"Enable the module and rebuild caches",body:"pm:enable registers the module with Drupal. Rebuilding caches is required so Drupal discovers the new module's hooks and routes. Without ddev drush cr, your hook won't fire.",code:"ddev drush pm:enable my_first_module -y && ddev drush cr\n# Expected: [success] Successfully enabled: my_first_module"},
{n:5,title:"Test the hook by saving a node",body:"Log into your Drupal site (/user) and go to any existing node (e.g., /node/1/edit) or create a new Article. Click Save. Look for the green status message at the top of the page. If it appears, your hook is working."},
{n:6,title:"Improve the hook to only react to articles",body:"A real hook should be targeted. Update the .module file to only fire for article nodes. Note: $node->bundle() returns the content type machine name.",code:"// Updated my_first_module.module\nfunction my_first_module_node_presave($node) {\n  if ($node->bundle() !== 'article') {\n    return;\n  }\n  \\Drupal::messenger()->addStatus(\n    t('Article hook fired! Saving: @title', ['@title' => $node->getTitle()])\n  );\n}"},
{n:7,title:"Rebuild and test the targeted hook",body:"After changing the .module file, rebuild caches again. Save an Article node — you should see the message. Save a Basic page node — you should NOT see it. This confirms the bundle check works.",code:"ddev drush cr"},
],aiCheck:{prompt:"Share your my_first_module.module file content AND describe what happened when you saved a node. Did the message appear?",checkGoal:"Verify the student has created a working Drupal module with hook_node_presave. Check: correct .module file PHP, hook name follows {module}_{hook} pattern correctly, and they confirmed the hook fired on node save. Give specific feedback."}}},
{day:"Day 10",title:"Event Subscribers",goal:"Understand event subscribers and when to use them over hooks.",
reading:[
{title:"Symfony events in Drupal",body:"Drupal is built on Symfony. Symfony uses an EventDispatcher system. Drupal exposes many events and you can subscribe to them using a properly injected class.",link:"https://www.drupal.org/docs/creating-custom-modules/subscribe-to-and-dispatch-events"},
{title:"Structure of an event subscriber",body:"You need: (1) A class implementing EventSubscriberInterface. (2) A static getSubscribedEvents() method. (3) A registration in your module's services.yml.",link:null},
{title:"When to use which",body:"<strong>Hooks</strong>: altering forms, entities, theme suggestions — anything in .module files. <strong>Event subscribers</strong>: Symfony kernel events, business logic needing injected services, anything requiring proper DI.",link:null},
],
activity:{type:"quiz",questions:[
{q:"What interface must your class implement to be an event subscriber in Drupal?",options:["HookSubscriberInterface","EventSubscriberInterface","DrupalEventInterface","SubscriberInterface"],answer:1,explanation:"EventSubscriberInterface from Symfony\\Component\\EventDispatcher is required. It mandates the static getSubscribedEvents() method that tells Drupal which events your class handles."},
{q:"You need to inject the entity_type.manager service into your event subscriber. How do you do this correctly?",options:["Call \\Drupal::entityTypeManager() inside the event method","Use constructor injection — add it as a constructor parameter and declare it in services.yml","Use \\Drupal::service() inside the event method","Event subscribers cannot use services"],answer:1,explanation:"Constructor injection is the correct Drupal/Symfony pattern. Declare the service as a constructor argument, type-hint it, store it as a property. This makes it testable and follows proper DI principles."},
{q:"Where must you register your event subscriber for Drupal to discover it?",options:["In the .module file","In a .routing.yml file","In your module's .services.yml file with the event_subscriber tag","In settings.php"],answer:2,explanation:"Event subscribers must be registered as services in your_module.services.yml with the tag 'name: event_subscriber'. Without this registration Drupal won't know your class exists."},
]}},
{day:"Day 11",title:"Services & Dependency Injection",goal:"Understand Drupal's service container and the dependency injection pattern.",
reading:[
{title:"What is a service?",body:"A service is a reusable PHP object registered in the service container. Drupal's core provides hundreds: entity_type.manager, database, config.factory, current_user, messenger, etc.",link:"https://api.drupal.org/api/drupal/services"},
{title:"services.yml",body:"Each module defines services in a {module}.services.yml file. You register your class, give it an ID, and declare its constructor dependencies (other services by their service ID).",link:null},
{title:"Accessing services correctly",body:"In classes: constructor injection (always preferred). In .module procedural code: \\Drupal::service('service.id') or shorthand like \\Drupal::entityTypeManager(). Never use \\Drupal:: inside a class that could receive injection.",link:null},
],
activity:{type:"hands_on",title:"Create a custom service with dependency injection",intro:"Register a service in services.yml and inject entity_type.manager into it.",steps:[
{n:1,title:"Create the services.yml file",body:"Every module that defines services needs a {machine_name}.services.yml file. The service ID (my_first_module.node_helper) is how other code calls it. The 'arguments' list contains service IDs to inject — @entity_type.manager means 'inject the entity_type.manager service from the container'.",code:"# web/modules/custom/my_first_module/my_first_module.services.yml\nservices:\n  my_first_module.node_helper:\n    class: Drupal\\my_first_module\\NodeHelper\n    arguments: ['@entity_type.manager']"},
{n:2,title:"Create the src/ directory for PHP classes",body:"Drupal follows PSR-4 autoloading. Classes in src/ are autoloaded under the namespace Drupal\\{module_name}\\. The folder must be named 'src' — not 'classes' or 'lib'.",code:"mkdir -p web/modules/custom/my_first_module/src"},
{n:3,title:"Create NodeHelper.php with constructor injection",body:"The constructor parameter type-hint (EntityTypeManagerInterface) documents what gets injected. Drupal reads the services.yml arguments list and passes the real service. The getLatestNodes method uses the entity storage API — never raw SQL for entities.",code:"<?php\n// web/modules/custom/my_first_module/src/NodeHelper.php\nnamespace Drupal\\my_first_module;\n\nuse Drupal\\Core\\Entity\\EntityTypeManagerInterface;\n\nclass NodeHelper {\n\n  public function __construct(\n    protected EntityTypeManagerInterface $entityTypeManager,\n  ) {}\n\n  public function getLatestNodes(int $count = 5): array {\n    $storage = $this->entityTypeManager->getStorage('node');\n    $ids = $storage->getQuery()\n      ->accessCheck(TRUE)\n      ->condition('status', 1)\n      ->sort('created', 'DESC')\n      ->range(0, $count)\n      ->execute();\n    return $storage->loadMultiple($ids);\n  }\n\n}"},
{n:4,title:"Rebuild caches to register the new service",body:"Drupal's service container is compiled and cached. Any time you add or change services.yml, you must rebuild caches or the new service won't exist.",code:"ddev drush cr"},
{n:5,title:"Test the service via drush php:eval",body:"\\Drupal::service() looks up a service from the container by its ID. This is how you'd call your service from procedural code. The output should be the titles of your 3 most recently created nodes.",code:"ddev drush php:eval \"\n\\$nodes = \\Drupal::service('my_first_module.node_helper')->getLatestNodes(3);\nforeach (\\$nodes as \\$n) {\n  echo \\$n->getTitle() . PHP_EOL;\n}\n\"\n# Expected: titles of your 3 newest nodes, one per line"},
],aiCheck:{prompt:"Paste your NodeHelper.php content AND the output of the drush php:eval command. I'll verify your service and DI are set up correctly.",checkGoal:"Verify the student has correctly created a Drupal service with constructor injection of entity_type.manager. Check: correct namespace, type-hinted constructor, service YAML declaration with @entity_type.manager argument, and that it successfully loaded nodes. Give specific feedback."}}},
{day:"Day 12",title:"Explore the Examples Module",goal:"Study real working implementations of Drupal's core APIs.",
reading:[
{title:"Why the Examples module matters",body:"It's the best learning resource after official docs. Each sub-module demonstrates one API pattern with heavily commented, working code you can run and modify.",link:"https://www.drupal.org/project/examples"},
{title:"What to study",body:"Focus on: <strong>event_subscriber</strong> (how to subscribe to events), <strong>form_api</strong> (complete Form API example), <strong>services_example</strong> (services and DI patterns). These three cover 80% of what you'll build.",link:null},
],
activity:{type:"hands_on",title:"Install and study the Examples module",intro:"Install Examples and study three specific sub-modules in depth.",steps:[
{n:1,title:"Install and enable the Examples module",body:"The Examples module is a collection of sub-modules, each demonstrating one Drupal API. It's the best learning resource after official docs. Install via Composer — never download modules manually.",code:"ddev composer require drupal/examples\nddev drush pm:enable examples -y && ddev drush cr"},
{n:2,title:"Enable specific sub-modules you'll study",body:"The main 'examples' module is just a menu container. Enable the specific sub-modules you need so they're accessible in the UI.",code:"ddev drush pm:enable event_subscriber_example form_api services_example -y && ddev drush cr"},
{n:3,title:"Read and annotate the EventSubscriberExample",body:"Open this file and read every line. Notice: (1) it implements EventSubscriberInterface, (2) getSubscribedEvents() maps event names to method names, (3) the handler receives an event object with data. This is the pattern you'll replicate.",code:"cat web/modules/contrib/examples/modules/event_subscriber_example/src/EventSubscriber/EventSubscriberExample.php"},
{n:4,title:"Read the Form API simple form",body:"Open this file and find the three key methods: buildForm (define fields), validateForm (check input), submitForm (process). Notice how $form is a render array and $form_state carries submitted values.",code:"cat web/modules/contrib/examples/modules/form_api/src/Form/FormApiExampleSimpleForm.php"},
{n:5,title:"Find the services example in the UI",body:"Visit /examples/services in your browser. This shows the service in action. Then read the source to see how the service is defined and called."},
{n:6,title:"Read the services_example services.yml",body:"Compare the services.yml definition with the PHP class. Notice how the argument in YAML maps to the constructor parameter in PHP. This is the DI pattern you practiced in Day 11.",code:"cat web/modules/contrib/examples/modules/services_example/services_example.services.yml\ncat web/modules/contrib/examples/modules/services_example/src/TimestampFormatterService.php"},
],aiCheck:{prompt:"After studying the Examples module, answer: (1) In the EventSubscriberExample, what event does it subscribe to and what does the handler do? (2) What are the three main methods in a Form API class and what does each do?",checkGoal:"Evaluate the student's understanding of the Examples module. They should correctly identify the subscribed event and handler, and understand buildForm (structure), validateForm (validation), submitForm (processing). Score and give detailed feedback."}}},
{day:"Day 13",title:"Week 2 Review",goal:"Solidify your understanding of hooks, events, and services before moving to site building.",
reading:[
{title:"Consolidation check",body:"Can you now: (1) Write a hook implementation from memory? (2) Explain when to use a hook vs. an event subscriber? (3) Create a service with DI in services.yml? These are daily tasks in Drupal development.",link:null},
],
activity:{type:"ai_open",prompt:"Answer these three without notes: (1) Write out (from memory) the minimum code needed for a custom Drupal module that implements hook_form_alter to add a custom submit handler to every form. Include the .info.yml and .module file. (2) Explain constructor injection — why is it preferred over calling \\Drupal::service() inside a class? (3) What tag must an event subscriber service have in services.yml?",checkGoal:"Evaluate the student's ability to write hook and service code from memory. Check: correct hook pattern, valid PHP syntax, understanding of DI benefits (testability, loose coupling), and correct 'event_subscriber' tag knowledge. Score 0-10 with specific feedback on each part."}},
]},
{label:"Week 3",name:"Configuration management & mini-project",days:[
{day:"Day 14",title:"Configuration Management (CMI) Deep Dive",goal:"Master the CMI workflow — the foundation of professional Drupal development environments.",
reading:[
{title:"Config vs. content — the critical distinction",body:"Configuration is anything that defines how your site works (content types, views, roles, etc.). Content is actual data (nodes, users, files). <strong>Config lives in YAML files. Content lives in the database.</strong> This is fundamental.",link:null},
{title:"The professional workflow",body:"Dev: make changes in UI → drush cex → commit to Git. Staging/Prod: git pull → drush cim → drush cr. Never manually copy database changes between environments.",link:"https://www.drupal.org/docs/configuration-management"},
{title:"Config splits",body:"The Config Split module lets you have different config per environment — e.g., Devel module only on dev, different caching on prod. Essential for real projects.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You create a new content type on your dev environment. What is the correct sequence to move it to production?",options:["Copy the database from dev to prod","Export config (drush cex), commit to Git, deploy, then import config (drush cim) on prod","Recreate the content type manually on prod","Use the Drupal migration system"],answer:1,explanation:"CMI workflow: dev changes → drush cex → Git commit → deploy → drush cim on prod. Reproducible, version-controlled, reviewable. Manual recreation is error-prone and doesn't scale."},
{q:"A teammate changed a View directly on production without exporting config. What problem does this create?",options:["Nothing — it's fine to make changes on production","The next config import from Git will overwrite their production changes","The View will automatically sync to dev","The config export will fail"],answer:1,explanation:"This is exactly the anti-pattern CMI solves. If your teammate made changes on prod without exporting, a future `drush cim` from Git will blow away their changes. Always: dev → export → deploy → import."},
{q:"Which file would contain the configuration for a 'Product' content type you created?",options:["content.type.product.yml","node.type.product.yml","product.content_type.yml","drupal.node.product.yml"],answer:1,explanation:"Content type config files follow the pattern node.type.{machine_name}.yml. Each config object in Drupal has a specific naming convention based on its config schema."},
]}},
{day:"Day 15",title:"Themes vs. Modules — What Goes Where",goal:"Understand the hard boundary between display logic and business logic in Drupal.",
reading:[
{title:"The golden rule",body:"Modules handle <strong>business logic</strong> (what data exists, how it's processed, what happens when events fire). Themes handle <strong>display logic</strong> (how data is presented, HTML structure, CSS, JS).",link:null},
{title:"Common mistakes",body:"Putting CSS in a module's .module file. Writing SQL queries in a Twig template. Using template_preprocess to do database lookups. All of these violate the boundary and make your code hard to maintain.",link:null},
{title:"The preprocess layer",body:"template_preprocess functions (in .theme or .module files) are the bridge — they prepare variables for templates but shouldn't contain business logic. Keep them thin.",link:null},
],
activity:{type:"quiz",questions:[
{q:"Where should you put code that calculates a discount price based on user role and product category?",options:["In a Twig template using filters","In a template_preprocess function in the .theme file","In a custom module service or hook","In a View's rewrite field settings"],answer:2,explanation:"Business logic (calculation, data retrieval, rules) belongs in a module — ideally a service. Themes should only receive pre-prepared data. This keeps your logic testable and reusable."},
{q:"Where should you put the HTML structure for a custom card component that displays event teasers?",options:["In a .module file using render arrays","In a custom Twig template file","In a PHP class in your module's src/ folder","In a custom block plugin's build() method"],answer:1,explanation:"HTML structure belongs in a Twig template. The module provides data; the template structures it. A block plugin's build() method returns a render array pointing TO a template, not containing raw HTML."},
]}},
{day:"Day 16",title:"Mini-Project: Blog Site",goal:"Build a complete structured content site using everything from Phases 1-2.",
reading:[
{title:"What you're building",body:"A blog with: custom Article content type with fields, a custom Tag taxonomy, a Views listing page, a custom hook that auto-sets a field on save, and all config exported to Git.",link:null},
],
activity:{type:"hands_on",title:"Build the blog site",intro:"Follow these steps to build a complete mini-project site.",steps:[
{n:1,title:"Create a Tags taxonomy vocabulary",body:"Taxonomy vocabularies are content classification systems. Go to Admin → Structure → Taxonomy → Add vocabulary. Name it 'Tags', set machine name to 'tags'. This will hold your article topic terms. After saving, add 4–5 sample terms like PHP, JavaScript, Drupal, DevOps."},
{n:2,title:"Add field_tags to the Article content type",body:"Go to Admin → Structure → Content types → Article → Manage fields → Add field. Choose 'Reference → Taxonomy term'. Label: Tags, machine name: field_tags. On the next screen, set the Reference type to 'Tags' vocabulary. Allow unlimited values so articles can have multiple tags."},
{n:3,title:"Add field_reading_time to Article",body:"Add another field: 'Number → Integer'. Label: Reading time (minutes), machine name: field_reading_time. Min value: 1. This will be auto-populated by our hook. On the Manage display tab, place it in the content region."},
{n:4,title:"Add field_featured to Article",body:"Add field: 'Boolean'. Label: Featured, machine name: field_featured. On/off label: Featured / Standard. This lets editors flag articles for a featured section."},
{n:5,title:"Build the /blog Views listing page",body:"Go to Admin → Structure → Views → Add view. Settings: Title = Blog, Show = Content of type = Article. Create a page at /blog, display = unformatted list, item = Content: teaser. Click Continue and edit. Add: Filter: Published = Yes. Sort: Created (DESC). Add an exposed filter on field_tags. Save."},
{n:6,title:"Add the reading time auto-calculation hook",body:"Update your .module file to calculate reading time on save. Average reading speed is ~200 words per minute. strip_tags removes HTML before counting. max(1,...) ensures we never show 0 minutes.",code:"// In my_first_module.module — update the existing hook_node_presave\nfunction my_first_module_node_presave($node) {\n  if ($node->bundle() !== 'article') {\n    return;\n  }\n  $body = $node->get('body')->value ?? '';\n  $words = str_word_count(strip_tags($body));\n  $reading_time = max(1, (int) round($words / 200));\n  $node->set('field_reading_time', $reading_time);\n}"},
{n:7,title:"Create 3 test articles and verify the hook",body:"Create three Article nodes with varying body lengths (short, medium, long). Save each and check the Reading time field — it should be auto-populated. Visit /blog to see the listing."},
{n:8,title:"Export configuration and commit to Git",body:"All your content type and Views changes are configuration. Export and commit them so they're version-controlled and deployable.",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add blog site: tags taxonomy, article fields, /blog view, reading time hook'"},
],aiCheck:{prompt:"Describe your blog site: (1) What fields did you add to the Article content type? (2) Paste your hook_node_presave implementation. (3) What does your Views listing look like?",checkGoal:"Verify the student has built a working blog site with custom fields, a Views listing, and a working hook. Check that the reading time calculation uses word count and body field, that Views is properly configured, and config was exported. Give specific constructive feedback."}}},
{day:"Day 17",title:"Mini-Project: Config Workflow & Git",goal:"Practice the complete dev-to-deployment config workflow with Git.",
reading:[
{title:"The config loop",body:"Every configuration change on dev should immediately be: (1) exported with drush cex, (2) committed to Git with a descriptive message, (3) importable on any other environment with drush cim. This is the discipline that separates professional Drupal devs.",link:null},
],
activity:{type:"hands_on",title:"Practice the full config export → Git → import cycle",intro:"Simulate moving your blog config to a 'staging' environment.",steps:[
{n:1,title:"Make a UI config change",body:"Go to Admin → Structure → Content types → Article → Manage fields → Add field. Add a 'Text (plain)' field. Label: Subtitle, machine name: field_subtitle. Save. This change now exists in the active database config but has NOT been exported to files yet — it would be lost if someone ran 'drush cim' from Git right now."},
{n:2,title:"Export and inspect the change",body:"Run cex to export the active config to YAML. Then use git diff to see exactly what changed. You should see a new file for the field definition and changes to the Article content type YAML.",code:"ddev drush cex -y\ngit diff config/sync/\n# You should see new files like:\n# field.field.node.article.field_subtitle.yml\n# field.storage.field_subtitle.yml"},
{n:3,title:"Commit the config change to Git",body:"Write a meaningful commit message that describes WHAT changed and WHY. Future-you and teammates need to understand this from the git log alone.",code:"git add config/sync/\ngit commit -m 'Add subtitle field to Article content type'"},
{n:4,title:"Simulate a staging import",body:"This simulates what happens on a staging server after a deploy. drush cim reads config from files and applies any differences to the active config. This is how your change travels from dev to every other environment.",code:"ddev drush cim -y\nddev drush cr\n# Expected: [success] The configuration was imported successfully."},
{n:5,title:"Verify the field exists after import",body:"Confirm the subtitle field is present in the Article entity's field definitions after the import.",code:"ddev drush php:eval \"\n\\$fields = \\Drupal::service('entity_field.manager')->getFieldDefinitions('node', 'article');\necho implode(', ', array_keys(\\$fields));\n\"\n# You should see 'field_subtitle' in the output"},
{n:6,title:"Practice: make, export, commit a second change",body:"Now make another small change — rename a field label, adjust a display, or add a View filter. Export, check git diff, commit. Build the muscle memory of: change → cex → diff → commit."},
{n:7,title:"Review your commit history",body:"Your git log should tell the story of your site's evolution. Every commit should be a clear, atomic change.",code:"git log --oneline\n# Good: each line describes a specific config change\n# Bad: 'misc changes' or 'config update'"},
],aiCheck:{prompt:"Paste the output of `git log --oneline -5` from your project. Show me your last 5 commits. I'll verify your config workflow discipline.",checkGoal:"Verify the student has been committing config changes with descriptive messages. Check for meaningful commit messages (not just 'config update') and that the log shows incremental config changes. Give feedback on commit message quality and workflow."}}},
{day:"Day 18",title:"Phase 1 Retrospective",goal:"Consolidate everything from Phase 1 and prepare your mindset for Phase 2.",
reading:[
{title:"What you now know",body:"Entity system, hooks, event subscribers, services, DI, Composer, Drush, CMI, and the theme vs. module boundary. This is the foundation everything else is built on.",link:null},
{title:"Heading into Phase 2",body:"Phase 2 is where you become a real Drupal site builder — Views, Paragraphs, Layout Builder, and content architecture. You'll build real client-quality sites.",link:null},
],
activity:{type:"ai_open",prompt:"Phase 1 final reflection — answer all three: (1) What was the hardest concept in Phase 1 for you and why? (2) Explain the complete flow of a Drupal request from browser URL to rendered HTML — mention routing, controllers, hooks, and render arrays. (3) If a junior dev asked you 'what's the most important habit to build as a Drupal developer', what would you tell them and why?",checkGoal:"Evaluate the student's Phase 1 comprehension. The request flow answer should mention: routing.yml → controller → render array → theme system → Twig templates. The habit answer should ideally be about config management, reading core code, or running drush cr. Score 0-10 with constructive Phase 1 summary feedback."}},
]},
]},
{id:2,label:"Phase 2",name:"Site Building",color:"#22c98e",bg:"#0f2620",weeks:[
{label:"Week 1",name:"Views & dynamic content",days:[
{day:"Day 1",title:"Views Module Fundamentals",goal:"Learn to build dynamic pages and blocks using Drupal's most powerful core module.",
reading:[
{title:"What Views does",body:"Views lets you query the database and display results as pages, blocks, feeds, or REST exports — without writing SQL. It's one of Drupal's most powerful features and you'll use it on every project.",link:"https://www.drupal.org/docs/8/core/modules/views"},
{title:"Key concepts",body:"<strong>Display</strong>: how to show the view (page, block, REST). <strong>Fields</strong>: which entity fields to show. <strong>Filters</strong>: which content to include. <strong>Sort criteria</strong>: ordering. <strong>Relationships</strong>: joining to related entities. <strong>Contextual filters</strong>: dynamic filtering based on URL.",link:null},
{title:"Format options",body:"Unformatted list, HTML list, Table, Grid, Bootstrap-compatible formats. Each changes how results are rendered. Table format is great for admin UIs; unformatted is best for themed output.",link:null},
],
activity:{type:"hands_on",title:"Build three essential Views",intro:"Create a page view, a block view, and a filtered view — the three most common patterns.",steps:[
{n:1,title:"Create a Views listing page at /articles",body:"Go to Admin → Structure → Views → Add view. Fill in: View name = Articles, Show = Content of type = Article. Check 'Create a page', Path = /articles, Display format = Unformatted list of Fields. Uncheck block. Click Save and edit."},
{n:2,title:"Add and configure fields on the page display",body:"In the Fields section: Remove the default Title field if present. Add: Content: Title (check 'Link this field to the original piece of content'). Add: Content: Body (set formatter to 'Trimmed', limit = 200 characters). Add: Content: Post date (format: Medium). Arrange them in this order: Title → Body → Date."},
{n:3,title:"Add filters: Published only, sorted newest first",body:"In the Filter criteria section: Add 'Content: Published' = Yes. This hides unpublished drafts from visitors. In the Sort criteria section: Add 'Content: Post date' → Descending (newest first)."},
{n:4,title:"Add a Block display to the same View",body:"In the Displays area at the top, click '+ Add' → Block. This creates a second display that shares the same query but renders as a block. In the block display: set 'Items to display' to 5. Set Pager to 'Display a specified number of items'."},
{n:5,title:"Place the block in the sidebar",body:"Go to Admin → Structure → Block layout. Find the 'Sidebar' region (or the first available sidebar region in your theme). Click 'Place block', search for your View name, and place it. Configure it to only show on article pages if desired."},
{n:6,title:"Add an exposed tag filter",body:"Back in the View editor, in the page display: in Filter criteria, click Add. Search for 'field_tags'. Check it and click Add and configure. Check 'Expose this filter to visitors'. Label: 'Filter by tag'. Click Apply. Save the View."},
{n:7,title:"Test the View and exposed filter",body:"Visit /articles in your browser. You should see your articles listed with title, body excerpt, and date. At the top, you should see a 'Filter by tag' dropdown. Select a tag and click Apply — the list should filter."},
{n:8,title:"Export config",body:"Views are configuration — export and commit so this work is reproducible.",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add articles listing View with block display and tag filter'"},
],aiCheck:{prompt:"Describe your Views setup: (1) What fields are on your /articles page? (2) What filters did you add? (3) Does the exposed filter work? Paste the first 10 lines of one of your views YAML files.",checkGoal:"Verify the student created working Views with page display, fields, filters, and exposed filter. Check that they exported config correctly. Give specific feedback on Views configuration best practices."}}},
{day:"Day 2",title:"Contextual Filters & Relationships",goal:"Master advanced Views techniques for building complex dynamic listings.",
reading:[
{title:"Contextual filters",body:"A contextual filter dynamically filters based on a URL argument or context. Example: /taxonomy/term/5 shows all nodes tagged with term ID 5. Drupal's taxonomy term pages use this pattern.",link:null},
{title:"Relationships",body:"Relationships allow you to bring in data from related entities. Example: on an Article view, add a relationship to 'Author' to display fields from the author's user profile.",link:null},
{title:"When to use Views vs. custom code",body:"Views for: listing pages, admin tables, blocks of content. Custom code for: complex business logic in display, heavy calculations, non-entity data sources.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You want a Views page at /author/[username] that shows all published articles by that author. What Views feature do you use?",options:["A regular filter set to the specific author","A contextual filter on the Author UID or username","A relationship to the user entity","A Views argument plugin"],answer:1,explanation:"Contextual filters handle dynamic URL-based filtering. You add a contextual filter for 'Author: UID' or 'Author: Name', set it to get the value from the URL, and Views dynamically filters by whoever is in the path."},
{q:"You want to show the author's profile picture next to each article in a View. What do you need first?",options:["A custom module to join the tables","A Relationship to the 'Content: Author' user entity","An exposed filter for the user","A second View embedded in the first"],answer:1,explanation:"Add a Relationship: 'Content: Author' to the View. Once the relationship is added, you can add fields from the related user entity — including their profile picture."},
]}},
{day:"Day 3",title:"Paragraphs Module",goal:"Use Paragraphs to build flexible, component-based page layouts.",
reading:[
{title:"What Paragraphs does",body:"Paragraphs is a contrib module that lets you attach different types of reusable content components to nodes. Think of it as Drupal's native component system — each paragraph type is like a content block.",link:"https://www.drupal.org/project/paragraphs"},
{title:"Common paragraph types",body:"Text block, Image + text, Quote, Call to action button, Video embed, Card grid, Hero banner. Each is a bundle of the Paragraph entity type with its own fields.",link:null},
{title:"Paragraphs vs. Layout Builder",body:"<strong>Paragraphs</strong>: structured content components, defined by editors in a fixed order. Best for controlled content structures. <strong>Layout Builder</strong>: drag-and-drop layout control, more flexible but harder to control.",link:null},
],
activity:{type:"hands_on",title:"Set up Paragraphs for a landing page",intro:"Install Paragraphs and create a Landing Page content type with flexible sections.",steps:[
{n:1,title:"Install and enable the Paragraphs module",body:"Paragraphs adds a new entity type (Paragraph) and an 'Entity reference revisions' field type. Install via Composer first, then enable with Drush.",code:"ddev composer require drupal/paragraphs\nddev drush pm:enable paragraphs -y && ddev drush cr"},
{n:2,title:"Create a 'Text Block' paragraph type",body:"Go to Admin → Structure → Paragraph types → Add paragraph type. Label: Text Block, machine name: text_block. Click Save. Then on the Manage fields tab: add 'Text (formatted, long)' field. Label: Body, machine name: field_body. This is the basic rich text section."},
{n:3,title:"Create a 'Hero Banner' paragraph type",body:"Add paragraph type: Hero Banner, machine name: hero_banner. Add these fields: (1) 'Text (plain)' for Headline (field_headline, required). (2) 'Text (plain)' for Subheadline (field_subheadline). (3) 'Image' for Background Image (field_background_image). Save each field."},
{n:4,title:"Create a 'CTA Button' paragraph type",body:"Add paragraph type: CTA Button, machine name: cta_button. Add fields: (1) 'Text (plain)' for Button Label (field_button_label, required). (2) 'Link' for Button URL (field_button_url, required, allow external links). This creates a clickable call-to-action component."},
{n:5,title:"Create the Landing Page content type",body:"Go to Admin → Structure → Content types → Add content type. Label: Landing Page, machine name: landing_page. Under Submission form settings, set Title label to 'Page Title'. Click Save and manage fields."},
{n:6,title:"Add the Paragraphs field to Landing Page",body:"On the Landing Page Manage fields tab: Add field → 'Reference revisions → Paragraphs'. Label: Sections, machine name: field_sections. On the field settings page: set the number of values to 'Unlimited'. On the next page (edit), select all three paragraph types (Text Block, Hero Banner, CTA Button). Save."},
{n:7,title:"Create a test landing page with all section types",body:"Go to Content → Add content → Landing Page. Title: Home Page. In the Sections area: click 'Add Hero Banner' — fill in Headline and Subheadline. Click 'Add Text Block' — write some body text. Click 'Add CTA Button' — set label and URL. Save and view the page to confirm all three sections render."},
{n:8,title:"Export config",body:"Paragraph types, the content type, and field settings are all configuration.",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add Paragraphs with Text Block, Hero Banner, CTA Button; Landing Page content type'"},
],aiCheck:{prompt:"Describe your Paragraphs setup: What paragraph types did you create, what fields does each have, and how does the landing page look when you view it?",checkGoal:"Verify the student has successfully installed Paragraphs, created meaningful paragraph types with appropriate fields, and built a working landing page. Give feedback on paragraph type design and whether their field choices make sense for the content."}}},
{day:"Day 4",title:"Layout Builder",goal:"Master Drupal's built-in drag-and-drop layout system for content display.",
reading:[
{title:"What Layout Builder does",body:"Layout Builder (core) lets you visually arrange blocks and fields into sections on a page. You can create layout templates for content types or customize individual nodes.",link:"https://www.drupal.org/docs/8/core/modules/layout-builder"},
{title:"Sections and blocks",body:"Layout Builder uses sections (columns/rows) and blocks (content pieces placed into sections). Core blocks include content fields, Views blocks, and custom blocks.",link:null},
{title:"Content type defaults vs. per-node overrides",body:"You can set a default layout for all nodes of a content type, then optionally allow editors to override it per node. For most sites, defaults-only is safer and more maintainable.",link:null},
],
activity:{type:"hands_on",title:"Build a layout with Layout Builder",intro:"Enable Layout Builder for your Article content type and create a two-column layout.",steps:[
{n:1,title:"Enable the Layout Builder core module",body:"Layout Builder is a core module — no Composer install needed. Enable it with Drush.",code:"ddev drush pm:enable layout_builder -y && ddev drush cr"},
{n:2,title:"Enable Layout Builder for the Article display",body:"Go to Admin → Structure → Content types → Article → Manage display. At the top, you'll see 'Layout options'. Check 'Use Layout Builder'. Leave 'Allow each content item to have its layout customized' unchecked for now — that creates per-node overrides which is harder to maintain. Click Save."},
{n:3,title:"Open the layout editor",body:"After saving, a new 'Manage layout' button appears. Click it. You're now in the Layout Builder canvas. You'll see a single-column layout with your existing fields."},
{n:4,title:"Add a two-column section",body:"At the top of the canvas, click 'Add section'. Choose 'Two column'. Set column widths to 67% / 33% (or your preference). Click Add section. You'll now have two columns — left (main) and right (sidebar)."},
{n:5,title:"Move fields into the columns",body:"For each existing block on the canvas, use the Configure (pencil) icon or drag it into the correct column. Move Title and Body to the left column. Move the Tags and Reading time fields to the right column. Remove any empty placeholder sections."},
{n:6,title:"Add a custom block to the sidebar",body:"In the right column, click 'Add block'. Browse to 'Create custom block'. Add a simple 'About the Author' text block as a sidebar placeholder. This shows how you can mix field blocks with content blocks."},
{n:7,title:"Save the layout and preview",body:"Click 'Save layout' at the top of the canvas. Then navigate to any Article node (e.g., /node/1). You should see your two-column layout with content on the left and metadata on the right."},
{n:8,title:"Export config",body:"Layout Builder layouts are stored as configuration.",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add two-column Layout Builder layout for Article content type'"},
],aiCheck:{prompt:"Describe your Layout Builder setup: What sections and blocks did you create? What does your article page look like now vs. before?",checkGoal:"Verify the student has successfully enabled and configured Layout Builder for a content type. Check they understand the sections/blocks model and have created a meaningful layout. Give feedback on layout design choices."}}},
{day:"Day 5",title:"Media & Image Styles",goal:"Set up professional media handling with image styles and responsive images.",
reading:[
{title:"Drupal's Media system",body:"The Media module (core) provides a centralized media library for images, videos, audio, and files. Images uploaded through Media are reusable across content.",link:"https://www.drupal.org/docs/8/core/modules/media"},
{title:"Image styles",body:"Image styles define server-side image transformations (scale, crop, resize). A single uploaded image can be displayed at multiple sizes by defining different image styles.",link:null},
{title:"Responsive image module",body:"The Responsive Image module (core) maps image styles to CSS breakpoints, serving the right image size to the right screen. Essential for performance.",link:null},
],
activity:{type:"quiz",questions:[
{q:"A client uploads a 4000px wide photo. You need to display it as a 400x300px thumbnail in listings and full-width on detail pages. What is the correct Drupal approach?",options:["Use CSS to resize the original image","Create two image styles (thumbnail 400x300 and full-width) and assign them to different display modes","Manually crop and upload two versions","Use JavaScript to resize images client-side"],answer:1,explanation:"Image styles apply server-side transformations. Create styles for each use case and assign them to field formatters in content display modes. The original is preserved; derived images are cached."},
{q:"What Drupal module maps image styles to responsive breakpoints so mobile gets a smaller image than desktop?",options:["Mobile Images module","Responsive Image module (core)","Picture element module","Breakpoints module alone"],answer:1,explanation:"The Responsive Image core module, combined with the Breakpoints module, lets you define which image style to serve at which screen width. Drupal outputs the appropriate <picture> or srcset HTML."},
]}},
{day:"Day 6",title:"User Roles & Permissions",goal:"Design and implement a complete user permission system for a real-world site.",
reading:[
{title:"Drupal's permission system",body:"Drupal uses roles with granular permissions. Users can have multiple roles. Every action in Drupal (view content, create articles, administer users) maps to a specific permission.",link:null},
{title:"Common role patterns",body:"Anonymous → authenticated → content_editor → content_manager → site_admin. Each adds more permissions. Never give editors 'administer site configuration' — that's admin-only.",link:null},
{title:"Content moderation",body:"The Content Moderation core module adds editorial workflow states (draft, review, published). Assign different states to different roles for proper editorial workflows.",link:null},
],
activity:{type:"hands_on",title:"Build a complete permission structure",intro:"Create roles for a real editorial workflow.",steps:[
{n:1,title:"Create the Content Editor role",body:"Go to Admin → People → Roles → Add role. Label: Content Editor, machine name: content_editor. Save. This role is for writers who can create and edit their own content only."},
{n:2,title:"Assign permissions to Content Editor",body:"Click 'Edit permissions' on the Content Editor role. Grant these permissions only: 'Node: Article: Create new content', 'Node: Article: Edit own content', 'Node: Article: View own unpublished content', 'Media: Use the media library', 'Node: Access the content overview page'. Do NOT grant: 'Administer content', 'Administer users', 'Administer site configuration', 'Delete any content', 'Edit any content'. Click Save permissions."},
{n:3,title:"Create the Content Manager role",body:"Add another role: Content Manager, machine name: content_manager. This role is for senior editors who manage all content but still can't touch site config."},
{n:4,title:"Assign permissions to Content Manager",body:"Grant Content Manager everything Content Editor has, PLUS: 'Node: Article: Edit any content', 'Node: Article: Delete any content', 'Node: Basic page: Edit any content', 'Taxonomy: Administer vocabularies and terms'. Still deny: 'Administer site configuration', 'Administer modules', 'Use the administration theme'. The manager controls content, not the site."},
{n:5,title:"Create a test user for each role",body:"Go to Admin → People → Add user. Create user: editor1, assign Content Editor role. Create user: manager1, assign Content Manager role. Note the passwords. You'll use these to test permissions."},
{n:6,title:"Enable Content Moderation for editorial workflow",body:"This adds Draft / Published / Archived states so editors submit for review before publishing.",code:"ddev drush pm:enable content_moderation workflows -y && ddev drush cr"},
{n:7,title:"Test permissions by logging in as each role",body:"Log out of admin. Log in as editor1 — try to edit someone else's article (should be denied), then try to edit your own (should work). Log out, log in as manager1 — editing any article should work. Try to access /admin/config — should be denied for both non-admin roles."},
{n:8,title:"Export config",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add content_editor and content_manager roles with editorial permissions'"},
],aiCheck:{prompt:"List the permissions you gave to content_editor vs. content_manager. Why did you choose to separate those specific permissions?",checkGoal:"Evaluate the student's understanding of the principle of least privilege in Drupal permissions. Check that editors can't do admin tasks, and that the permission separation makes logical sense for an editorial workflow. Give feedback on security best practices."}}},
{day:"Day 7",title:"Week 1 Review — Site Building",goal:"Solidify Views, Paragraphs, Layout Builder, and permissions with a comprehensive challenge.",
reading:[
{title:"What you've built",body:"You now have the skills to build real client-quality Drupal sites — Views for content listings, Paragraphs for flexible layouts, Layout Builder for display control, and a proper permission system. This is the Site Builder certification territory.",link:null},
],
activity:{type:"ai_open",prompt:"Site Building challenge — answer all three: (1) A client needs an events site with: events listing page filterable by category, a featured events block for the homepage, and each event has a flexible content area with text, images, and a map embed. Which Drupal tools would you use for each requirement and why? (2) What's the difference between a Paragraphs approach and a Layout Builder approach for flexible page content? When would you choose each? (3) You have an Editor role that somehow can delete any content. How do you audit and fix Drupal permissions?",checkGoal:"Evaluate site building judgment. Key answers: (1) Views for listing + block, Paragraphs for the flexible content area, custom paragraph types for map embed. (2) Paragraphs = structured content order, Layout Builder = visual layout control — choose based on editorial vs. layout needs. (3) Admin → People → Permissions, look for 'delete any content' checkbox on Editor role. Score 0-10 with specific feedback."}},
]},
{label:"Week 2",name:"Advanced site building",days:[
{day:"Day 8",title:"Configuration Management Across Environments",goal:"Master multi-environment config workflows including Config Split.",
reading:[
{title:"The multi-environment problem",body:"Dev has Devel module and verbose errors. Staging matches prod. Prod has Varnish config and CDN settings. Config Split lets you split config by environment so drush cim applies the right config in the right place.",link:"https://www.drupal.org/project/config_split"},
{title:"settings.php overrides",body:"$settings, $config, and $databases in settings.php override config and are never exported. Use this for: database credentials, trusted host patterns, per-environment feature flags.",link:null},
{title:"config/sync vs. config/default",body:"config/sync is your active config export. config/default is used for installation profiles. Don't confuse them. Your workflow always uses config/sync.",link:null},
],
activity:{type:"hands_on",title:"Set up Config Split for dev vs. prod",intro:"Configure different module sets per environment using Config Split.",steps:[
{n:1,title:"Install and enable Config Split",body:"Config Split lets you have different module states and config values per environment. The classic use: Devel, Views UI, and Kint are enabled on dev but NOT on prod. Without Config Split, drush cim would disable them on prod (because they're disabled in the shared config).",code:"ddev composer require drupal/config_split\nddev drush pm:enable config_split -y && ddev drush cr"},
{n:2,title:"Create the config/dev directory",body:"This folder will hold config that only applies on dev. It must exist before you configure the split.",code:"mkdir -p config/dev"},
{n:3,title:"Create a 'dev' Config Split entity",body:"Go to Admin → Config → Development → Configuration split → Add configuration split. Fill in: Label = Dev, Machine name = dev, Folder = config/dev, Status = Enabled (active on this machine). In 'Complete Split' section, add these modules: devel, views_ui. These will be excluded from config/sync and only appear in config/dev."},
{n:4,title:"Activate the split in settings.local.php",body:"Config Split reads this setting to know whether to activate a split. On prod, you'd omit this line (or set it FALSE) to keep dev-only modules out.",code:"// In web/sites/default/settings.local.php\n$config['config_split.config_split.dev']['status'] = TRUE;"},
{n:5,title:"Export config with the split active",body:"Run cex — Config Split will redirect the Devel and Views UI module config to config/dev/ instead of config/sync/.",code:"ddev drush cex -y\nls config/dev/\n# Expected: you should see files like:\n# core.extension.yml (with devel listed)\n# views_ui.settings.yml"},
{n:6,title:"Verify the main config/sync has no dev modules",body:"Confirm that config/sync/core.extension.yml does NOT list 'devel' — it should only appear in config/dev.",code:"grep 'devel' config/sync/core.extension.yml\n# Should return nothing\ngrep 'devel' config/dev/core.extension.yml\n# Should return: devel: 0"},
],aiCheck:{prompt:"Paste the output of `ls config/dev/` and explain why Config Split is important for a professional Drupal workflow.",checkGoal:"Verify the student has set up Config Split and understands why it's needed. Check that dev-only modules appear in the config/dev folder. Give feedback on the broader environment management strategy."}}},
{day:"Day 9",title:"Search API & Faceted Search",goal:"Add professional search functionality to a Drupal site.",
reading:[
{title:"Search API",body:"Search API is the most-used search solution for Drupal. It provides a flexible search backend (Database, Solr, Elasticsearch) with a Views integration for building search pages.",link:"https://www.drupal.org/project/search_api"},
{title:"Facets module",body:"Facets module provides faceted filtering UI for Search API — the sidebar filters you see on e-commerce sites (filter by category, price range, author, etc.).",link:"https://www.drupal.org/project/facets"},
],
activity:{type:"hands_on",title:"Build a faceted search page",intro:"Add Search API with Database backend and faceted filtering to your site.",steps:[
{n:1,title:"Install Search API and Facets",body:"search_api is the main module. search_api_db is the Database backend (no Solr/Elasticsearch needed). facets adds the sidebar filtering UI.",code:"ddev composer require drupal/search_api drupal/facets\nddev drush pm:enable search_api search_api_db facets -y && ddev drush cr"},
{n:2,title:"Create a Search API server",body:"A 'server' is the search backend (database, Solr, etc.). Go to Admin → Config → Search and metadata → Search API → Add server. Label: Database Server, Machine name: database_server, Backend: Database. Leave all other settings as default. Click Save."},
{n:3,title:"Create a search index",body:"An 'index' defines what content to index and how. Go to Search API → Add index. Label: Articles, Machine name: articles, Datasource: Content → select 'Article'. Server: your Database Server. Click Save."},
{n:4,title:"Add fields to the index",body:"On the index edit page, click 'Fields' tab. Add these fields: Title → set type to 'Fulltext' (for keyword matching). Body → set type to 'Fulltext'. field_tags → set type to 'String' (for exact facet matching). Click 'Save changes'."},
{n:5,title:"Index all existing content",body:"Click 'Index now' to process all existing articles. You should see '0 items remaining'. New articles are indexed automatically on save.",code:"# Or via Drush:\nddev drush search-api:index\n# Expected: [success] Successfully indexed X items on index Articles"},
{n:6,title:"Build a search View",body:"Go to Admin → Structure → Views → Add view. Show: Index 'Articles'. Create a page at /search. Display: Unformatted list. Click Save. In the View editor: Add exposed filter 'Search: Fulltext search'. Add a sort by Relevance (descending). Save."},
{n:7,title:"Add a Tags facet block",body:"Go to Admin → Config → Search and metadata → Facets → Add facet. Source: Articles index, Field: field_tags, Facet source: search_api_views_page:articles. Save. On the next page, configure: Widget = Checkboxes, Sort by count. Go to Admin → Structure → Block layout and place the new Tags facet block in a sidebar region. Set block visibility: Pages = /search."},
{n:8,title:"Test the search page",body:"Visit /search. Type a keyword and search. Then check a tag in the sidebar facet — the results should filter. Combine both a keyword and a tag filter. The results should narrow further."},
],aiCheck:{prompt:"Describe your search setup: (1) Which backend did you use and why? (2) What fields did you index? (3) Does the search and facet filtering work? What happens when you combine a keyword search with a tag filter?",checkGoal:"Verify the student has a working Search API + Facets setup. Key checks: index has fulltext fields, Views is using the index as data source, facets are working. Give feedback on field selection and indexing strategy."}}},
{day:"Day 10",title:"Pathauto & URL Management",goal:"Set up clean, SEO-friendly URLs automatically with Pathauto.",
reading:[
{title:"Pathauto module",body:"Pathauto automatically generates clean URL aliases for content based on patterns. Example: /articles/[node:title] gives you /articles/my-article-title instead of /node/42.",link:"https://www.drupal.org/project/pathauto"},
{title:"Token module",body:"Pathauto depends on Token, which provides dynamic replacement patterns for entity values. [node:title], [user:name], [term:name] etc. are token patterns.",link:null},
{title:"Metatag module",body:"Metatag automatically generates SEO meta tags (title, description, og:image) from content. Pairs perfectly with Pathauto for a professional SEO setup.",link:null},
],
activity:{type:"hands_on",title:"Set up Pathauto for all content types",intro:"Configure automatic URL patterns for articles, taxonomy terms, and users.",steps:[
{n:1,title:"Install Pathauto and Token",body:"Pathauto requires Token, which provides the [node:title] and [term:name] replacement patterns. Always install both together.",code:"ddev composer require drupal/pathauto drupal/token\nddev drush pm:enable pathauto token -y && ddev drush cr"},
{n:2,title:"Configure an Article URL pattern",body:"Go to Admin → Config → Search and metadata → URL aliases → Patterns → Add Pathauto pattern. Pattern type: Content. Pattern: /articles/[node:title] (the Token module will auto-clean special characters and spaces). Content type: Article only. Label: Article pages. Click Save. Note: Pathauto auto-lowercases and slugifies the title — 'My Article!' becomes 'my-article'."},
{n:3,title:"Configure a Taxonomy term pattern",body:"Add another pattern. Pattern type: Taxonomy term. Pattern: /topics/[term:name]. Vocabulary: Tags. Label: Tags terms. Save. Now visiting a tag term will use /topics/my-tag instead of /taxonomy/term/5."},
{n:4,title:"Configure a User pattern",body:"Add pattern. Pattern type: User. Pattern: /authors/[user:name]. Label: User profiles. Save. Author profile URLs become /authors/username."},
{n:5,title:"Bulk update all existing content",body:"Existing nodes won't automatically get new aliases — you must bulk-update them. Go to Admin → Config → Search and metadata → URL aliases → Bulk update. Select 'Content paths' and check 'Article'. Click Update. Repeat for Taxonomy terms."},
{n:6,title:"Verify aliases are working",body:"Create a new Article — its URL should automatically use the Pathauto pattern. Check with the path_alias.manager service.",code:"ddev drush php:eval \"\n\\$node = \\Drupal::entityTypeManager()->getStorage('node')->load(1);\n\\$alias = \\Drupal::service('path_alias.manager')->getAliasByPath('/node/' . \\$node->id());\necho 'Node: ' . \\$node->getTitle() . PHP_EOL;\necho 'Alias: ' . \\$alias . PHP_EOL;\n\"\n# Expected: Alias: /articles/your-article-title"},
{n:7,title:"Export config",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Add Pathauto URL patterns for articles, taxonomy terms, and users'"},
],aiCheck:{prompt:"Paste the output of the drush php:eval command AND show your Pathauto patterns configuration. What URL does a new Article get now?",checkGoal:"Verify the student has correctly set up Pathauto patterns. Check that the alias follows the configured pattern and that bulk update worked. Give feedback on URL strategy and SEO considerations."}}},
{day:"Day 11",title:"Phase 2 Mini-Project: Events Site",goal:"Build a complete, professional events listing site using all Phase 2 skills.",
reading:[
{title:"What you're building",body:"An events site with: Event content type (date, location, category, Paragraphs sections), taxonomy categories, Views listing with exposed filters, Search API search page, Pathauto URLs, proper permissions, and all config exported.",link:null},
],
activity:{type:"hands_on",title:"Build the events site",intro:"This is your Phase 2 capstone. Take your time to build it properly.",steps:[
{n:1,title:"Create an 'Event Categories' taxonomy vocabulary",body:"Go to Admin → Structure → Taxonomy → Add vocabulary. Label: Event Categories, machine name: event_categories. Add 4–5 sample terms: Conference, Workshop, Webinar, Networking, Meetup."},
{n:2,title:"Create the Event content type",body:"Admin → Structure → Content types → Add content type. Label: Event, machine name: event. Add these fields in order: (1) field_event_date — Date range (datetime), required. (2) field_location — Text (plain), label: Location. (3) field_category — Reference → Taxonomy term, vocabulary: Event Categories, label: Category. (4) field_registration_url — Link, label: Registration URL, allow external URLs. (5) field_sections — Reference revisions → Paragraphs, label: Content Sections, unlimited, include all paragraph types. Save each field as you go."},
{n:3,title:"Build the /events Views listing page",body:"Admin → Structure → Views → Add view. Show: Event content, create page at /events, display format = Table of Fields. Add fields: Title (linked), field_event_date (use 'Date range' formatter, short date format), field_location, field_category. Filter criteria: Published = Yes. Add another filter: field_event_date (start date) >= 'now' (so past events don't show). Sort: field_event_date ASC (soonest first). Exposed filters: field_category (let users filter by category)."},
{n:4,title:"Add Layout Builder to Event full-page display",body:"Admin → Structure → Content types → Event → Manage display. Enable Layout Builder. Click Manage layout. Build two sections: Section 1 (one column, full-width): place Title, field_event_date, field_location, field_category. Section 2 (two column 70/30): left = field_sections; right = field_registration_url. Save layout."},
{n:5,title:"Add a Pathauto URL pattern for events",body:"Admin → Config → Search and metadata → URL aliases → Patterns → Add pattern. Type: Content, content type: Event. Pattern: /events/[node:field_event_date:date:html_date]/[node:title]. This creates URLs like /events/2026-06-15/my-conference. Save."},
{n:6,title:"Create 5 test events",body:"Create five Event nodes with: different categories, varying dates (some future, some past — to test the date filter), real content in the Paragraphs sections, and registration URLs. Include at least 2 Conference and 2 Workshop events to test category filtering."},
{n:7,title:"Test the complete site",body:"Visit /events — only future events should show. Filter by 'Conference' — only conferences should appear. Click an event — the Layout Builder layout should show with the two-column format. Check that event URLs follow the Pathauto pattern."},
{n:8,title:"Export and commit everything",code:"ddev drush cex -y\ngit add config/\ngit commit -m 'Phase 2 capstone: events site with content type, views, layout, pathauto'"},
],aiCheck:{prompt:"Describe your completed events site: (1) What content type fields did you create? (2) What does the /events listing look like and how does filtering work? (3) What does a single event page look like? Share any interesting decisions you made.",checkGoal:"Evaluate the Phase 2 capstone project. Key checks: appropriate field types for event data, Views using date filter correctly, Paragraphs sections working, clean URLs. Give comprehensive feedback on content architecture quality and professional site building practices."}}},
{day:"Day 12",title:"Phase 2 Retrospective",goal:"Consolidate site building skills and prepare for custom module development.",
reading:[
{title:"Site Builder certification readiness",body:"You now have the skills for the Acquia Certified Site Builder exam. You've worked with Views, Paragraphs, Layout Builder, CMI, permissions, Search API, and Pathauto — all exam topic areas.",link:"https://docs.acquia.com/acquia-academy/acquia-certified-drupal-site-builder"},
{title:"What's next",body:"Phase 3 moves into custom module development — routing, Form API, Entity API, plugins, and services. This is where you go from configuring Drupal to extending it.",link:null},
],
activity:{type:"ai_open",prompt:"Phase 2 final — answer these three: (1) Describe the complete architecture of a Drupal site you'd build for a university department that needs: faculty profiles, course listings, news, events, and a resource library. What content types, Views, and modules would you use? (2) What's the difference between a Views exposed filter and a facet from the Search API Facets module? When would you use each? (3) Explain the CMI workflow from local dev all the way to production deployment, including what happens if someone made a config change directly on prod.",checkGoal:"Evaluate Phase 2 mastery. Key checks: (1) thoughtful content architecture with appropriate content types and relationships, (2) correct distinction — exposed filters are basic form filters on a Views query, facets aggregate and count results, (3) complete cmi workflow with awareness of the prod-direct-change anti-pattern. Score 0-10 with detailed Phase 2 feedback."}},
]},
{label:"Week 3",name:"Advanced configuration & components",days:[
{day:"Day 13",title:"Field Configuration Mastery",goal:"Go deep on field types, display modes, and field grouping — the skills that separate polished sites from rough ones.",
reading:[
{title:"Field storage vs. field instance",body:"Every Drupal field has two layers of config: <strong>field storage</strong> (data type, cardinality — shared across all bundles that use it) and <strong>field instance</strong> (required/optional, default value, help text — per bundle). field.storage.node.field_price.yml and field.field.node.product.field_price.yml are both created when you add a field.",link:null},
{title:"Display modes",body:"Drupal renders content differently depending on context. The <strong>Default</strong> display mode is used for full entity pages. <strong>Teaser</strong> is used in listing views. You can create custom display modes (e.g., Card, Admin Summary) and assign them in Views or Layout Builder.",link:null},
{title:"Field Group module",body:"The field_group contrib module lets you wrap fields in fieldsets, tabs, or accordions on both the content form and display. Essential for complex content types with many fields.",link:"https://www.drupal.org/project/field_group"},
{title:"Formatter vs. widget",body:"The <strong>widget</strong> controls how a field appears on the <em>edit form</em> (Manage form display). The <strong>formatter</strong> controls how it appears to <em>visitors</em> (Manage display). Always configure both.",link:null},
],
activity:{type:"hands_on",title:"Field configuration deep-dive on the Product content type",intro:"Configure formatters, display modes, and field groups on the Product content type you built in Day 3.",steps:[
{n:1,title:"Install the field_group module",body:"field_group is not in core — install via Composer. It adds a new 'Add group' button to the Manage form display and Manage display pages.",code:"ddev composer require drupal/field_group\nddev drush pm:enable field_group -y\nddev drush cr"},
{n:2,title:"Add Sale Price and SKU fields to Product",body:"Go to Admin → Structure → Content types → Product → Manage fields. Add field: Number (decimal), Label: Sale Price, machine name: field_sale_price, Scale 2, NOT required, Help text: 'Leave blank if no sale applies'. Add field: Text (plain), Label: SKU, machine name: field_sku, Max length 50, Required YES, Help text: 'Unique product identifier (e.g., PROD-001-BLK-M)'."},
{n:3,title:"Configure the Default display mode formatters",body:"Go to Admin → Structure → Content types → Product → Manage display. For Price: formatter → Decimal, gear icon → Decimal separator ., Scale 2, Prefix $, Apply. For Sale Price: same formatter settings as Price. Drag fields into this order: Price, Sale Price, Category, Featured, SKU, Stock Count.",},
{n:4,title:"Enable and configure the Teaser display mode",body:"Scroll to the bottom of Manage display. Under Custom display settings, check 'Teaser' and Save. Click the Teaser tab. Drag ALL fields except Title and Price to the 'Disabled' section. Teaser shows only the product name and price — perfect for listing pages. Click Save.",},
{n:5,title:"Create a Pricing field group on the edit form",body:"Go to Manage form display. Click 'Add group' (bottom of the page). Group type: Fieldset. Label: Pricing, machine name: group_pricing. Save and continue. Drag field_price and field_sale_price UNDER group_pricing (indented). Click the gear icon on group_pricing → Open state: Collapsed → Apply. This keeps the form clean by default.",},
{n:6,title:"Create an Advanced Details group on the edit form",body:"Click 'Add group' again. Fieldset. Label: Advanced Details, machine name: group_advanced, set to Collapsed. Drag field_sku and field_stock_count into it. Save. Now the form shows only the Product Name, Category, and Featured fields by default — the rest are in collapsed fieldsets.",},
{n:7,title:"Test the form and display",body:"Go to Add content → Product. Verify the Pricing and Advanced Details fieldsets appear collapsed. Save a test product. Visit the product's full page — verify Price shows with $ prefix and 2 decimal places. Visit /articles (or any listing using teaser view mode) — verify the teaser shows only title and price.",},
{n:8,title:"Inspect the config diff",code:"ddev drush cex -y\n# Inspect a field config to see storage vs instance:\ncat config/sync/field.storage.node.field_price.yml\necho '---'\ncat config/sync/field.field.node.product.field_price.yml\n# field.storage: defines type (decimal), precision, scale — shared\n# field.field: defines required, default_value, help_text — per-bundle"},
],aiCheck:{prompt:"Paste the output of `ls config/sync/ | grep 'field' | grep 'product'`. Also describe: how many field groups appear on the product form? Is the Pricing fieldset collapsed by default? Does the Teaser display mode show only 2 fields (title + price)?",checkGoal:"Verify the student has configured field groups, display modes, and formatters. Check that display modes (Default vs Teaser) show different fields, the form has proper field groups, and the Price formatter shows a $ prefix. Give specific feedback on display mode strategy and form UX choices."}}},
{day:"Day 14",title:"Block System Deep Dive",goal:"Master custom block content types, block placement with visibility rules, and custom block plugins.",
reading:[
{title:"Block content types vs. block plugins",body:"Drupal has two kinds of blocks. <strong>Block content</strong> (Admin → Structure → Block layout → Custom block library) are editor-created instances — a specific announcement, a specific sidebar widget. <strong>Block plugins</strong> are developer-created classes that generate dynamic content programmatically.",link:null},
{title:"Block regions",body:"Themes define regions (header, sidebar, footer, etc.) where blocks can be placed. Each theme has its own region map. You can add custom regions by editing the theme's .info.yml and page template.",link:null},
{title:"Block visibility rules",body:"Every placed block can be restricted to: specific pages (by path), specific roles, specific content types, or specific languages. Visibility rules are evaluated in the block's placement config — not the block plugin itself.",link:null},
{title:"ContainerFactoryPluginInterface",body:"Block plugins that need injected services must implement ContainerFactoryPluginInterface and add a static create() factory method. The plugin's constructor signature is different from regular services — it receives $configuration, $plugin_id, $plugin_definition, then injected services.",link:"https://api.drupal.org/api/drupal/core!lib!Drupal!Core!Plugin!ContainerFactoryPluginInterface.php"},
],
activity:{type:"hands_on",title:"Custom block content type, visibility rules, and a block plugin",intro:"Build a Site Alert custom block type, place it with visibility rules, and create a block plugin that shows dynamic site statistics.",steps:[
{n:1,title:"Create a Site Alert custom block content type",body:"Go to Admin → Structure → Block layout → then look for 'Custom block library' link or go to /admin/structure/block/block-content/types. Click 'Add custom block type'. Label: Site Alert, machine name: site_alert. Save. On Manage fields, add: field_alert_message (Text plain, required), field_alert_type (List text, options: info|Information, warning|Warning, danger|Danger, required, default: info), field_dismissible (Boolean, default: No).",},
{n:2,title:"Create block instances",body:"Go to Admin → Content → Blocks (or Admin → Structure → Block layout → 'Custom block library'). Click 'Add custom block' → Site Alert. Block 1: description 'Maintenance Notice', Alert Message: 'We will be performing scheduled maintenance on Sunday from 2–4 AM.', Alert Type: Warning, Dismissible: checked. Save. Block 2: description 'New Feature Announcement', Alert Message: 'New dashboard features are now available!', Alert Type: Information, Dismissible: unchecked. Save.",},
{n:3,title:"Place blocks with visibility rules",body:"Go to Admin → Structure → Block layout. Place 'Maintenance Notice' in the Highlighted region. In the placement config: uncheck 'Display title'. Visibility → Pages → 'Hide for the listed pages', add /user/login and /user/register. Save. Place 'New Feature Announcement' in the Help region. Visibility → Pages → 'Show for the listed pages', enter <front>. Visibility → Roles → check 'Authenticated user'. Save. Click 'Save blocks'.",},
{n:4,title:"Create a custom block plugin directory",body:"Block plugins live in src/Plugin/Block/ — that path is required for Drupal's plugin discovery to find your class.",code:"mkdir -p web/modules/custom/my_first_module/src/Plugin/Block"},
{n:5,title:"Create the SiteStatsBlock plugin class",body:"The @Block annotation is how Drupal discovers the plugin without scanning all PHP files. ContainerFactoryPluginInterface + static create() is required for DI in plugins — the constructor signature is different from regular services (it receives $configuration, $plugin_id, $plugin_definition first, then injected services). Cache tags (node_list, user_list) tell Drupal when to invalidate the cached block output.",code:"<?php\n// web/modules/custom/my_first_module/src/Plugin/Block/SiteStatsBlock.php\nnamespace Drupal\\my_first_module\\Plugin\\Block;\n\nuse Drupal\\Core\\Block\\BlockBase;\nuse Drupal\\Core\\Entity\\EntityTypeManagerInterface;\nuse Drupal\\Core\\Plugin\\ContainerFactoryPluginInterface;\nuse Symfony\\Component\\DependencyInjection\\ContainerInterface;\n\n/**\n * @Block(\n *   id = \"site_stats_block\",\n *   admin_label = @Translation(\"Site Statistics\"),\n *   category = @Translation(\"Custom\")\n * )\n */\nclass SiteStatsBlock extends BlockBase implements ContainerFactoryPluginInterface {\n\n  public function __construct(\n    array $configuration,\n    $plugin_id,\n    $plugin_definition,\n    protected EntityTypeManagerInterface $entityTypeManager\n  ) {\n    parent::__construct($configuration, $plugin_id, $plugin_definition);\n  }\n\n  public static function create(\n    ContainerInterface $container,\n    array $configuration,\n    $plugin_id,\n    $plugin_definition\n  ): static {\n    return new static(\n      $configuration, $plugin_id, $plugin_definition,\n      $container->get('entity_type.manager')\n    );\n  }\n\n  public function build(): array {\n    $nodeCount = $this->entityTypeManager->getStorage('node')->getQuery()\n      ->accessCheck(FALSE)->condition('status', 1)->count()->execute();\n    $userCount = $this->entityTypeManager->getStorage('user')->getQuery()\n      ->accessCheck(FALSE)->condition('status', 1)->condition('uid', 0, '>')->count()->execute();\n    return [\n      '#theme'  => 'item_list',\n      '#title'  => $this->t('Site Statistics'),\n      '#items'  => [\n        $this->t('@count published pieces of content', ['@count' => $nodeCount]),\n        $this->t('@count registered users', ['@count' => $userCount]),\n      ],\n      '#cache'  => ['tags' => ['node_list', 'user_list'], 'max-age' => 3600],\n    ];\n  }\n\n}"},
{n:6,title:"Rebuild caches and place the block",body:"After creating a new block plugin, rebuild caches so Drupal discovers the annotation. Then place it via the Block layout UI.",code:"ddev drush cr\n# Then: Admin → Structure → Block layout\n# Find any region → Place block → search 'Site Statistics'\n# Place block → Save block → Save blocks"},
{n:7,title:"Verify and export",code:"# Visit your site — the stats block should show node and user counts\n\nddev drush cex -y\nls config/sync/ | grep 'block.block'\n# Expected: multiple block.block.*.yml files — one per placed block"},
],aiCheck:{prompt:"Paste your SiteStatsBlock.php. Confirm: (1) Does the block appear in the Block library under 'Custom' category? (2) Does it show on the site with correct node and user counts? (3) Paste the output of `ls config/sync/ | grep 'block.block'`.",checkGoal:"Verify the student created a working block plugin with ContainerFactoryPluginInterface, correct annotation, DI of entity_type.manager, and working cache tags. Check that block content type was created with appropriate fields and blocks were placed with visibility rules. Give specific feedback on plugin architecture and cache strategy."}}},
{day:"Day 15",title:"Editorial Workflows with Content Moderation",goal:"Set up a complete editorial workflow with states, transitions, and role-based permissions.",
reading:[
{title:"Content Moderation module",body:"Content Moderation (core) extends Drupal's default published/unpublished states with custom workflow states. Content can move through states like Draft → In Review → Published → Archived, with different roles controlling which transitions are allowed.",link:"https://www.drupal.org/docs/8/core/modules/content-moderation"},
{title:"Workflows vs. states",body:"A <strong>Workflow</strong> defines the full state machine: what states exist, what transitions are allowed between them, and which entity types it applies to. States are the individual steps (Draft, In Review, Published). Transitions connect them directionally.",link:null},
{title:"Revisions and moderation",body:"Content Moderation relies on Drupal's revisioning system. When a node is in 'In Review' state, the live published version stays visible — only the pending revision changes. Editors work on revisions; visitors see the last published revision.",link:null},
],
activity:{type:"hands_on",title:"Build a complete editorial workflow",intro:"Enable Content Moderation, build a 4-state workflow with 7 transitions, and wire up role-based permissions.",steps:[
{n:1,title:"Enable the required core modules",body:"content_moderation and workflows are both core modules — no Composer install needed. workflows provides the state machine framework; content_moderation integrates it with Drupal entities.",code:"ddev drush pm:enable content_moderation workflows -y\nddev drush cr"},
{n:2,title:"Create the Editorial Workflow",body:"Go to Admin → Configuration → Workflow → Workflows. Click Add workflow. Name: Editorial Workflow, Workflow type: Content moderation. Click Save.",},
{n:3,title:"Add the four workflow states",body:"In the workflow editor, add these states one at a time via 'Add a new state': (1) Draft — Default revision: NO, Published: NO. (2) In Review — Default revision: NO, Published: NO. (3) Published — Default revision: YES, Published: YES. (4) Archived — Default revision: YES, Published: NO. The Published flag here controls whether content at that state is visible to anonymous users.",},
{n:4,title:"Add the seven transitions",body:"Transitions define which state changes are allowed. Add all seven: (1) Create new draft: Draft→Draft. (2) Submit for review: Draft→In Review. (3) Request changes: In Review→Draft. (4) Publish: In Review→Published. (5) Unpublish: Published→Draft. (6) Archive: Published→Archived. (7) Restore from archive: Archived→Draft.",},
{n:5,title:"Apply the workflow to Article content type",body:"Scroll down to 'This workflow applies to:'. Click Add another → Entity type: Content → Bundle: Article. Click Add. Click Save on the workflow. Now go to Admin → Structure → Content types → Article → Edit — you should see that 'Create new revision' is now forced on (Content Moderation requires it).",},
{n:6,title:"Create roles and assign transition permissions",body:"Each transition becomes its own permission. Content Editors can create drafts and submit for review; Content Managers can publish and archive. Run these commands, then also verify in Admin → People → Permissions.",code:"ddev drush role:create content_editor 'Content Editor'\nddev drush role:create content_manager 'Content Manager'\n\n# Editor permissions\nddev drush role:perm:add content_editor 'access content'\nddev drush role:perm:add content_editor 'create article content'\nddev drush role:perm:add content_editor 'edit own article content'\nddev drush role:perm:add content_editor 'use editorial_workflow transition create_new_draft'\nddev drush role:perm:add content_editor 'use editorial_workflow transition submit_for_review'\n\n# Manager permissions (everything editor has + approval powers)\nddev drush role:perm:add content_manager 'create article content'\nddev drush role:perm:add content_manager 'edit any article content'\nddev drush role:perm:add content_manager 'use editorial_workflow transition create_new_draft'\nddev drush role:perm:add content_manager 'use editorial_workflow transition submit_for_review'\nddev drush role:perm:add content_manager 'use editorial_workflow transition request_changes'\nddev drush role:perm:add content_manager 'use editorial_workflow transition publish'\nddev drush role:perm:add content_manager 'use editorial_workflow transition unpublish'\nddev drush role:perm:add content_manager 'use editorial_workflow transition archive'"},
{n:7,title:"Test the workflow as each role",body:"Go to Admin → People → Add user. Create editor1 with Content Editor role, and manager1 with Content Manager role. Log out of admin. Log in as editor1 → create a new Article → in the Moderation state dropdown at the bottom, you should only see 'Draft' and 'In Review'. Log out. Log in as manager1 → find the article → edit it → you should see all transitions including 'Publish'."},
{n:8,title:"Check moderation state programmatically",body:"Content Moderation stores states as field data accessible via the moderation_state pseudo-field. This pattern is useful in hooks and custom code.",code:"ddev drush php:eval \"\n\\$nids = \\Drupal::entityTypeManager()->getStorage('node')\n  ->getQuery()->accessCheck(FALSE)->condition('type', 'article')->execute();\nforeach (\\Drupal::entityTypeManager()->getStorage('node')->loadMultiple(\\$nids) as \\$node) {\n  echo \\$node->getTitle() . ' → ' . \\$node->get('moderation_state')->value . PHP_EOL;\n}\n\"\n# Expected: each article title followed by its current moderation state"},
{n:9,title:"Export config",code:"ddev drush cex -y\nls config/sync/ | grep workflow\n# Expected: workflows.workflow.editorial_workflow.yml and related files"},
],aiCheck:{prompt:"Paste the output of the drush php:eval command that lists articles and their moderation states. Also paste `ls config/sync/ | grep workflow`. Confirm: can an editor submit for review but NOT publish? Can a manager publish?",checkGoal:"Verify the student has set up a working Content Moderation workflow. Check: 4 states are correct, 7 transitions are wired correctly, roles have the right transition permissions (editor can't publish), and programmatic state reading works. Give specific feedback on the access model and revision strategy."}}},
]},
]},
{id:3,label:"Phase 3",name:"Custom Module Development",color:"#f5a623",bg:"#281d08",weeks:[
{label:"Week 1",name:"Routing, controllers & forms",days:[
{day:"Day 1",title:"Routing System Deep Dive",goal:"Understand how Drupal maps URLs to code using its routing system.",
reading:[
{title:"How routing works",body:"Drupal maps URLs to controller methods via YAML routing files ({module}.routing.yml). Every custom page needs a route definition. The router handles access control, parameters, and admin path detection.",link:"https://www.drupal.org/docs/8/api/routing-system"},
{title:"Route parameters & upcasting",body:"Routes can have dynamic segments like /node/{node} or /user/{user_id}. Drupal auto-loads ('upcasts') the entity if the parameter name matches an entity type — so {node} gives you a fully-loaded Node object.",link:null},
{title:"Access callbacks",body:"The 'requirements' section of a route defines access. _permission, _role, _entity_access, and custom _custom_access callbacks are all options. Access is denied before the controller runs.",link:null},
],
activity:{type:"hands_on",title:"Build a custom route and controller",intro:"Create a custom page at /hello/{name} that greets the user.",steps:[
{n:1,title:"Create the routing YAML file",body:"The routing file maps URLs to controllers. The key (my_first_module.hello) is the route name — used everywhere in Drupal to generate URLs. The path {name} is a dynamic parameter that gets passed to the controller. The requirements section enforces access — _permission means the user must have that permission.",code:"# web/modules/custom/my_first_module/my_first_module.routing.yml\nmy_first_module.hello:\n  path: '/hello/{name}'\n  defaults:\n    _controller: '\\Drupal\\my_first_module\\Controller\\HelloController::page'\n    _title: 'Hello Page'\n  requirements:\n    _permission: 'access content'"},
{n:2,title:"Create the Controller directory",body:"Controllers must live in src/Controller/ to follow Drupal's PSR-4 namespace convention.",code:"mkdir -p web/modules/custom/my_first_module/src/Controller"},
{n:3,title:"Create the HelloController class",body:"ControllerBase gives you access to Drupal services via shorthand methods ($this->t(), $this->currentUser(), etc.). The method name must match the ::page in routing.yml. The {name} URL parameter arrives as a PHP parameter of the same name. Return a render array — never return a string directly from a controller.",code:"<?php\n// web/modules/custom/my_first_module/src/Controller/HelloController.php\nnamespace Drupal\\my_first_module\\Controller;\n\nuse Drupal\\Core\\Controller\\ControllerBase;\n\nclass HelloController extends ControllerBase {\n\n  public function page(string $name): array {\n    return [\n      '#markup' => $this->t('Hello, @name! Welcome to Drupal routing.', [\n        '@name' => $name,\n      ]),\n    ];\n  }\n\n}"},
{n:4,title:"Rebuild caches",body:"Routing YAML is cached. Any time you add or change a .routing.yml file, you must run drush cr before Drupal recognizes the new route.",code:"ddev drush cr\n# Expected: [success] Cache rebuild complete."},
{n:5,title:"Test the route in your browser",body:"Visit your site's URL with the /hello/{name} path. Replace {name} with your own name. You should see the greeting. Also test the access control — if you log out, can anonymous users still see the page? They should, because 'access content' is granted to anonymous users by default.",code:"# Visit in browser:\n# https://your-site.ddev.site/hello/Roland\n# Expected page title: Hello Page\n# Expected body: Hello, Roland! Welcome to Drupal routing."},
{n:6,title:"Extend the route to show the current user",body:"Update your controller to also display the logged-in user's name. currentUser() is available via ControllerBase.",code:"// Updated HelloController page() method:\npublic function page(string $name): array {\n  $current_user = $this->currentUser()->getDisplayName();\n  return [\n    '#markup' => $this->t(\n      'Hello, @name! You are logged in as @user.',\n      ['@name' => $name, '@user' => $current_user]\n    ),\n  ];\n}"},
{n:7,title:"Rebuild and test the updated controller",code:"ddev drush cr\n# Visit /hello/Roland again — you should now see both names"},
],aiCheck:{prompt:"Paste your routing YAML and HelloController.php. Also describe what happened when you visited /hello/YourName.",checkGoal:"Verify correct routing YAML indentation, proper class namespace and ControllerBase extension, render array returned (not a string), and that the page loaded. Give specific feedback."}}},
{day:"Day 2",title:"Form API — FormBase",goal:"Build custom forms using Drupal's Form API.",
reading:[
{title:"Drupal Form API",body:"Drupal provides a standard way to build forms using the Form API. All forms are PHP classes extending FormBase (or ConfigFormBase for settings). The API handles CSRF protection, validation, theming, and submission automatically.",link:"https://www.drupal.org/docs/drupal-apis/form-api"},
{title:"The three key methods",body:"<strong>buildForm()</strong> — define form structure as a render array. <strong>validateForm()</strong> — add validation logic, call $form_state->setError() for errors. <strong>submitForm()</strong> — handle submission, save data, redirect.",link:null},
{title:"Form element types",body:"textfield, textarea, select, checkboxes, radios, email, number, date, file, managed_file, entity_autocomplete. Each has standard properties: #title, #required, #default_value, #description.",link:null},
],
activity:{type:"hands_on",title:"Build a subscription form",intro:"Create a custom form that collects name and email with validation.",steps:[
{n:1,title:"Create the Form directory",body:"Form classes live in src/Form/ by Drupal convention.",code:"mkdir -p web/modules/custom/my_first_module/src/Form"},
{n:2,title:"Create the SubscribeForm class",body:"FormBase provides $this->t() and $this->messenger(). The getFormId() return value must be globally unique — prefix with your module name. In buildForm(), each form element is an array entry with #type, #title, and other properties. In validateForm(), setErrorByName() attaches the error message to a specific field. In submitForm(), use $form_state->getValue() to read submitted data.",code:"<?php\n// web/modules/custom/my_first_module/src/Form/SubscribeForm.php\nnamespace Drupal\\my_first_module\\Form;\n\nuse Drupal\\Core\\Form\\FormBase;\nuse Drupal\\Core\\Form\\FormStateInterface;\n\nclass SubscribeForm extends FormBase {\n\n  public function getFormId(): string {\n    return 'my_first_module_subscribe';\n  }\n\n  public function buildForm(array $form, FormStateInterface $form_state): array {\n    $form['name'] = [\n      '#type' => 'textfield',\n      '#title' => $this->t('Full name'),\n      '#required' => TRUE,\n      '#maxlength' => 100,\n    ];\n    $form['email'] = [\n      '#type' => 'email',\n      '#title' => $this->t('Email address'),\n      '#required' => TRUE,\n    ];\n    $form['interests'] = [\n      '#type' => 'checkboxes',\n      '#title' => $this->t('Interests'),\n      '#options' => [\n        'drupal' => $this->t('Drupal'),\n        'php' => $this->t('PHP'),\n        'frontend' => $this->t('Frontend'),\n      ],\n    ];\n    $form['submit'] = [\n      '#type' => 'submit',\n      '#value' => $this->t('Subscribe'),\n    ];\n    return $form;\n  }\n\n  public function validateForm(array &$form, FormStateInterface $form_state): void {\n    $name = trim($form_state->getValue('name'));\n    if (strlen($name) < 2) {\n      $form_state->setErrorByName('name', $this->t('Name must be at least 2 characters.'));\n    }\n  }\n\n  public function submitForm(array &$form, FormStateInterface $form_state): void {\n    $name = $form_state->getValue('name');\n    $email = $form_state->getValue('email');\n    $interests = array_filter($form_state->getValue('interests'));\n    $this->messenger()->addStatus(\n      $this->t('Thanks @name (@email), you\\'re subscribed to: @topics', [\n        '@name' => $name,\n        '@email' => $email,\n        '@topics' => implode(', ', $interests) ?: 'all topics',\n      ])\n    );\n  }\n\n}"},
{n:3,title:"Add a route pointing to the form class",body:"Using _form instead of _controller tells Drupal to instantiate and render the form class directly — no need to write a controller.",code:"# Add to my_first_module.routing.yml\nmy_first_module.subscribe:\n  path: '/subscribe'\n  defaults:\n    _form: '\\Drupal\\my_first_module\\Form\\SubscribeForm'\n    _title: 'Subscribe to Updates'\n  requirements:\n    _access: 'TRUE'"},
{n:4,title:"Rebuild caches",code:"ddev drush cr"},
{n:5,title:"Test form validation",body:"Visit /subscribe. Try these test cases: (1) Submit with an empty name — the #required should trigger a browser error. (2) Submit with a 1-character name (e.g., 'A') — your custom validateForm should show 'Name must be at least 2 characters.' (3) Submit with valid data — the success message should appear with your name, email, and selected interests."},
],aiCheck:{prompt:"Paste your SubscribeForm.php and describe what happens when you: (1) submit with a 1-character name, (2) submit with valid data.",checkGoal:"Verify correct Form API structure: getFormId returns unique string, buildForm returns render array with proper element types, validateForm uses setErrorByName, submitForm uses messenger. Check validation fires correctly. Give specific feedback."}}},
{day:"Day 3",title:"Form API — ConfigFormBase",goal:"Build admin settings forms that save to Drupal's configuration system.",
reading:[
{title:"ConfigFormBase",body:"ConfigFormBase extends FormBase with built-in support for saving to Drupal's config system. It uses $this->config() to read/write values, which are then exportable via drush cex.",link:null},
{title:"The getEditableConfigNames() method",body:"This protected method tells Drupal which config objects your form manages. These must be declared for the form to be able to write config values.",link:null},
],
activity:{type:"hands_on",title:"Build an admin settings form",intro:"Create a settings page for your module that saves config values.",steps:[
{n:1,title:"Create SettingsForm.php extending ConfigFormBase",body:"ConfigFormBase extends FormBase with two extras: it knows which config objects your form manages (getEditableConfigNames), and it reads/writes to the Drupal config system automatically. Values saved here are exportable via drush cex — they travel to other environments with your config workflow.",code:"<?php\n// web/modules/custom/my_first_module/src/Form/SettingsForm.php\nnamespace Drupal\\my_first_module\\Form;\n\nuse Drupal\\Core\\Form\\ConfigFormBase;\nuse Drupal\\Core\\Form\\FormStateInterface;\n\nclass SettingsForm extends ConfigFormBase {\n\n  protected function getEditableConfigNames(): array {\n    return ['my_first_module.settings'];\n  }\n\n  public function getFormId(): string {\n    return 'my_first_module_settings';\n  }\n\n  public function buildForm(array $form, FormStateInterface $form_state): array {\n    $config = $this->config('my_first_module.settings');\n\n    $form['greeting'] = [\n      '#type' => 'textfield',\n      '#title' => $this->t('Greeting text'),\n      '#description' => $this->t('Used in the welcome message on the subscribe form.'),\n      '#default_value' => $config->get('greeting') ?? 'Hello',\n      '#required' => TRUE,\n    ];\n    $form['max_items'] = [\n      '#type' => 'number',\n      '#title' => $this->t('Maximum items to show'),\n      '#default_value' => $config->get('max_items') ?? 5,\n      '#min' => 1,\n      '#max' => 50,\n    ];\n    $form['feature_enabled'] = [\n      '#type' => 'checkbox',\n      '#title' => $this->t('Enable reading time feature'),\n      '#default_value' => $config->get('feature_enabled') ?? TRUE,\n    ];\n\n    return parent::buildForm($form, $form_state);\n  }\n\n  public function submitForm(array &$form, FormStateInterface $form_state): void {\n    $this->config('my_first_module.settings')\n      ->set('greeting', $form_state->getValue('greeting'))\n      ->set('max_items', (int) $form_state->getValue('max_items'))\n      ->set('feature_enabled', (bool) $form_state->getValue('feature_enabled'))\n      ->save();\n    parent::submitForm($form, $form_state);\n  }\n\n}"},
{n:2,title:"Add the admin route",body:"Admin routes go under /admin/config/. The _permission requirement ensures only administrators can access this page. The path /admin/config/system/my-module follows Drupal's admin URL convention — system configs live under /admin/config/system/.",code:"# Add to my_first_module.routing.yml\nmy_first_module.settings:\n  path: '/admin/config/system/my-module'\n  defaults:\n    _form: '\\Drupal\\my_first_module\\Form\\SettingsForm'\n    _title: 'My Module Settings'\n  requirements:\n    _permission: 'administer site configuration'"},
{n:3,title:"Rebuild and open the settings page",code:"ddev drush cr\n# Visit: https://your-site.ddev.site/admin/config/system/my-module\n# Fill in values and click Save configuration"},
{n:4,title:"Verify the values were saved to the config system",body:"After submitting, run drush cget to confirm the values are in Drupal's config system. The config object name matches what you declared in getEditableConfigNames().",code:"ddev drush cget my_first_module.settings\n# Expected output:\n# greeting: 'Hello'\n# max_items: 5\n# feature_enabled: true"},
{n:5,title:"Use the saved config value in the hook",body:"Update your hook_node_presave to read the feature_enabled flag from config before auto-calculating reading time.",code:"// Updated in my_first_module.module:\nfunction my_first_module_node_presave($node) {\n  if ($node->bundle() !== 'article') {\n    return;\n  }\n  $config = \\Drupal::config('my_first_module.settings');\n  if (!$config->get('feature_enabled')) {\n    return;\n  }\n  $body = $node->get('body')->value ?? '';\n  $words = str_word_count(strip_tags($body));\n  $node->set('field_reading_time', max(1, (int) round($words / 200)));\n}"},
],aiCheck:{prompt:"Paste your SettingsForm.php and the output of `ddev drush cget my_first_module.settings` after saving the form.",checkGoal:"Verify ConfigFormBase usage: getEditableConfigNames returns the config object name, buildForm reads from config with default values, submitForm saves with ->set()->save() pattern, admin permission on route. Check that drush cget shows saved values."}}},
{day:"Day 4",title:"Entity API — Loading & Querying",goal:"Work programmatically with Drupal entities using the Entity API.",
reading:[
{title:"EntityTypeManager",body:"The central service for entity operations. Key methods: getStorage('entity_type') → EntityStorageInterface with load(), loadMultiple(), create(), delete().",link:"https://api.drupal.org/api/drupal/core!lib!Drupal!Core!Entity!EntityTypeManager.php"},
{title:"Entity queries",body:"Use entityTypeManager->getStorage('node')->getQuery() to build programmatic queries. Supports conditions, sort, range, accessCheck. Returns entity IDs — load them separately.",link:null},
{title:"Creating and saving entities",body:"$node = Node::create(['type'=>'article','title'=>'Test','status'=>1]); $node->save(). Field values use $node->set('field_name', $value) or $node->get('field_name')->setValue($value).",link:null},
],
activity:{type:"hands_on",title:"Entity API CRUD operations",intro:"Practice creating, loading, querying, and updating entities programmatically.",steps:[
{n:1,title:"Query entities with conditions and sorting",body:"getQuery() builds an entity query — it's like a typed query builder for entities. Always include ->accessCheck(TRUE) so Drupal enforces permissions. The result is an array of IDs, not loaded entities — this is intentional for performance. Load them separately with loadMultiple().",code:"ddev drush php:eval \"\n\\$storage = \\Drupal::entityTypeManager()->getStorage('node');\n\\$ids = \\$storage->getQuery()\n  ->accessCheck(TRUE)\n  ->condition('type', 'article')\n  ->condition('status', 1)\n  ->sort('created', 'DESC')\n  ->range(0, 3)\n  ->execute();\necho 'Found IDs: ' . implode(', ', \\$ids) . PHP_EOL;\n\\$nodes = \\$storage->loadMultiple(\\$ids);\nforeach (\\$nodes as \\$n) {\n  echo \\$n->id() . ': ' . \\$n->getTitle() . PHP_EOL;\n}\n\"\n# Expected: node IDs and titles of your 3 most recent articles"},
{n:2,title:"Load a single entity by ID",body:"load() returns one entity or NULL if not found. Always check for NULL before using the entity. The pattern is: load → check null → use.",code:"ddev drush php:eval \"\n\\$node = \\Drupal::entityTypeManager()->getStorage('node')->load(1);\nif (\\$node) {\n  echo 'Title: ' . \\$node->getTitle() . PHP_EOL;\n  echo 'Status: ' . (\\$node->isPublished() ? 'Published' : 'Unpublished') . PHP_EOL;\n  echo 'Created: ' . date('Y-m-d', \\$node->getCreatedTime()) . PHP_EOL;\n} else {\n  echo 'Node 1 does not exist';\n}\n\""},
{n:3,title:"Create and save a new entity",body:"Node::create() accepts an associative array of field values. 'type' is the bundle (content type). After setting values, always call ->save() — the entity is not persisted until save() is called. After save, $node->id() returns the new numeric ID.",code:"ddev drush php:eval \"\n\\$node = \\Drupal\\node\\Entity\\Node::create([\n  'type' => 'article',\n  'title' => 'Created via Entity API at ' . date('H:i:s'),\n  'status' => 1,\n  'body' => [\n    'value' => '<p>This article was created programmatically.</p>',\n    'format' => 'basic_html',\n  ],\n]);\n\\$node->save();\necho 'Created node ID: ' . \\$node->id() . PHP_EOL;\necho 'URL: /node/' . \\$node->id() . PHP_EOL;\n\"\n# Visit /node/{id} to confirm it was created"},
{n:4,title:"Update an existing entity",body:"Load → modify → save. The key rule: you must call save() after changing field values or nothing persists. setTitle() is a typed method on NodeInterface. For custom fields, use set('field_name', $value).",code:"ddev drush php:eval \"\n\\$nid = 1; // Replace with a real node ID from your site\n\\$node = \\Drupal::entityTypeManager()->getStorage('node')->load(\\$nid);\nif (!\\$node) { echo 'Node not found'; exit; }\n\\$original_title = \\$node->getTitle();\n\\$node->setTitle('Updated: ' . \\$original_title . ' [' . date('H:i:s') . ']');\n\\$node->save();\necho 'Updated title: ' . \\$node->getTitle() . PHP_EOL;\n\""},
{n:5,title:"Delete an entity",body:"Only delete the programmatically created test node — not real content. After delete(), the entity is removed from the database. You can also use deleteMultiple() for bulk deletions.",code:"ddev drush php:eval \"\n// Use the node ID that was created in step 3\n\\$nid = 999; // Replace with the ID from step 3\n\\$node = \\Drupal::entityTypeManager()->getStorage('node')->load(\\$nid);\nif (\\$node) {\n  \\$title = \\$node->getTitle();\n  \\$node->delete();\n  echo 'Deleted: ' . \\$title . PHP_EOL;\n} else {\n  echo 'Node not found';\n}\n\""},
],aiCheck:{prompt:"Paste the output of all three drush php:eval commands. Did all three operations (query, create, update) work? What node ID was created?",checkGoal:"Verify the student can use the Entity API for all CRUD operations. Check that: query returns correct results, create produces a new node ID, update changes the title. Give feedback on Entity API patterns and common pitfalls."}}},
{day:"Day 5",title:"Plugin System — Custom Block Plugins",goal:"Understand Drupal's plugin system and build a custom block plugin.",
reading:[
{title:"What is a plugin?",body:"Plugins are swappable implementations of a type. Drupal has plugin types for: blocks, field formatters, field widgets, views handlers, migrate sources, etc. Each plugin type has a manager that discovers and instantiates plugins.",link:"https://www.drupal.org/docs/drupal-apis/plugin-api"},
{title:"Block plugins",body:"Custom blocks are the most common plugin you'll write. They use the @Block annotation for discovery and must implement build() to return a render array.",link:null},
{title:"Annotations",body:"Drupal uses PHP docblock annotations (via Doctrine Annotations) for plugin discovery. The @Block annotation tells Drupal about your plugin — its ID, admin label, and category.",link:null},
],
activity:{type:"hands_on",title:"Build a custom block plugin",intro:"Create a block that shows the current user's name and their recent nodes.",steps:[
{n:1,title:"Create the Plugin/Block directory",body:"Block plugins must live in src/Plugin/Block/ — this path is part of Drupal's plugin discovery. The namespace must also match.",code:"mkdir -p web/modules/custom/my_first_module/src/Plugin/Block"},
{n:2,title:"Create UserSummaryBlock.php",body:"The @Block annotation tells Drupal this is a block plugin — id is unique, admin_label appears in the block library. ContainerFactoryPluginInterface enables DI — without it, you'd have no way to inject services into a plugin. The static create() method is the factory that pulls services from the container. build() returns the render array that becomes the block's content.",code:"<?php\n// web/modules/custom/my_first_module/src/Plugin/Block/UserSummaryBlock.php\nnamespace Drupal\\my_first_module\\Plugin\\Block;\n\nuse Drupal\\Core\\Block\\BlockBase;\nuse Drupal\\Core\\Plugin\\ContainerFactoryPluginInterface;\nuse Drupal\\Core\\Entity\\EntityTypeManagerInterface;\nuse Drupal\\Core\\Session\\AccountInterface;\nuse Symfony\\Component\\DependencyInjection\\ContainerInterface;\n\n/**\n * @Block(\n *   id = \"user_summary_block\",\n *   admin_label = @Translation(\"User Summary\"),\n *   category = @Translation(\"Custom\")\n * )\n */\nclass UserSummaryBlock extends BlockBase implements ContainerFactoryPluginInterface {\n\n  public function __construct(\n    array $config,\n    $plugin_id,\n    $plugin_def,\n    protected EntityTypeManagerInterface $entityTypeManager,\n    protected AccountInterface $currentUser,\n  ) {\n    parent::__construct($config, $plugin_id, $plugin_def);\n  }\n\n  public static function create(ContainerInterface $container, array $config, $plugin_id, $plugin_def): static {\n    return new static(\n      $config, $plugin_id, $plugin_def,\n      $container->get('entity_type.manager'),\n      $container->get('current_user'),\n    );\n  }\n\n  public function build(): array {\n    $name = htmlspecialchars($this->currentUser->getDisplayName());\n    $uid = $this->currentUser->id();\n\n    if ($uid === 0) {\n      return ['#markup' => '<p>Please log in to see your summary.</p>'];\n    }\n\n    $storage = $this->entityTypeManager->getStorage('node');\n    $ids = $storage->getQuery()\n      ->accessCheck(TRUE)\n      ->condition('uid', $uid)\n      ->condition('status', 1)\n      ->sort('created', 'DESC')\n      ->range(0, 3)\n      ->execute();\n    $nodes = $storage->loadMultiple($ids);\n\n    $items = [];\n    foreach ($nodes as $node) {\n      $items[] = '<li>' . htmlspecialchars($node->getTitle()) . '</li>';\n    }\n\n    $list = $items ? '<ul>' . implode('', $items) . '</ul>' : '<p>No articles yet.</p>';\n\n    return [\n      '#markup' => '<p>Welcome, <strong>' . $name . '</strong>!</p><p>Your recent articles:</p>' . $list,\n    ];\n  }\n\n}"},
{n:3,title:"Rebuild caches to discover the plugin",body:"Block plugins are discovered via annotation scanning, which is cached. Rebuild caches after creating any new plugin.",code:"ddev drush cr\n# Expected: [success] Cache rebuild complete."},
{n:4,title:"Find and place the block",body:"Go to Admin → Structure → Block layout. Click 'Place block' in any region (e.g., Sidebar first). Search for 'User Summary'. Click 'Place block'. Save the block configuration (you can leave defaults). Save the block layout page."},
{n:5,title:"Verify the block on the frontend",body:"Visit the homepage as a logged-in user. The User Summary block should appear in the sidebar with your name and your recent articles. Log out — you should see the 'Please log in' message."},
],aiCheck:{prompt:"Paste your UserSummaryBlock.php and confirm: (1) Does the block appear in the block library? (2) When placed, does it show the current user's name?",checkGoal:"Verify correct block plugin structure: @Block annotation with id/admin_label/category, ContainerFactoryPluginInterface for DI, correct create() factory method, build() returns render array. Check that it appears in the block UI. Give specific feedback."}}},
{day:"Day 6",title:"Custom Entity Type",goal:"Build a completely custom content entity type in Drupal.",
reading:[
{title:"When to create a custom entity",body:"Create a custom entity when: you need a data structure that doesn't fit nodes/taxonomy, you want admin CRUD UI without content moderation overhead, or you're building a specific feature (e.g., job listings, subscriber records).",link:null},
{title:"ContentEntityBase",body:"Custom content entities extend ContentEntityBase. You define fields in baseFieldDefinitions() and use annotations to declare entity metadata (admin labels, routes, handlers).",link:null},
],
activity:{type:"hands_on",title:"Build a Subscriber custom entity",intro:"Create a simple custom entity to store newsletter subscriber records.",steps:[
{n:1,title:"Create the Entity directory",body:"Entity classes live in src/Entity/ by Drupal convention.",code:"mkdir -p web/modules/custom/my_first_module/src/Entity"},
{n:2,title:"Create the Subscriber entity class",body:"The @ContentEntityType annotation is the entity definition — id is used everywhere in code, base_table is the database table name, entity_keys maps special fields (id = primary key, label = display field). baseFieldDefinitions() defines the database schema and field types. Always call parent::baseFieldDefinitions() first to get the id and langcode fields.",code:"<?php\n// web/modules/custom/my_first_module/src/Entity/Subscriber.php\nnamespace Drupal\\my_first_module\\Entity;\n\nuse Drupal\\Core\\Entity\\ContentEntityBase;\nuse Drupal\\Core\\Field\\BaseFieldDefinition;\nuse Drupal\\Core\\Entity\\EntityTypeInterface;\n\n/**\n * @ContentEntityType(\n *   id = \"subscriber\",\n *   label = @Translation(\"Subscriber\"),\n *   label_collection = @Translation(\"Subscribers\"),\n *   base_table = \"subscriber\",\n *   entity_keys = {\n *     \"id\" = \"id\",\n *     \"label\" = \"email\"\n *   },\n *   admin_permission = \"administer site configuration\"\n * )\n */\nclass Subscriber extends ContentEntityBase {\n\n  public static function baseFieldDefinitions(EntityTypeInterface $entity_type): array {\n    $fields = parent::baseFieldDefinitions($entity_type);\n\n    $fields['email'] = BaseFieldDefinition::create('email')\n      ->setLabel(t('Email address'))\n      ->setRequired(TRUE)\n      ->setDisplayOptions('form', ['type' => 'email_default', 'weight' => 0])\n      ->setDisplayOptions('view', ['label' => 'above', 'type' => 'basic_string', 'weight' => 0]);\n\n    $fields['name'] = BaseFieldDefinition::create('string')\n      ->setLabel(t('Full name'))\n      ->setSettings(['max_length' => 100])\n      ->setDisplayOptions('form', ['type' => 'string_textfield', 'weight' => 1])\n      ->setDisplayOptions('view', ['label' => 'above', 'type' => 'string', 'weight' => 1]);\n\n    $fields['subscribed_at'] = BaseFieldDefinition::create('created')\n      ->setLabel(t('Subscribed at'))\n      ->setDescription(t('The time this subscriber was created.'));\n\n    return $fields;\n  }\n\n}"},
{n:3,title:"Clear caches and run database updates",body:"New entity type definitions are cached. Clear first, then run updb — Drupal will detect the new entity type and create the 'subscriber' database table.",code:"ddev drush cr\nddev drush updb -y\n# Expected: if the entity type is new, you'll see a message about creating tables\n# If nothing happens, force it:\nddev drush php:eval \"\\Drupal::entityTypeManager()->clearCachedDefinitions(); drupal_flush_all_caches();\""},
{n:4,title:"Verify the database table was created",body:"Confirm the subscriber table exists in the database.",code:"ddev drush php:eval \"\n\\$schema = \\Drupal::database()->schema();\necho \\$schema->tableExists('subscriber') ? 'Table exists!' : 'Table NOT found';\n\"\n# Expected: Table exists!"},
{n:5,title:"Create a subscriber entity programmatically",body:"The Entity API for creating custom entities is identical to creating nodes — Node::create() vs Subscriber::create(). This is the power of the entity system.",code:"ddev drush php:eval \"\n\\$sub = \\Drupal\\my_first_module\\Entity\\Subscriber::create([\n  'email' => 'test@example.com',\n  'name' => 'Test Subscriber',\n]);\n\\$sub->save();\necho 'Created subscriber ID: ' . (int) \\$sub->id() . PHP_EOL;\n\"\n# Expected: Created subscriber ID: 1"},
{n:6,title:"Load and verify the saved subscriber",code:"ddev drush php:eval \"\n\\$sub = \\Drupal::entityTypeManager()->getStorage('subscriber')->load(1);\nif (\\$sub) {\n  echo 'Email: ' . \\$sub->get('email')->value . PHP_EOL;\n  echo 'Name: ' . \\$sub->get('name')->value . PHP_EOL;\n} else {\n  echo 'Not found';\n}\n\""},
],aiCheck:{prompt:"Paste your Subscriber.php entity class and the output of the subscriber creation command. Did the entity save successfully with an ID?",checkGoal:"Verify correct custom entity structure: @ContentEntityType annotation with id/label/base_table/entity_keys, baseFieldDefinitions returns proper field definitions with display options, entity saves with a numeric ID. Give feedback on entity design and common issues."}}},
{day:"Day 7",title:"Week 1 Review — Module Dev",goal:"Consolidate routing, Form API, Entity API, and plugins with a comprehensive challenge.",
reading:[
{title:"What you've mastered",body:"You can now build custom pages, forms, admin settings, query entities, write block plugins, and create custom entity types. This covers the core of the Acquia Backend Specialist exam.",link:null},
],
activity:{type:"ai_open",prompt:"Module dev challenge — answer all three: (1) Walk me through building a custom Drupal page that shows a form, and when submitted, creates a new Node programmatically using the Entity API. Describe the files you'd need to create and the key code in each. (2) What is the difference between a ContentEntityBase and a ConfigEntityBase? Give a real-world example of when you'd create each. (3) You're building a block that needs to show content from an external API. Why should you use ContainerFactoryPluginInterface and inject a custom HTTP client service rather than calling file_get_contents() directly?",checkGoal:"Evaluate the student's module dev understanding. Key answers: (1) routing.yml + Controller (or _form route) + Form class with submitForm creating a Node; (2) content=database rows+CRUD, config=YAML+admin settings — e.g., subscriber records vs. module configuration; (3) testability, DI, service reuse, separation of concerns. Score 0-10 with specific feedback."}},
]},
{label:"Week 2",name:"Services, testing & advanced APIs",days:[
{day:"Day 8",title:"Queue API & Batch API",goal:"Handle long-running and background tasks properly in Drupal.",
reading:[
{title:"Queue API",body:"The Queue API processes items asynchronously. Use it for: sending emails, third-party API calls, image processing — anything that shouldn't block a page request. Cron processes queues.",link:"https://api.drupal.org/api/drupal/core!core.api.php/group/queue"},
{title:"Batch API",body:"The Batch API handles long-running operations with a progress bar in the browser. Use it for: bulk content updates, large imports, bulk email sends. Unlike Queue, it runs in the foreground with user feedback.",link:"https://api.drupal.org/api/drupal/core!includes!form.inc/group/batch"},
{title:"When to use which",body:"Queue: background, no UI feedback needed, can run on cron. Batch: foreground, user needs to see progress, admin operations.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You need to send 10,000 notification emails when a major announcement is published. Which API should you use?",options:["Process all emails in hook_node_insert — it's fine since it's async","Use the Batch API to show a progress bar to the editor","Add all emails to a Queue and process them via cron","Use PHP's mail() function in a loop"],answer:2,explanation:"For background email sending, Queue is ideal. Add each email as a queue item in hook_node_insert, then a QueueWorker processes them asynchronously on cron. This won't block the editor's page load or risk timeouts."},
{q:"An admin needs to update a custom field on 50,000 existing nodes. Which API is most appropriate?",options:["A single PHP loop in a .module file","The Queue API processed by cron","The Batch API with a progress bar","The Entity API in a drush script"],answer:2,explanation:"Batch API is perfect here — the admin triggers it, watches a progress bar, and gets confirmation when done. It splits the work into chunks to avoid memory limits and timeouts."},
]}},
{day:"Day 9",title:"Database API & Custom Tables",goal:"Use Drupal's Database API for custom data storage and queries.",
reading:[
{title:"Drupal's Database API",body:"Drupal wraps PDO in a database abstraction layer. Use \\Drupal::database() for custom queries. Supports select(), insert(), update(), delete(), merge(), and upsert().",link:"https://www.drupal.org/docs/drupal-apis/database-api"},
{title:"When to use custom tables vs. entities",body:"Custom entity: when you need revisions, translations, field UI, Views integration. Custom table: for high-volume log/analytics data, junction tables, simple key-value stores where entity overhead is too much.",link:null},
{title:"hook_schema()",body:"Define custom database tables in hook_schema() in your {module}.install file. Drupal creates them on module install and manages updates via hook_update_N().",link:null},
],
activity:{type:"hands_on",title:"Create a custom analytics table",intro:"Build a simple page view counter using a custom database table.",steps:[
{n:1,title:"Create the .install file with hook_schema()",body:"hook_schema() tells Drupal the structure of your custom tables. Drupal creates these tables when the module is installed (and removes them on uninstall). The schema format defines each column's type, length, and constraints.",code:"<?php\n// web/modules/custom/my_first_module/my_first_module.install\n\n/**\n * Implements hook_schema().\n */\nfunction my_first_module_schema(): array {\n  return [\n    'my_module_page_views' => [\n      'description' => 'Tracks page view counts per path.',\n      'fields' => [\n        'path' => [\n          'type' => 'varchar',\n          'length' => 255,\n          'not null' => TRUE,\n          'default' => '',\n          'description' => 'The request path.',\n        ],\n        'views' => [\n          'type' => 'int',\n          'unsigned' => TRUE,\n          'not null' => TRUE,\n          'default' => 0,\n          'description' => 'Total view count for this path.',\n        ],\n        'last_viewed' => [\n          'type' => 'int',\n          'unsigned' => TRUE,\n          'not null' => TRUE,\n          'default' => 0,\n          'description' => 'Unix timestamp of last view.',\n        ],\n      ],\n      'primary key' => ['path'],\n    ],\n  ];\n}"},
{n:2,title:"Apply the schema by reinstalling the module",body:"The schema is only created on fresh install. Since the module is already installed, you need to either reinstall it or manually apply the schema.",code:"# Option 1: Reinstall the module (loses all module data)\nddev drush pm:uninstall my_first_module -y && ddev drush pm:enable my_first_module -y && ddev drush cr\n\n# Option 2: Apply schema manually (keeps existing module data)\nddev drush php:eval \"\n\\$schema = \\Drupal::database()->schema();\nif (!\\$schema->tableExists('my_module_page_views')) {\n  \\$module_schema = my_first_module_schema();\n  \\$schema->createTable('my_module_page_views', \\$module_schema['my_module_page_views']);\n  echo 'Table created!';\n} else {\n  echo 'Table already exists';\n}\n\""},
{n:3,title:"Create an EventSubscriber to track page views",body:"Create a new file: src/EventSubscriber/PageViewSubscriber.php. It listens to the kernel response event, which fires on every page request after the response is built.",code:"<?php\n// web/modules/custom/my_first_module/src/EventSubscriber/PageViewSubscriber.php\nnamespace Drupal\\my_first_module\\EventSubscriber;\n\nuse Drupal\\Core\\Database\\Connection;\nuse Symfony\\Component\\EventDispatcher\\EventSubscriberInterface;\nuse Symfony\\Component\\HttpKernel\\Event\\ResponseEvent;\nuse Symfony\\Component\\HttpKernel\\KernelEvents;\n\nclass PageViewSubscriber implements EventSubscriberInterface {\n\n  public function __construct(protected Connection $database) {}\n\n  public static function getSubscribedEvents(): array {\n    return [KernelEvents::RESPONSE => 'onResponse'];\n  }\n\n  public function onResponse(ResponseEvent $event): void {\n    if (!$event->isMainRequest()) {\n      return; // Skip sub-requests (AJAX, etc.)\n    }\n    $path = $event->getRequest()->getPathInfo();\n    $this->database->merge('my_module_page_views')\n      ->key('path', $path)\n      ->fields(['path' => $path, 'views' => 1, 'last_viewed' => time()])\n      ->expression('views', 'views + :inc', [':inc' => 1])\n      ->expression('last_viewed', ':ts', [':ts' => time()])\n      ->execute();\n  }\n\n}"},
{n:4,title:"Register the subscriber in services.yml",body:"Add the event subscriber service to your module's services.yml.",code:"# In my_first_module.services.yml — add:\n  my_first_module.page_view_subscriber:\n    class: Drupal\\my_first_module\\EventSubscriber\\PageViewSubscriber\n    arguments: ['@database']\n    tags:\n      - { name: event_subscriber }"},
{n:5,title:"Rebuild and browse some pages",code:"ddev drush cr\n# Browse 5–10 different pages on your site (homepage, articles, etc.)"},
{n:6,title:"Query the analytics data",body:"Check what was tracked. You should see your visited paths sorted by view count.",code:"ddev drush php:eval \"\n\\$rows = \\Drupal::database()->select('my_module_page_views', 'p')\n  ->fields('p')\n  ->orderBy('views', 'DESC')\n  ->range(0, 5)\n  ->execute()\n  ->fetchAll();\nforeach (\\$rows as \\$r) {\n  echo \\$r->path . ' — ' . (int) \\$r->views . ' views' . PHP_EOL;\n}\n\"\n# Expected: your top 5 viewed paths with counts"},
],aiCheck:{prompt:"Paste your hook_schema() and the output of the database query command. Are views being tracked? What are the top 5 most-viewed paths?",checkGoal:"Verify correct schema definition, merge query usage, and that page views are being tracked. Check that hook_schema follows Drupal's schema API format correctly. Give feedback on Database API patterns and when to use merge vs. insert/update."}}},
{day:"Day 10",title:"PHPUnit Testing in Drupal",goal:"Write automated tests for your custom module code.",
reading:[
{title:"Test types in Drupal",body:"<strong>Unit tests</strong>: test pure PHP logic with no Drupal bootstrap — fastest. <strong>Kernel tests</strong>: test with Drupal's service container but no HTTP — good for services and entity operations. <strong>Functional tests</strong>: full browser simulation — slowest but most comprehensive.",link:"https://www.drupal.org/docs/automated-testing"},
{title:"Where tests live",body:"Tests go in modules/custom/my_module/tests/src/Unit/, /Kernel/, or /Functional/. File names end in Test.php and extend the appropriate base class.",link:null},
{title:"Why testing matters for Drupal",body:"Drupal has a large public API surface. Tests protect you from breaking changes on core/contrib updates and document expected behavior. The Acquia Backend Specialist exam covers testing concepts.",link:null},
],
activity:{type:"hands_on",title:"Write a unit test for your NodeHelper service",intro:"Write and run a PHPUnit unit test for the getLatestNodes method.",steps:[
{n:1,title:"Create the test directory structure",body:"Drupal unit tests live in tests/src/Unit/. The namespace must be Drupal\\Tests\\{module_name}\\Unit. Create the directory first.",code:"mkdir -p web/modules/custom/my_first_module/tests/src/Unit"},
{n:2,title:"Write the NodeHelperTest class",body:"Unit tests use mocks to avoid needing a real database or Drupal bootstrap. createMock() creates a fake version of a class that you control. willReturn() sets what the fake method returns. The key insight: you're testing YOUR code logic, not Drupal's entity system — so you mock all dependencies.",code:"<?php\n// web/modules/custom/my_first_module/tests/src/Unit/NodeHelperTest.php\nnamespace Drupal\\Tests\\my_first_module\\Unit;\n\nuse Drupal\\Tests\\UnitTestCase;\nuse Drupal\\my_first_module\\NodeHelper;\nuse Drupal\\Core\\Entity\\EntityTypeManagerInterface;\nuse Drupal\\Core\\Entity\\EntityStorageInterface;\n\nclass NodeHelperTest extends UnitTestCase {\n\n  public function testGetLatestNodesReturnsCorrectCount(): void {\n    // Create a mock query object that returns 3 IDs\n    $query = new class {\n      public function accessCheck(bool $b): static { return $this; }\n      public function condition(string $f, mixed $v): static { return $this; }\n      public function sort(string $f, string $d): static { return $this; }\n      public function range(int $s, int $l): static { return $this; }\n      public function execute(): array { return [1, 2, 3]; }\n    };\n\n    // Mock the storage to return the query and then 3 fake entities\n    $storage = $this->createMock(EntityStorageInterface::class);\n    $storage->method('getQuery')->willReturn($query);\n    $storage->method('loadMultiple')\n      ->with([1, 2, 3])\n      ->willReturn(['entity1', 'entity2', 'entity3']);\n\n    // Mock the EntityTypeManager to return our mock storage\n    $etm = $this->createMock(EntityTypeManagerInterface::class);\n    $etm->method('getStorage')\n      ->with('node')\n      ->willReturn($storage);\n\n    $helper = new NodeHelper($etm);\n    $result = $helper->getLatestNodes(3);\n\n    $this->assertCount(3, $result);\n    $this->assertSame(['entity1', 'entity2', 'entity3'], $result);\n  }\n\n  public function testGetLatestNodesDefaultCountIsFive(): void {\n    $query = new class {\n      public int $rangeLimit = 0;\n      public function accessCheck(bool $b): static { return $this; }\n      public function condition(string $f, mixed $v): static { return $this; }\n      public function sort(string $f, string $d): static { return $this; }\n      public function range(int $s, int $l): static { $this->rangeLimit = $l; return $this; }\n      public function execute(): array { return []; }\n    };\n\n    $storage = $this->createMock(EntityStorageInterface::class);\n    $storage->method('getQuery')->willReturn($query);\n    $storage->method('loadMultiple')->willReturn([]);\n\n    $etm = $this->createMock(EntityTypeManagerInterface::class);\n    $etm->method('getStorage')->willReturn($storage);\n\n    $helper = new NodeHelper($etm);\n    $helper->getLatestNodes(); // no argument — should use default of 5\n\n    $this->assertSame(5, $query->rangeLimit);\n  }\n\n}"},
{n:3,title:"Run the unit tests",body:"PHPUnit is in vendor/bin/. Run from the project root. --no-coverage skips code coverage generation (which requires Xdebug).",code:"# From your project root (not inside web/):\nddev exec vendor/bin/phpunit web/modules/custom/my_first_module/tests/src/Unit/ --no-coverage\n\n# Expected output:\n# OK (2 tests, 3 assertions)"},
{n:4,title:"Debug a failing test",body:"If the test fails, read the error carefully. Common mistakes: (1) Namespace doesn't match the file path. (2) Mock method names are wrong. (3) The query mock doesn't return the right type. Fix the error and re-run."},
{n:5,title:"Add a test for edge case: empty result",body:"Add this third test method to NodeHelperTest to verify the empty case.",code:"public function testGetLatestNodesReturnsEmptyArrayWhenNoneFound(): void {\n  $query = new class {\n    public function accessCheck(bool $b): static { return $this; }\n    public function condition(string $f, mixed $v): static { return $this; }\n    public function sort(string $f, string $d): static { return $this; }\n    public function range(int $s, int $l): static { return $this; }\n    public function execute(): array { return []; } // No IDs found\n  };\n  $storage = $this->createMock(EntityStorageInterface::class);\n  $storage->method('getQuery')->willReturn($query);\n  $storage->method('loadMultiple')->willReturn([]);\n  $etm = $this->createMock(EntityTypeManagerInterface::class);\n  $etm->method('getStorage')->willReturn($storage);\n  $helper = new NodeHelper($etm);\n  $this->assertSame([], $helper->getLatestNodes());\n}"},
],aiCheck:{prompt:"Paste the PHPUnit output from running your test. Did it pass? If not, what error did you get?",checkGoal:"Verify the student can write and run a Drupal unit test. Check test structure: extends UnitTestCase, uses mocks correctly, has meaningful assertions. If it failed, diagnose the error. Give feedback on unit testing best practices in Drupal."}}},
{day:"Day 11",title:"Coding Standards & Code Quality",goal:"Write Drupal code that meets community coding standards.",
reading:[
{title:"Drupal coding standards",body:"Drupal has strict coding standards — PSR-2 base plus Drupal-specific rules. These cover: docblock formatting, hook documentation, use of t() for translatable strings, @deprecated notices, and more.",link:"https://www.drupal.org/docs/develop/standards"},
{title:"PHP CodeSniffer",body:"phpcs with the Drupal and DrupalPractice standards detects coding violations automatically. Run it before every commit.",link:null},
{title:"Why this matters for production",body:"Modules submitted to drupal.org require coding standards compliance. Acquia exams test knowledge of standards. Agency work often requires passing phpcs in CI.",link:null},
],
activity:{type:"hands_on",title:"Run coding standards on your module",intro:"Install phpcs with Drupal standards and fix all violations.",steps:[
{n:1,title:"Install PHP CodeSniffer with the Drupal standard",body:"drupal/coder provides the Drupal and DrupalPractice phpcs standards. squizlabs/php_codesniffer is the underlying tool. Install as dev dependencies — they're only needed in development, not on production.",code:"ddev composer require --dev drupal/coder squizlabs/php_codesniffer"},
{n:2,title:"Register the Drupal coding standard with phpcs",body:"phpcs needs to know where the Drupal ruleset files are. This config command registers the path permanently.",code:"ddev exec vendor/bin/phpcs --config-set installed_paths ../../drupal/coder/coder_sniffer\n# Verify registration:\nddev exec vendor/bin/phpcs -i\n# Expected: The installed coding standards are: ... Drupal, DrupalPractice ..."},
{n:3,title:"Run phpcs on your module — first scan",body:"This shows all violations before any fixes. Read through the list carefully — understanding each violation is the goal.",code:"ddev exec vendor/bin/phpcs --standard=Drupal --extensions=php,module,inc,install,yml \\\n  web/modules/custom/my_first_module/\n# Note how many ERRORs and WARNINGs you have — write it down"},
{n:4,title:"Run phpcbf to auto-fix whitespace and formatting issues",body:"phpcbf (PHP Code Beautifier and Fixer) auto-corrects violations that can be fixed without human judgment — mostly whitespace, blank lines, and bracket placement.",code:"ddev exec vendor/bin/phpcbf --standard=Drupal \\\n  web/modules/custom/my_first_module/\n# It will report how many fixes it made"},
{n:5,title:"Re-run phpcs to see remaining violations",body:"After phpcbf, check what's left. These will be violations phpcbf couldn't auto-fix — usually missing docblocks, wrong t() usage, or code logic issues you must fix manually.",code:"ddev exec vendor/bin/phpcs --standard=Drupal --extensions=php,module,inc,install,yml \\\n  web/modules/custom/my_first_module/\n# Compare to your earlier count — how many were fixed automatically?"},
{n:6,title:"Manually fix the remaining violations",body:"Common manual fixes needed: (1) Missing docblock on a function — add /** * Description. */. (2) Use of \\Drupal:: in a class that could use injection — for now add @todo inject properly. (3) Missing trailing newline at end of file — add a blank line. Fix them one by one and re-run phpcs after each fix."},
{n:7,title:"Run DrupalPractice standard too",body:"DrupalPractice catches higher-level issues like calling \\Drupal:: inside a class that should use injection.",code:"ddev exec vendor/bin/phpcs --standard=DrupalPractice --extensions=php,module \\\n  web/modules/custom/my_first_module/src/\n# This catches patterns phpcs --standard=Drupal misses"},
],aiCheck:{prompt:"Paste the final phpcs output after running phpcbf. How many errors and warnings remain? List the top 3 types of violations you found.",checkGoal:"Verify the student ran phpcs and phpcbf. Evaluate their understanding of the violations found — key issues might be missing docblocks, incorrect t() usage, or spacing issues. Give feedback on coding standards and which violations are most important to fix."}}},
{day:"Day 12",title:"Phase 3 Retrospective",goal:"Consolidate custom module development skills and prepare for theming.",
reading:[
{title:"Backend Specialist readiness",body:"You now have significant overlap with the Acquia Certified Back End Specialist exam: routing, Form API, Entity API, plugin system, Database API, Queue/Batch API, and testing.",link:null},
],
activity:{type:"ai_open",prompt:"Phase 3 final — answer these two in depth: (1) You're building a module that needs to: (a) expose a new admin page listing all Subscriber entities, (b) allow admins to approve or reject subscribers, (c) send an email notification asynchronously when approved. Describe the complete architecture — every file you'd create, every Drupal API you'd use, and why. (2) A junior developer on your team wrote this code in a hook: $result = db_query('SELECT * FROM node WHERE status = 1'); — what's wrong with it and how would you fix it?",checkGoal:"Evaluate Phase 3 module development mastery. (1) should include: routing.yml, Controller, Views or custom listing, hook or event subscriber for approval logic, Queue API for async email. (2) db_query is deprecated, use Entity API or database abstraction — db_query bypasses access control, doesn't use placeholders safely. Score 0-10 with comprehensive Phase 3 feedback."}},
]},
]},
{id:4,label:"Phase 4",name:"Theming & Frontend",color:"#3b9eff",bg:"#0d1e33",weeks:[
{label:"Week 1",name:"Twig & template system",days:[
{day:"Day 1",title:"Twig Syntax Essentials",goal:"Get comfortable with Twig before diving into Drupal-specific templates.",
reading:[
{title:"Twig's three delimiters",body:"<strong>{{ variable }}</strong> — output a value (auto-escaped). <strong>{% tag %}</strong> — control flow: if/else, for loops, set, block. <strong>{# comment #}</strong> — not rendered.",link:"https://twig.symfony.com/doc/3.x/"},
{title:"Drupal-specific Twig functions",body:"<strong>{{ content }}</strong> — render all fields. <strong>{{ content.field_name }}</strong> — render one field. <strong>{{ url('route.name') }}</strong> — generate URL. <strong>{{ attach_library('theme/library') }}</strong> — attach assets.",link:null},
{title:"Twig filters",body:"<strong>|t</strong> — translate. <strong>|raw</strong> — unescaped HTML (use carefully). <strong>|default('fallback')</strong> — fallback if null/empty. <strong>|date('Y-m-d')</strong> — format date. <strong>|clean_class</strong> — sanitize for CSS class use.",link:null},
],
activity:{type:"quiz",questions:[
{q:"In a Drupal Twig template, how do you output the title field of a node safely?",options:["<?php echo $node->title; ?>","{{ node.title }}","{{ content.title }}","{% echo title %}"],answer:2,explanation:"{{ content.title }} renders the title field through Drupal's render system (caching, theming, escaping). Use content.field_name for most field rendering."},
{q:"You want to output raw HTML stored in a text field. Which filter should you use and when is it safe?",options:["|html — always safe","|raw — safe only when content has already been sanitized by Drupal","|escape — converts HTML to plain text","|safe — Drupal's built-in safety filter"],answer:1,explanation:"|raw bypasses Twig's auto-escaping. Only use it for content already sanitized by Drupal (like body field output from content.body — Drupal filters it before passing to Twig). Never use |raw on raw user input."},
{q:"How do you check if a field has a value before rendering it in Twig?",options:["{% if content.field_image is defined %}","{% if content.field_image %}","{% if node.field_image.value %}","{% if field_image %}"],answer:1,explanation:"{% if content.field_image %} is the Drupal-idiomatic way to check if a rendered field has content. It evaluates to false if the field is empty. Note: this checks the rendered output, not the raw field value."},
]}},
{day:"Day 2",title:"Drupal Template Hierarchy & Overrides",goal:"Understand how Drupal's theme system discovers and uses templates.",
reading:[
{title:"Template discovery order",body:"Drupal looks for templates in this order: theme → base theme → module. The most specific template wins. Your theme can override any module template by placing an appropriately named file in its /templates directory.",link:"https://www.drupal.org/docs/theming-drupal/working-with-twig-templates"},
{title:"Template naming conventions",body:"node.html.twig overrides all nodes. node--article.html.twig overrides only articles. node--article--teaser.html.twig overrides articles in teaser view mode. More specific = higher priority.",link:null},
{title:"Template suggestions",body:"Drupal generates a list of candidate template names for every render. Enable Twig debug mode to see them as HTML comments — this is the fastest way to know which template file to create.",link:null},
],
activity:{type:"hands_on",title:"Create custom node templates",intro:"Enable Twig debug and override article templates.",steps:[
{n:1,title:"Create a custom theme if you don't have one",body:"You need a custom theme to add templates. Create a minimal one based on Olivero (the default core theme).",code:"mkdir -p web/themes/custom/mytheme/templates\n# Create mytheme.info.yml:\ncat > web/themes/custom/mytheme/mytheme.info.yml << 'EOF'\nname: My Theme\ntype: theme\ndescription: Custom theme for learning\ncore_version_requirement: ^10 || ^11\nbase theme: olivero\nregions:\n  header: Header\n  content: Content\n  sidebar_first: Sidebar\n  footer: Footer\nEOF\n# Enable the theme:\nddev drush theme:enable mytheme -y\nddev drush config:set system.theme default mytheme -y\nddev drush cr"},
{n:2,title:"Enable Twig debug mode",body:"Twig debug adds HTML comments to your source showing exactly which template file is being used and what alternatives are available. The null render cache ensures every page reload shows fresh templates without having to run drush cr constantly.",code:"# In web/sites/default/settings.local.php (create it if it doesn't exist):\n$settings['twig_debug'] = TRUE;\n$settings['cache']['bins']['render'] = 'cache.backend.null';\n$settings['cache']['bins']['dynamic_page_cache'] = 'cache.backend.null';\nddev drush cr"},
{n:3,title:"View the template suggestions in page source",body:"Visit any Article node page (e.g., /node/1). Right-click the page → View Page Source. Search for 'FILE NAME SUGGESTIONS' in the source. You'll see a block like: <!-- FILE NAME SUGGESTIONS:\n   * node--article--full.html.twig\n   * node--article.html.twig  ← this is the one to create\n   * node--1.html.twig\n   * node.html.twig\n-->\nThe top suggestion is the most specific. The active template is marked with an 'x'."},
{n:4,title:"Copy the base template and rename it",body:"Copy the base node template from the Olivero theme (or core's base theme) and place it in your theme's templates directory with the correct name.",code:"# Find where the base node template is:\nfind web -name 'node.html.twig' | grep -v custom\n# Copy and rename for article override:\ncp web/core/themes/olivero/templates/content/node.html.twig \\\n   web/themes/custom/mytheme/templates/node--article.html.twig"},
{n:5,title:"Add a reading time section to the template",body:"Open the copied template and find where the body content renders. Add a reading time badge before the body field.",code:"{# In node--article.html.twig, after the title section: #}\n{% if content.field_reading_time %}\n  <div class=\"article-reading-time\">\n    <span class=\"reading-time-label\">{{ content.field_reading_time }}</span> min read\n  </div>\n{% endif %}"},
{n:6,title:"Confirm the template is active",body:"Refresh an article page. In the page source, the 'x' next to FILE NAME SUGGESTIONS should now be on node--article.html.twig. The reading time section should appear on the page.",code:"ddev drush cr\n# Refresh the page — look for the 'x' marker in the HTML comments"},
],aiCheck:{prompt:"Paste the THEME HOOK and FILE NAME SUGGESTIONS comment you found in the HTML source for an Article page. Also paste the key customization you made to your node--article.html.twig template.",checkGoal:"Verify the student has enabled Twig debug, found template suggestions correctly, and created a working template override. Check that they understand the template naming hierarchy. Give feedback on Twig debugging workflow."}}},
{day:"Day 3",title:"template_preprocess & Custom Variables",goal:"Pass custom PHP-computed variables into Twig templates using preprocess functions.",
reading:[
{title:"What template_preprocess does",body:"Preprocess functions (hook_preprocess_HOOK) run before a template renders and can add/modify variables available in the template. They're defined in the .theme file or a module's .module file.",link:null},
{title:"The function signature",body:"function mytheme_preprocess_node(&$variables) — the $variables array contains everything available to the template, including $variables['node'] (the entity) and $variables['content'] (rendered fields).",link:null},
{title:"Keep preprocess thin",body:"Preprocess should prepare display variables — format data, compute labels, check conditions. Never do business logic or database queries in preprocess. Use a custom service for anything complex.",link:null},
],
activity:{type:"hands_on",title:"Add custom variables to a template",intro:"Use hook_preprocess_node to add a reading time label to article templates.",steps:[
{n:1,title:"Create the .theme file",body:"The .theme file is where your theme's PHP hooks live. Create it if it doesn't exist. Function names follow the pattern {theme_name}_preprocess_{hook}.",code:"touch web/themes/custom/mytheme/mytheme.theme\n# Open the file and add the opening PHP tag:\necho '<?php' > web/themes/custom/mytheme/mytheme.theme"},
{n:2,title:"Add the preprocess function",body:"hook_preprocess_node() runs before any node template renders. The $variables array contains all template variables. You can add new ones here. Keep preprocess functions thin — only formatting and display preparation, no database queries.",code:"<?php\n// web/themes/custom/mytheme/mytheme.theme\n\n/**\n * Implements hook_preprocess_node().\n */\nfunction mytheme_preprocess_node(array &$variables): void {\n  $node = $variables['node'];\n\n  if ($node->bundle() !== 'article') {\n    return;\n  }\n\n  // Build a human-readable reading time label.\n  $minutes = (int) ($node->get('field_reading_time')->value ?? 0);\n  if ($minutes > 0) {\n    $variables['reading_time_label'] = $minutes === 1\n      ? '1 minute read'\n      : $minutes . ' minutes read';\n  }\n  else {\n    $variables['reading_time_label'] = NULL;\n  }\n\n  // Add a CSS class based on whether the article is featured.\n  $featured = (bool) ($node->get('field_featured')->value ?? FALSE);\n  $variables['attributes']['class'][] = $featured ? 'article--featured' : 'article--standard';\n}"},
{n:3,title:"Clear caches",body:"Preprocess functions are in .theme files which are cached. Always clear after modifying .theme files.",code:"ddev drush cr"},
{n:4,title:"Use the new variable in the template",body:"Open your node--article.html.twig and add the reading time display. Use the variable you set in the preprocess function. Always check it's not null before rendering.",code:"{# In node--article.html.twig — add after the article header: #}\n{% if reading_time_label %}\n  <div class=\"article-meta\">\n    <span class=\"reading-time\">{{ reading_time_label }}</span>\n  </div>\n{% endif %}"},
{n:5,title:"Test with articles of different reading times",body:"View an Article with a calculated reading time (one with a long body). The label should say '3 minutes read' (or similar). View a short article — it might say '1 minute read'. If field_reading_time is 0, no label should appear."},
{n:6,title:"Add another preprocess variable for the author",body:"Practice adding a second variable — the author's display name.",code:"// Add to the preprocess function, inside the if block:\n$uid = $node->getOwnerId();\n\\$user = \\Drupal::entityTypeManager()->getStorage('user')->load($uid);\n$variables['author_name'] = $user ? $user->getDisplayName() : '';\n\n// Then in your template:\n// {% if author_name %}\n//   <span class=\"author\">By {{ author_name }}</span>\n// {% endif %}"},
],aiCheck:{prompt:"Paste your preprocess function and the Twig snippet where you use reading_time_label. Does it appear on the article page?",checkGoal:"Verify correct preprocess function naming (theme_preprocess_hook), $variables manipulation, and correct Twig variable usage. Check they're not doing business logic in preprocess. Give feedback on the preprocess pattern."}}},
{day:"Day 4",title:"Libraries — CSS, JS & drupalSettings",goal:"Attach CSS and JavaScript to Drupal pages correctly using the Libraries API.",
reading:[
{title:"*.libraries.yml",body:"Drupal uses a libraries system to declare and attach CSS/JS assets. Define libraries in your theme's or module's {name}.libraries.yml file. Assets are attached explicitly — Drupal never auto-includes all CSS/JS.",link:"https://www.drupal.org/docs/theming-drupal/adding-stylesheets-css-and-javascript-js-to-a-drupal-theme"},
{title:"Attaching libraries",body:"In a template: {{ attach_library('mytheme/my-library') }}. In a preprocess: $variables['#attached']['library'][] = 'mytheme/my-library'. In a render array: '#attached' => ['library' => ['mytheme/my-library']].",link:null},
{title:"drupalSettings — passing PHP to JS",body:"To pass PHP values to JavaScript: in preprocess add $variables['#attached']['drupalSettings']['myModule']['setting'] = $value. In JS access via drupalSettings.myModule.setting.",link:null},
{title:"Drupal.behaviors",body:"Always wrap JS in Drupal.behaviors, not $(document).ready(). Behaviors re-run on AJAX-loaded content, making your JS work with Views AJAX, CKEditor, etc.",link:null},
],
activity:{type:"hands_on",title:"Create a theme library with CSS and JS",intro:"Define a library, attach it, and pass a value from PHP to JavaScript.",steps:[
{n:1,title:"Create the CSS and JS asset directories",code:"mkdir -p web/themes/custom/mytheme/css\nmkdir -p web/themes/custom/mytheme/js"},
{n:2,title:"Define the library in mytheme.libraries.yml",body:"Libraries are declared in {theme_name}.libraries.yml. The CSS key under 'theme' is the SMACSS category (base, layout, component, state, theme) — this controls load order. 'theme' is for general theming styles.",code:"# web/themes/custom/mytheme/mytheme.libraries.yml\narticle-enhancements:\n  version: 1.0\n  css:\n    theme:\n      css/article.css: {}\n  js:\n    js/article.js: {}\n  dependencies:\n    - core/drupal\n    - core/drupalSettings"},
{n:3,title:"Create the CSS file",body:"Use BEM naming (block__element--modifier). The .node--type-article class is automatically added by Drupal to the node wrapper. The .reading-time class matches the span you added in the template.",code:"/* web/themes/custom/mytheme/css/article.css */\n.article-meta {\n  margin: 0.5rem 0 1rem;\n  font-size: 0.875rem;\n  color: #666;\n}\n\n.reading-time {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.25rem;\n  font-style: italic;\n}\n\n.article--featured {\n  border-left: 4px solid #0078d4;\n  padding-left: 1rem;\n}"},
{n:4,title:"Create the JS file using Drupal.behaviors",body:"Always use Drupal.behaviors — NOT $(document).ready() or DOMContentLoaded. Behaviors re-fire on AJAX-loaded content (Views AJAX pager, BigPipe, etc.). The context parameter is the DOM element being processed — search within it, not document.",code:"// web/themes/custom/mytheme/js/article.js\n(function (Drupal, drupalSettings) {\n  'use strict';\n\n  Drupal.behaviors.articleEnhancements = {\n    attach: function (context) {\n      // context is the DOM context being processed\n      const articles = context.querySelectorAll('.node--type-article:not(.processed)');\n      articles.forEach(function (article) {\n        article.classList.add('processed');\n\n        // Add a subtle underline to article titles\n        const title = article.querySelector('h1, h2');\n        if (title) {\n          title.style.borderBottom = '2px solid #0078d4';\n          title.style.paddingBottom = '0.25rem';\n        }\n      });\n    }\n  };\n\n})(Drupal, drupalSettings);"},
{n:5,title:"Attach the library in the article template",body:"attach_library() is the Twig function to load a library. Place it at the top of the template. The format is 'theme_name/library_name'.",code:"{# In node--article.html.twig — add at the very top: #}\n{{ attach_library('mytheme/article-enhancements') }}"},
{n:6,title:"Pass a PHP value to JavaScript via drupalSettings",body:"To pass a value from PHP to JS, add it to $variables['#attached']['drupalSettings'] in your preprocess function. Then access it in JS via drupalSettings.myModule.myKey.",code:"// In mytheme_preprocess_node(), add inside the article check:\n$variables['#attached']['drupalSettings']['mytheme']['articleMaxWords'] = 200;\n\n// In article.js, use it:\n// var wordsPerMin = drupalSettings.mytheme.articleMaxWords;"},
{n:7,title:"Rebuild caches and verify",code:"ddev drush cr\n# Visit an article page — check browser DevTools:\n# Network tab: article.css and article.js should load\n# Elements tab: .article--featured class should be on featured articles"},
],aiCheck:{prompt:"Paste your mytheme.libraries.yml and confirm: (1) Does the reading-time CSS styling work? (2) Does the JS border appear on article titles?",checkGoal:"Verify correct libraries.yml structure (version, css/js paths, SMACSS category for CSS), correct attach_library usage in template, and working Drupal.behaviors pattern in JS. Give feedback on library best practices."}}},
{day:"Day 5",title:"Single Directory Components (SDC)",goal:"Build modern Drupal components using the SDC system introduced in Drupal 10.3.",
reading:[
{title:"What SDC is",body:"Single Directory Components (SDC) groups a component's template, CSS, JS, and metadata into a single folder. Available in Drupal 10.3+. This is the modern way to build reusable UI components in Drupal.",link:"https://www.drupal.org/docs/develop/theming-drupal/using-single-directory-components"},
{title:"Component structure",body:"Each component lives in a folder: my-card/my-card.component.yml (metadata/props), my-card/my-card.twig (template), my-card/my-card.css (styles), my-card/my-card.js (behavior). The folder name is the component ID.",link:null},
{title:"Props and slots",body:"Props are typed inputs declared in the component.yml schema. Slots are arbitrary Twig content blocks passed into the component. Props = data; slots = markup. This is similar to React props/children.",link:null},
],
activity:{type:"hands_on",title:"Build a Card SDC",intro:"Create a reusable Card component using SDC, then use it in a node template.",steps:[
{n:1,title:"Enable the Single Directory Components module",body:"SDC is a core module from Drupal 10.3. Enable it if not already active.",code:"ddev drush pm:enable sdc -y && ddev drush cr"},
{n:2,title:"Create the component folder",body:"Each SDC component lives in its own subfolder under components/. The folder name becomes the component ID.",code:"mkdir -p web/themes/custom/mytheme/components/article-card"},
{n:3,title:"Create article-card.component.yml",body:"The component.yml file declares the component's props (typed inputs). The JSON Schema format defines what data each prop accepts. Props are what the calling template passes in.",code:"# web/themes/custom/mytheme/components/article-card/article-card.component.yml\nname: Article Card\ndescription: A card for displaying article teasers in listings.\nprops:\n  type: object\n  properties:\n    title:\n      type: string\n      title: Article title\n    url:\n      type: string\n      title: URL\n      description: The path to the full article.\n    reading_time:\n      type: integer\n      title: Reading time\n      description: Estimated minutes to read.\n    is_featured:\n      type: boolean\n      title: Featured\n      default: false\n  required:\n    - title\n    - url"},
{n:4,title:"Create article-card.twig",body:"The template can use any declared prop by name. Slots are available for arbitrary markup passed from the caller — {{ content }} is the default slot name.",code:"{# web/themes/custom/mytheme/components/article-card/article-card.twig #}\n<article class=\"article-card{% if is_featured %} article-card--featured{% endif %}\">\n  <h3 class=\"article-card__title\">\n    <a class=\"article-card__link\" href=\"{{ url }}\">\n      {{- title -}}\n    </a>\n  </h3>\n  {% if reading_time %}\n    <span class=\"article-card__reading-time\">{{ reading_time }} min read</span>\n  {% endif %}\n  {% block content %}\n    {{ content }}\n  {% endblock %}\n</article>"},
{n:5,title:"Create article-card.css",body:"Component-scoped CSS. Drupal automatically loads this file when the component renders — no libraries.yml needed.",code:"/* web/themes/custom/mytheme/components/article-card/article-card.css */\n.article-card {\n  border: 1px solid #e0e0e0;\n  border-radius: 4px;\n  padding: 1rem;\n  margin-bottom: 1rem;\n  transition: box-shadow 0.2s;\n}\n.article-card:hover { box-shadow: 0 2px 8px rgba(0,0,0,0.1); }\n.article-card--featured { border-left: 3px solid #0078d4; }\n.article-card__title { margin: 0 0 0.5rem; }\n.article-card__link { color: inherit; text-decoration: none; }\n.article-card__link:hover { text-decoration: underline; }\n.article-card__reading-time { font-size: 0.8em; color: #666; }"},
{n:6,title:"Create node--article--teaser.html.twig to use the component",body:"Create a teaser template that uses the SDC component. The include syntax is 'theme_name:component-id'. Pass data from the Twig context as props.",code:"# Copy base teaser template first:\ncp web/core/themes/olivero/templates/content/node.html.twig \\\n   web/themes/custom/mytheme/templates/node--article--teaser.html.twig"},
{n:7,title:"Replace teaser template content with SDC include",body:"Edit your new teaser template to use the article-card component.",code:"{# node--article--teaser.html.twig #}\n{% include 'mytheme:article-card' with {\n  title: label,\n  url: url,\n  reading_time: content.field_reading_time|render|striptags|trim,\n  is_featured: node.field_featured.value|default(false)\n} only %}"},
{n:8,title:"Rebuild caches and test",body:"Visit your /articles or /blog Views listing page — articles should now render using your card component.",code:"ddev drush cr\n# Visit /articles (your Views listing)\n# Each article teaser should use the card layout"},
],aiCheck:{prompt:"Paste your article-card.component.yml and article-card.twig. Does the component render correctly in teaser view mode?",checkGoal:"Verify correct SDC structure: component.yml with props schema, Twig template using prop names correctly, correct include syntax with 'theme:component-name'. Give feedback on component design and SDC best practices for Drupal 10.3+."}}},
{day:"Day 6",title:"Accessibility & Performance",goal:"Build themes that are fast and accessible — non-negotiable for professional work.",
reading:[
{title:"Accessibility in Drupal themes",body:"Drupal core is accessible by default. Custom themes can break this. Key areas: heading hierarchy (one H1 per page), alt text on images, sufficient color contrast, keyboard navigation, skip links, ARIA attributes.",link:"https://www.drupal.org/docs/accessibility"},
{title:"Performance: asset aggregation",body:"Enable CSS/JS aggregation in production (Admin → Config → Development → Performance). Drupal merges and minifies assets. Don't add inline styles or scripts — always use the Libraries API.",link:null},
{title:"Lazy loading images",body:"Use the loading='lazy' attribute on images not in the viewport. Drupal's responsive images module can add this automatically. Significant performance win for image-heavy sites.",link:null},
],
activity:{type:"quiz",questions:[
{q:"A Drupal theme has these headings: H1 (site name), H2 (page title), H3 (article title), H4 (sidebar heading). What accessibility problem exists?",options:["No problem — multiple heading levels are fine","The page should only have one H1 — the page title should be H1, not H2","H4 should not be used in sidebars","There should be no H1 at all"],answer:1,explanation:"Each page should have exactly one H1, which should be the main page content title (not the site name). The site name should use a different element or ARIA role. Screen readers use the H1 to identify page content."},
{q:"You add a custom background image via CSS in your theme. How should you handle the alt text?",options:["Add alt='background image' to the img tag","CSS background images don't support alt text — use them only for decorative images. Content images must use the img tag with meaningful alt text","Add an aria-label to the element","Background images automatically get alt text from the file name"],answer:1,explanation:"CSS background-image is for decorative visuals only — they're invisible to screen readers. Any image that conveys information must be an <img> tag with descriptive alt text. This is WCAG 2.1 Success Criterion 1.1.1."},
]}},
{day:"Day 7",title:"Phase 4 Retrospective",goal:"Consolidate theming skills and prepare for the advanced decoupled phase.",
reading:[
{title:"Front-end Specialist readiness",body:"You now have strong coverage of the Acquia Certified Front-end Specialist exam: Twig templates, template hierarchy, preprocess functions, Libraries API, SDC, and accessibility. You'll need 1-2 real themed projects to fill in exam scenario practice.",link:null},
],
activity:{type:"ai_open",prompt:"Phase 4 final — answer these two: (1) A designer gives you a Figma file with a complex article page design: hero image full-width, article content in a centered column, a 3-column 'related articles' section at the bottom, and a sticky table of contents sidebar. Walk through your entire implementation plan — which Drupal systems and template files you'd create, how you'd structure your CSS, and how you'd use SDC. (2) Drupal's performance tab warns that CSS/JS aggregation is disabled. What does enabling it do, and are there any cases where a developer would want to keep it disabled?",checkGoal:"Evaluate Phase 4 theming mastery. (1) should include: node--article.html.twig, SDC for related articles card, preprocess for ToC generation, Libraries with CSS custom properties for layout, maybe layout_builder sections; (2) aggregation merges/minifies assets for prod — disabled in dev for easier debugging with source maps. Score 0-10 with detailed Phase 4 feedback."}},
]},
]},
{id:5,label:"Phase 5",name:"Decoupled & Advanced",color:"#6bc44a",bg:"#14200d",weeks:[
{label:"Week 1",name:"JSON:API, REST & GraphQL",days:[
{day:"Day 1",title:"JSON:API Fundamentals",goal:"Learn to expose Drupal content via JSON:API for decoupled frontends.",
reading:[
{title:"What JSON:API provides",body:"Drupal's JSON:API module (core since Drupal 8.7) exposes all content entities as a REST API following the JSON:API spec. Enable the module — no custom code needed to start consuming content.",link:"https://www.drupal.org/docs/core-modules-and-themes/core-modules/jsonapi-module"},
{title:"URL structure",body:"<strong>/jsonapi/node/article</strong> — all articles. <strong>/jsonapi/node/article/{uuid}</strong> — specific article. <strong>/jsonapi/taxonomy_term/tags</strong> — all tags. Pattern: /jsonapi/{entity_type}/{bundle}.",link:null},
{title:"Query parameters",body:"<strong>?filter[status]=1</strong> — published only. <strong>?fields[node--article]=title,body</strong> — sparse fieldsets. <strong>?include=field_tags</strong> — include related entities inline. <strong>?sort=-created</strong> — sort newest first.",link:null},
],
activity:{type:"hands_on",title:"Query your Drupal site via JSON:API",intro:"Enable JSON:API and build increasingly complex API queries.",steps:[
{n:1,title:"Enable JSON:API and verify the endpoint",body:"JSON:API is a core module — no Composer install needed. Once enabled, all entity types are immediately available at /jsonapi.",code:"ddev drush pm:enable jsonapi -y && ddev drush cr\n# Verify it works:\ncurl -s https://your-site.ddev.site/jsonapi | python3 -m json.tool | head -20\n# Expected: a JSON object listing all available entity type endpoints"},
{n:2,title:"Basic query — list all articles",body:"The URL pattern is /jsonapi/{entity_type}/{bundle}. Open this in your browser or a REST client like Insomnia. Look at the response structure — notice 'data' is an array of resource objects, each with 'type', 'id' (UUID), 'attributes', and 'relationships'.",code:"# In browser:\n# https://your-site.ddev.site/jsonapi/node/article\n\n# Or with curl:\ncurl -s 'https://your-site.ddev.site/jsonapi/node/article' | python3 -m json.tool | head -40"},
{n:3,title:"Filter to published only with sparse fieldsets",body:"sparse fieldsets (?fields) reduce response size — only return the fields you need. filter[status]=1 filters to published nodes. sort=-created means newest first (- prefix = descending).",code:"curl -s 'https://your-site.ddev.site/jsonapi/node/article?filter[status]=1&fields[node--article]=title,created&sort=-created&page[limit]=3' | python3 -m json.tool"},
{n:4,title:"Include related taxonomy terms inline",body:"?include=field_tags fetches the related tag entities and embeds them in the 'included' array of the response. Without this, the relationship is just a reference (UUID only).",code:"curl -s 'https://your-site.ddev.site/jsonapi/node/article?include=field_tags&filter[status]=1&page[limit]=2&fields[node--article]=title,field_tags&fields[taxonomy_term--tags]=name' | python3 -m json.tool"},
{n:5,title:"Fetch a single article by UUID",body:"Each JSON:API resource has a UUID (not a numeric ID). Get a UUID from any response, then fetch that specific resource.",code:"# First, get a UUID from the listing:\ncurl -s 'https://your-site.ddev.site/jsonapi/node/article?page[limit]=1&fields[node--article]=title' | python3 -m json.tool | grep '\"id\"'\n\n# Then fetch that specific article:\ncurl -s 'https://your-site.ddev.site/jsonapi/node/article/{UUID}' | python3 -m json.tool"},
{n:6,title:"Check the JSON:API entrypoint for all available resources",body:"The entrypoint lists every available resource type — useful for discovering what your Drupal site exposes.",code:"curl -s 'https://your-site.ddev.site/jsonapi' | python3 -m json.tool | grep '\"href\"' | head -20"},
],aiCheck:{prompt:"Paste one article object from your JSON:API response (the first item in the 'data' array). What structure does it have? What's in the 'attributes' vs 'relationships' sections?",checkGoal:"Verify the student has successfully queried JSON:API and understands the response structure: 'type', 'id' (UUID), 'attributes' (field values), 'relationships' (related entities), 'links' (self URL). Give feedback on JSON:API structure and query capabilities."}}},
{day:"Day 2",title:"Authentication & Write Operations",goal:"Secure your JSON:API with OAuth and perform create/update operations.",
reading:[
{title:"Simple OAuth module",body:"Simple OAuth implements OAuth 2.0 for Drupal. It provides access tokens for JSON:API authentication — required for any write operations and for accessing unpublished/restricted content.",link:"https://www.drupal.org/project/simple_oauth"},
{title:"JSON:API write operations",body:"With authentication, JSON:API supports POST (create), PATCH (update), and DELETE. The request body must follow the JSON:API spec format — {'data':{'type':'node--article','attributes':{...}}}",link:null},
{title:"Access control",body:"JSON:API respects all Drupal permissions. Unauthenticated users can only access what the anonymous role can see. Design your permissions intentionally for API access.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You want your Next.js frontend to create Article nodes via JSON:API. What do you need to set up?",options:["Just enable JSON:API — it allows writes by default","Install Simple OAuth, create a Consumer, create a user with node creation permissions, and get an access token","Use Drupal's built-in API key system","Disable CSRF protection in settings.php"],answer:1,explanation:"You need: Simple OAuth module, an OAuth Consumer entity, a dedicated API user with appropriate permissions, and an OAuth access token. The token is sent as a Bearer header with each write request."},
{q:"A JSON:API PATCH request to update an article's title fails with 403 Forbidden even though your user has 'edit any content' permission. What's the most likely cause?",options:["JSON:API doesn't support PATCH","The user's OAuth token has expired or isn't being sent in the Authorization header","You need to rebuild caches","PATCH is only available on node/page content type"],answer:1,explanation:"A 403 on an authenticated write operation usually means the access token is missing or expired. Check: Is 'Authorization: Bearer {token}' in your request headers? Has the token expired (check OAuth expiry)? Is the content-type header set correctly?"},
]}},
{day:"Day 3",title:"Consuming Drupal JSON:API from Next.js",goal:"Build a working Next.js frontend that consumes your Drupal JSON:API.",
reading:[
{title:"next-drupal library",body:"The next-drupal package (by Chapter Three) provides a DrupalClient that simplifies consuming Drupal's JSON:API from Next.js — handling authentication, serialization, and preview mode.",link:"https://next-drupal.org"},
{title:"Data fetching patterns",body:"In Next.js 13+ App Router: use server components and fetch() directly with revalidation. In Pages Router: use getStaticProps/getStaticPaths for static generation from Drupal content.",link:null},
{title:"Your React/Next.js background",body:"This is where your existing React experience becomes a major asset. The complexity is entirely on the Drupal config side — consuming JSON:API is just fetch() with a specific URL structure.",link:null},
],
activity:{type:"hands_on",title:"Build a Next.js page from Drupal content",intro:"Create a simple Next.js app that fetches and displays articles from your DDEV Drupal site.",steps:[
{n:1,title:"Create a new Next.js app",body:"Create the app in a separate directory outside your Drupal project (not inside it). Use TypeScript and the App Router (--app flag).",code:"npx create-next-app@latest drupal-frontend --typescript --app --no-tailwind\ncd drupal-frontend"},
{n:2,title:"Configure CORS on the Drupal side first",body:"Before your Next.js app can fetch from Drupal, you need to allow cross-origin requests. Add CORS config to Drupal's services.yml. This allows localhost:3000 (your Next.js dev server) to make requests.",code:"# In web/sites/default/services.yml (copy from default.services.yml if needed)\n# Find or add the cors.config section:\ncors.config:\n  enabled: true\n  allowedHeaders: ['*']\n  allowedMethods: ['GET']\n  allowedOrigins: ['http://localhost:3000', 'http://localhost:3001']\n  exposedHeaders: false\n  maxAge: false\n  supportsCredentials: false\nddev drush cr"},
{n:3,title:"Create a type for Drupal articles",body:"Create a type file to keep your API responses typed.",code:"// drupal-frontend/types/drupal.ts\nexport interface DrupalArticle {\n  id: string;\n  attributes: {\n    title: string;\n    body: { processed: string } | null;\n    created: string;\n    path: { alias: string } | null;\n  };\n}"},
{n:4,title:"Fetch articles in the homepage server component",body:"In Next.js 13+ App Router, page components are server components by default — they can use async/await directly. fetch() with { next: { revalidate: 60 } } caches the result for 60 seconds.",code:"// drupal-frontend/app/page.tsx\nimport { DrupalArticle } from '../types/drupal';\n\nconst DRUPAL_URL = process.env.DRUPAL_BASE_URL ?? 'https://your-site.ddev.site';\n\nexport default async function HomePage() {\n  const res = await fetch(\n    `${DRUPAL_URL}/jsonapi/node/article?filter[status]=1&fields[node--article]=title,body,created&sort=-created&page[limit]=5`,\n    { next: { revalidate: 60 } }\n  );\n\n  if (!res.ok) {\n    return <main><p>Failed to load articles.</p></main>;\n  }\n\n  const json = await res.json();\n  const articles: DrupalArticle[] = json.data ?? [];\n\n  return (\n    <main style={{ maxWidth: '800px', margin: '0 auto', padding: '2rem' }}>\n      <h1>Articles from Drupal</h1>\n      {articles.map((article) => (\n        <article key={article.id} style={{ borderBottom: '1px solid #eee', marginBottom: '2rem', paddingBottom: '2rem' }}>\n          <h2>{article.attributes.title}</h2>\n          <p style={{ color: '#666', fontSize: '0.875rem' }}>\n            {new Date(article.attributes.created).toLocaleDateString()}\n          </p>\n          {article.attributes.body && (\n            <div dangerouslySetInnerHTML={{ __html: article.attributes.body.processed }} />\n          )}\n        </article>\n      ))}\n    </main>\n  );\n}"},
{n:5,title:"Add the DRUPAL_BASE_URL env variable",code:"# Create .env.local in the drupal-frontend directory:\necho 'DRUPAL_BASE_URL=https://your-site.ddev.site' > .env.local\n# Replace 'your-site' with your actual DDEV project name"},
{n:6,title:"Run the Next.js dev server",code:"npm run dev\n# Visit http://localhost:3000\n# You should see your Drupal articles listed"},
{n:7,title:"Debug any CORS errors",body:"Open browser DevTools → Console. If you see 'CORS policy' errors: (1) Confirm you added localhost:3000 to allowedOrigins in Drupal's services.yml. (2) Confirm you ran ddev drush cr after the change. (3) Confirm the Drupal URL in .env.local exactly matches your DDEV URL."},
],aiCheck:{prompt:"Describe what you see in your Next.js app: (1) Are the Drupal articles showing? (2) Did you run into any CORS errors? How did you fix them? (3) What does the JSON:API response structure look like when you console.log(data)?",checkGoal:"Verify the student has a working decoupled Drupal + Next.js setup. Check they resolved CORS, understand the JSON:API response structure, and can map attributes to React components. Give feedback on the decoupled architecture pattern."}}},
{day:"Day 4",title:"Caching in Drupal",goal:"Understand and implement Drupal's multi-layer caching system.",
reading:[
{title:"Drupal's cache layers",body:"<strong>Page cache</strong>: caches full anonymous pages. <strong>Dynamic page cache</strong>: caches pages with per-user variations (uses cache contexts). <strong>Render cache</strong>: caches individual render array fragments. Each layer is independent.",link:"https://www.drupal.org/docs/drupal-apis/cache-api"},
{title:"Cache tags",body:"Cache tags allow surgical cache invalidation. A node with ID 42 has tag 'node:42'. Any cached content tagged with 'node:42' is invalidated when node 42 is saved. Tags propagate up through render arrays automatically.",link:null},
{title:"Cache contexts",body:"Cache contexts define what makes a cached item unique. 'user' = separate cache per user. 'url' = per URL. 'languages:language_interface' = per language. Use the minimum contexts needed — contexts kill performance.",link:null},
{title:"Cache bins",body:"Different types of data use different cache bins: 'render' (render cache), 'data' (custom data), 'bootstrap' (fast-access config). Use \\Drupal::cache('data') for your custom cached data.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You build a block that shows the current user's name. The first user who loads it sees their name, but then every subsequent user sees the first user's name. What cache concept fixes this?",options:["Increase the cache lifetime","Add cache context 'user' to the block's render array","Add cache tag 'user:current'","Disable caching for the block"],answer:1,explanation:"Cache contexts define uniqueness. Adding '#cache' => ['contexts' => ['user']] to the block's render array tells Drupal to cache a separate version per user. Without it, the first cached version is served to everyone."},
{q:"You update a node's title but the change doesn't appear on the homepage for 10 minutes. What's the correct Drupal solution?",options:["Set cache lifetime to 0 for all pages","Make sure the homepage render array includes the node's cache tag — Drupal will auto-invalidate when the node is saved","Manually clear cache on every node save","Disable the page cache"],answer:1,explanation:"Cache tags solve this. If the homepage render array carries the tag 'node:42', Drupal automatically invalidates it when node 42 is saved. No need to set short cache lifetimes or manually clear cache."},
]}},
{day:"Day 5",title:"Custom Cache Implementation",goal:"Implement caching in custom modules using the Cache API.",
reading:[
{title:"When to cache custom data",body:"Cache expensive operations: external API calls, complex entity queries, computed data that rarely changes. Rule: if it takes >100ms and the result doesn't change between requests, cache it.",link:null},
{title:"The Cache API",body:"$cache = \\Drupal::cache('data'); $cache->get('my_cache_key') — get cached item. $cache->set('my_cache_key', $data, Cache::PERMANENT, ['node:list']) — store with tags. $cache->invalidateTags(['node:list']) — invalidate.",link:null},
],
activity:{type:"hands_on",title:"Add caching to your NodeHelper service",intro:"Wrap your getLatestNodes method with a cache layer.",steps:[
{n:1,title:"Update NodeHelper to accept a cache backend via constructor",body:"Add CacheBackendInterface as a second constructor parameter. The cache ID (cid) is a unique string key — prefix with your module name to avoid collisions. Cache::PERMANENT means it doesn't expire by time — it only invalidates when the 'node_list' tag is cleared (which Drupal does automatically when any node is saved/deleted).",code:"<?php\n// Updated NodeHelper.php\nnamespace Drupal\\my_first_module;\n\nuse Drupal\\Core\\Cache\\Cache;\nuse Drupal\\Core\\Cache\\CacheBackendInterface;\nuse Drupal\\Core\\Entity\\EntityTypeManagerInterface;\n\nclass NodeHelper {\n\n  public function __construct(\n    protected EntityTypeManagerInterface $entityTypeManager,\n    protected CacheBackendInterface $cache,\n  ) {}\n\n  public function getLatestNodes(int $count = 5): array {\n    $cid = 'my_first_module:latest_nodes:' . $count;\n\n    // Check cache first — this is a cache HIT\n    if ($cached = $this->cache->get($cid)) {\n      return $cached->data;\n    }\n\n    // Cache MISS — run the entity query\n    $storage = $this->entityTypeManager->getStorage('node');\n    $ids = $storage->getQuery()\n      ->accessCheck(TRUE)\n      ->condition('status', 1)\n      ->sort('created', 'DESC')\n      ->range(0, $count)\n      ->execute();\n    $nodes = $storage->loadMultiple($ids);\n\n    // Store in cache with node_list tag so it invalidates when any node changes\n    $this->cache->set($cid, $nodes, Cache::PERMANENT, ['node_list']);\n\n    return $nodes;\n  }\n\n}"},
{n:2,title:"Update services.yml to inject the cache backend",body:"@cache.data is Drupal's general-purpose data cache bin. Other bins exist for specific use cases: @cache.render (render cache), @cache.bootstrap (fast config cache).",code:"# Updated my_first_module.services.yml\nservices:\n  my_first_module.node_helper:\n    class: Drupal\\my_first_module\\NodeHelper\n    arguments: ['@entity_type.manager', '@cache.data']"},
{n:3,title:"Rebuild caches",code:"ddev drush cr"},
{n:4,title:"Measure first call vs. second call timing",body:"The first call is a cache miss — it queries the database. The second call is a cache hit — it reads from cache. You should see a measurable difference.",code:"ddev drush php:eval \"\n\\$t1 = microtime(true);\n\\$r1 = \\Drupal::service('my_first_module.node_helper')->getLatestNodes(5);\n\\$t2 = microtime(true);\n\\$r2 = \\Drupal::service('my_first_module.node_helper')->getLatestNodes(5);\n\\$t3 = microtime(true);\necho 'First call (cache miss):  ' . round((\\$t2 - \\$t1) * 1000) . 'ms' . PHP_EOL;\necho 'Second call (cache hit):  ' . round((\\$t3 - \\$t2) * 1000) . 'ms' . PHP_EOL;\necho 'Results same: ' . (\\$r1 === \\$r2 ? 'YES' : 'NO') . PHP_EOL;\n\"\n# Expected: second call is significantly faster (often <1ms vs 5-20ms)"},
{n:5,title:"Verify the cache invalidates when a node is saved",body:"Save any node, then run the timing test again. The first call after a node save should be a cache miss again because Drupal invalidated the 'node_list' tag.",code:"# Save a node to trigger cache invalidation:\nddev drush php:eval \"\\$n = \\Drupal::entityTypeManager()->getStorage('node')->load(1); \\$n->save(); echo 'Node saved';\"  \n\n# Now re-run the timing test — first call should be slow again:\nddev drush php:eval \"\n\\$t1 = microtime(true);\n\\Drupal::service('my_first_module.node_helper')->getLatestNodes(5);\n\\$t2 = microtime(true);\necho 'After node save: ' . round((\\$t2 - \\$t1) * 1000) . 'ms (should be slow = cache miss)';\n\""},
],aiCheck:{prompt:"Paste your updated NodeHelper.php getLatestNodes method and the output of the timing test. Is the second call faster than the first?",checkGoal:"Verify correct cache implementation: cache->get() checks before query, cache->set() stores with node_list tag, services.yml passes @cache.data. Check that the second call is measurably faster. Give feedback on cache strategy and tag selection."}}},
{day:"Day 6",title:"Deployment, DevOps & Environment Management",goal:"Set up a professional deployment workflow for Drupal.",
reading:[
{title:"The deployment checklist",body:"Every Drupal deployment should run: git pull, composer install --no-dev, drush updb -y, drush cim -y, drush cr. Automate this. Never skip drush updb or cim on deploy.",link:null},
{title:"Coolify + AWS Lightsail for Drupal",body:"Since you already have a Coolify setup on AWS Lightsail from your MA-Portal work, Drupal can be deployed as a Docker container or via Coolify's PHP/Nginx stack. Environment variables handle per-env settings.",link:null},
{title:"settings.php per environment",body:"Use settings.local.php (excluded from Git) for local overrides. Use environment variables or platform-specific settings files for staging/prod. Never commit database credentials to Git.",link:null},
],
activity:{type:"hands_on",title:"Set up a deployment script",intro:"Create a reusable deployment script that handles the full Drupal deploy cycle.",steps:[
{n:1,title:"Create deploy.sh in your project root",body:"The set -e flag means the script stops on any error — crucial for deployments. Each step builds on the previous. The ORDER matters: always updb before cim, always cim before cr.",code:"#!/bin/bash\n# deploy.sh — Drupal deployment script\nset -euo pipefail\n\necho '==> [1/5] Pulling latest code'\ngit pull origin main\n\necho '==> [2/5] Installing Composer dependencies (no dev)'\ncomposer install --no-dev --optimize-autoloader\n\necho '==> [3/5] Running database updates'\n# updb MUST run before cim — DB updates can change schema that cim depends on\ndrush updb -y\n\necho '==> [4/5] Importing configuration'\n# cim applies your YAML config files to the active database config\ndrush cim -y\n\necho '==> [5/5] Rebuilding caches'\ndrush cr\n\necho ''\necho '✓ Deployment complete'"},
{n:2,title:"Make it executable and test locally",body:"Test the script in your local DDEV environment to make sure it runs without errors.",code:"chmod +x deploy.sh\n# Test in DDEV's SSH container:\nddev ssh\nbash /var/www/html/deploy.sh\nexit"},
{n:3,title:"Create a .env.example (commit this)",body:".env.example documents required environment variables without exposing real values. Commit this to Git. The actual .env is in .gitignore.",code:"# .env.example — commit this to Git\n# Copy to .env and fill in real values on each server\nDB_HOST=localhost\nDB_NAME=drupal\nDB_USER=drupal\nDB_PASS=\nDRUPAL_HASH_SALT=change_me_to_a_long_random_string\nAPP_ENV=production\n# Generate hash salt: php -r \"echo hash('sha256', random_bytes(32));\""},
{n:4,title:"Add Trusted Host Patterns for production",body:"Drupal requires you to whitelist the domain names the site runs on. This prevents HTTP Host header injection attacks. Add this to settings.php (not settings.local.php — it should be on prod too).",code:"# In web/sites/default/settings.php\n# Add near the bottom, before the settings.local.php include:\n\\$settings['trusted_host_patterns'] = [\n  '^yourdomain\\.com$',\n  '^www\\.yourdomain\\.com$',\n  // Add your server IP too during setup:\n  // '^123\\.45\\.67\\.89$',\n];"},
{n:5,title:"Add a maintenance mode check to the deploy script",body:"Professional deploys put the site in maintenance mode during the critical window when database updates are running.",code:"# Updated deploy.sh — add after git pull:\necho '==> Enabling maintenance mode'\ndrush state:set system.maintenance_mode 1 && drush cr\n\n# ... (other steps) ...\n\n# At the end, before final cache rebuild:\necho '==> Disabling maintenance mode'\ndrush state:set system.maintenance_mode 0\ndrush cr"},
{n:6,title:"Commit the deployment artifacts",code:"git add deploy.sh .env.example\ngit commit -m 'Add deployment script and env.example'"},
],aiCheck:{prompt:"Paste your deploy.sh script. Explain in 2-3 sentences: why does the order of commands in the deploy script matter? What would happen if you ran drush cim before drush updb?",checkGoal:"Verify correct deploy script order and understanding. Key insight: updb must run before cim because database updates may alter the schema that config import relies on. If you cim first, database updates might fail or produce inconsistencies. Give feedback on deployment strategy."}}},
{day:"Day 7",title:"Phase 5 Capstone: Headless Drupal + Next.js",goal:"Build and deploy a complete decoupled Drupal application.",
reading:[
{title:"What you're building",body:"A headless Drupal backend with your events content, JSON:API, Simple OAuth authentication, and a Next.js frontend that fetches, displays, and filters events. Deployed with a professional config workflow.",link:null},
],
activity:{type:"hands_on",title:"Full capstone build",intro:"This is your Phase 5 capstone. Build the complete decoupled stack.",steps:[
{n:1,title:"Drupal backend prep — verify events data",body:"Confirm your events content type has at least 5 events with different categories and future dates. Enable JSON:API if not already done. Test the endpoint manually before writing Next.js code.",code:"ddev drush pm:enable jsonapi -y && ddev drush cr\n# Test the events endpoint:\ncurl -s 'https://your-site.ddev.site/jsonapi/node/event?filter[status]=1&page[limit]=2' | python3 -m json.tool | head -30\n# Confirm 'data' has events. Note the UUID of one event for detail page testing."},
{n:2,title:"Configure CORS for your Next.js origin",body:"Add your Next.js dev URL and production URL to Drupal's CORS allowedOrigins.",code:"# In web/sites/default/services.yml:\ncors.config:\n  enabled: true\n  allowedHeaders: ['*']\n  allowedMethods: ['GET']\n  allowedOrigins: ['http://localhost:3000', 'https://your-nextjs-production.com']\n  exposedHeaders: false\n  maxAge: false\n  supportsCredentials: false\nddev drush cr"},
{n:3,title:"Create the Next.js events listing page",body:"Create app/events/page.tsx as a server component that fetches events from Drupal JSON:API.",code:"// drupal-frontend/app/events/page.tsx\nconst DRUPAL_URL = process.env.DRUPAL_BASE_URL ?? 'https://your-site.ddev.site';\n\nexport default async function EventsPage() {\n  const res = await fetch(\n    `${DRUPAL_URL}/jsonapi/node/event?filter[status]=1&sort=field_event_date` +\n    `&fields[node--event]=title,field_event_date,field_location,path` +\n    `&page[limit]=20`,\n    { next: { revalidate: 300 } }\n  );\n  const { data } = await res.json();\n\n  return (\n    <main style={{ maxWidth: '900px', margin: '0 auto', padding: '2rem' }}>\n      <h1>Upcoming Events</h1>\n      {data.map((event: any) => (\n        <article key={event.id} style={{ borderBottom: '1px solid #eee', marginBottom: '1.5rem', paddingBottom: '1.5rem' }}>\n          <h2>\n            <a href={event.attributes.path?.alias ?? `/events/${event.id}`}>\n              {event.attributes.title}\n            </a>\n          </h2>\n          <p>\n            {event.attributes.field_event_date?.value\n              ? new Date(event.attributes.field_event_date.value).toLocaleDateString()\n              : 'Date TBD'}\n            {event.attributes.field_location ? ` — ${event.attributes.field_location}` : ''}\n          </p>\n        </article>\n      ))}\n    </main>\n  );\n}"},
{n:4,title:"Create event detail pages with generateStaticParams",body:"Create the [slug] dynamic route for individual event pages. generateStaticParams pre-generates all event pages at build time.",code:"// drupal-frontend/app/events/[slug]/page.tsx\nconst DRUPAL_URL = process.env.DRUPAL_BASE_URL ?? 'https://your-site.ddev.site';\n\nexport async function generateStaticParams() {\n  const res = await fetch(`${DRUPAL_URL}/jsonapi/node/event?fields[node--event]=path&page[limit]=100`);\n  const { data } = await res.json();\n  return data\n    .filter((e: any) => e.attributes.path?.alias)\n    .map((e: any) => ({ slug: e.attributes.path.alias.replace('/events/', '') }));\n}\n\nexport default async function EventPage({ params }: { params: { slug: string } }) {\n  const res = await fetch(\n    `${DRUPAL_URL}/jsonapi/node/event?filter[path.alias]=/events/${params.slug}` +\n    `&fields[node--event]=title,field_event_date,field_location,body`,\n    { next: { revalidate: 300 } }\n  );\n  const { data } = await res.json();\n  const event = data[0];\n\n  if (!event) return <main><p>Event not found.</p></main>;\n\n  return (\n    <main style={{ maxWidth: '800px', margin: '0 auto', padding: '2rem' }}>\n      <h1>{event.attributes.title}</h1>\n      {event.attributes.body && (\n        <div dangerouslySetInnerHTML={{ __html: event.attributes.body.processed }} />\n      )}\n    </main>\n  );\n}"},
{n:5,title:"Run and test the full app locally",code:"npm run dev\n# Visit http://localhost:3000/events\n# Click an event — the detail page should load"},
{n:6,title:"Write an ARCHITECTURE.md",body:"Document your system so a new developer could understand and run it in 30 minutes. Cover: Drupal setup, Next.js setup, how they connect, environment variables, deployment steps.",code:"# Create ARCHITECTURE.md in drupal-frontend/\ncat > ARCHITECTURE.md << 'EOF'\n# Architecture\n\n## Drupal Backend\n- Version: 10.x with DDEV\n- Key modules: JSON:API, Pathauto, Paragraphs\n- Content types: Article, Event, Landing Page\n\n## Next.js Frontend\n- App Router (Next.js 14+)\n- Fetches from Drupal JSON:API\n- Server components for all data fetching\n\n## Integration\n- CORS configured in Drupal services.yml\n- DRUPAL_BASE_URL env variable connects the apps\n\n## Environment variables\n- DRUPAL_BASE_URL: base URL of the Drupal site\nEOF"},
],aiCheck:{prompt:"Describe your completed capstone: (1) What endpoints does your Next.js app call? (2) How did you handle the CORS setup? (3) Is it deployed? Share the URL if yes. (4) What was the hardest part?",checkGoal:"Evaluate the Phase 5 capstone. Key checks: Next.js is actually fetching from Drupal JSON:API, events are displayed and linked to detail pages, student understands the decoupled architecture. Give comprehensive feedback on the full-stack Drupal architecture."}}},
]},
{label:"Week 2",name:"Advanced caching, multisite & exam prep",days:[
{day:"Day 8",title:"Varnish & Reverse Proxy Caching",goal:"Understand reverse proxy caching and how Drupal integrates with Varnish.",
reading:[
{title:"What Varnish does",body:"Varnish sits in front of Drupal and caches entire HTTP responses. Anonymous page requests are served directly from Varnish without hitting PHP or the database — extremely fast.",link:null},
{title:"Surrogate keys / cache tags",body:"Drupal sends cache tags as HTTP response headers (X-Drupal-Cache-Tags). Varnish stores these. When a node is saved, Drupal calls Varnish to purge all pages carrying that node's cache tag.",link:null},
{title:"Purge module",body:"The Purge module (contrib) provides the infrastructure for Drupal to communicate invalidations to Varnish and CDNs. Essential for production Drupal with external caching.",link:"https://www.drupal.org/project/purge"},
],
activity:{type:"quiz",questions:[
{q:"Drupal is configured with Varnish. An anonymous user visits /events and gets a cached response. You then update an event node. How does the /events page get invalidated automatically?",options:["It doesn't — you must manually clear Varnish","Drupal sends the node's cache tags to Varnish via the Purge module, which invalidates all cached pages carrying that tag","Varnish automatically polls Drupal every minute","The page cache lifetime expires after 5 minutes"],answer:1,explanation:"Cache tags + Purge module = automatic, surgical invalidation. When the event node saves, Drupal emits an invalidation for 'node:42'. Purge sends this to Varnish, which purges all cached responses tagged with node:42 — including /events."},
{q:"A client complains that logged-in users sometimes see cached pages meant for other users. What cache concept is misconfigured?",options:["Cache tags are not set correctly","Cache contexts are missing or wrong — the cache doesn't include a 'user' or 'session' context","The cache lifetime is too long","Varnish is serving all content instead of bypassing for logged-in users"],answer:1,explanation:"Varnish should never cache authenticated requests — the standard config passes cookies to Drupal for logged-in users. If logged-in users see other users' content, cache contexts are missing (should include 'user' context) or Varnish is incorrectly caching authenticated sessions."},
]}},
{day:"Day 9",title:"Performance Profiling",goal:"Identify and fix performance bottlenecks in Drupal applications.",
reading:[
{title:"Common Drupal performance issues",body:"N+1 queries (loading entities one by one in a loop), uncached expensive computations, missing indexes on custom tables, Views without proper caching, large media files without image styles.",link:null},
{title:"Profiling tools",body:"<strong>Devel module</strong>: shows query count and execution times per page. <strong>Xhprof/Blackfire</strong>: full PHP profiler. <strong>Drupal's built-in slow query log</strong>: logs queries over a threshold. <strong>Lighthouse</strong>: frontend performance.",link:null},
{title:"Views performance",body:"Every Views query should have: a result cache enabled, proper use of relationships (avoid loading all related entities), paging limits, and database indexes on filtered fields.",link:null},
],
activity:{type:"hands_on",title:"Profile and optimize a slow page",intro:"Use Devel to find query bottlenecks on your site.",steps:[
{n:1,title:"Install and enable the Devel module",body:"Devel is a developer tool — install as a dev dependency. It exposes query logging, variable dumping (kint), and PHP info.",code:"ddev composer require drupal/devel --dev\nddev drush pm:enable devel -y && ddev drush cr"},
{n:2,title:"Enable the query log",body:"Go to Admin → Config → Development → Devel settings. Check 'Display query log'. Set 'Slow query threshold' to 100 (ms). Save. Now every page load will show a query log at the bottom."},
{n:3,title:"Create a slow scenario — load a page with many entities",body:"Visit an Article detail page or your /articles listing with several items. Scroll to the bottom of the page — you'll see the Devel query log with every query that ran and how long each took.",code:"# Visit: https://your-site.ddev.site/articles\n# Scroll to bottom — Devel query log will appear\n# Note:\n# - Total query count\n# - Any queries over 100ms\n# - Repeated similar queries (N+1 pattern)"},
{n:4,title:"Identify the N+1 pattern",body:"Look for groups of very similar queries that differ only by ID. For example: 'SELECT * FROM node WHERE nid = 1', 'SELECT * FROM node WHERE nid = 2', etc. This is the N+1 anti-pattern — loading entities one at a time in a loop instead of using loadMultiple()."},
{n:5,title:"Enable Views result caching",body:"One of the biggest query reducers for Views pages. Go to Admin → Structure → Views → edit your Articles view. Click 'Advanced' tab. Under Caching, click the 'None' link next to 'Query results'. Change to 'Time-based'. Set cache duration to 1 hour. Save.",code:"# Also via drush — list views:\nddev drush views:list"},
{n:6,title:"Measure before and after caching",body:"Compare query counts with Views caching disabled vs enabled. With caching enabled, a cached page should have far fewer queries.",code:"# Visit /articles twice — first load builds cache, second load reads from cache\n# Compare query counts in the Devel log:\n# First load (cache miss): N queries\n# Second load (cache hit): should be significantly fewer queries"},
{n:7,title:"Check a custom module for the N+1 pattern",body:"If you have code that loads entities one at a time in a loop, refactor it to use loadMultiple().",code:"# BAD pattern (N+1):\n# foreach ($node_ids as $nid) {\n#   $node = \\Drupal::entityTypeManager()->getStorage('node')->load($nid);\n# }\n\n# GOOD pattern:\n$nodes = \\Drupal::entityTypeManager()->getStorage('node')->loadMultiple($node_ids);\n\n# Test that your code uses the good pattern:\nddev drush php:eval \"\n\\$t1 = microtime(true);\n\\$storage = \\Drupal::entityTypeManager()->getStorage('node');\n\\$ids = \\$storage->getQuery()->accessCheck(TRUE)->condition('status',1)->range(0,10)->execute();\n\\$nodes = \\$storage->loadMultiple(\\$ids); // ONE query for all 10\n\\$t2 = microtime(true);\necho count(\\$nodes) . ' nodes loaded in ' . round((\\$t2-\\$t1)*1000) . 'ms (1 query)';\n\""},
],aiCheck:{prompt:"What did you find in the Devel query log? How many queries on the page? Were any slow? What optimization did you make and what was the before/after query count?",checkGoal:"Evaluate the student's performance profiling experience. Key insights: Views result caching reduces queries significantly, query count is a useful performance proxy, N+1 patterns appear as many similar queries. Give feedback on performance optimization strategy."}}},
{day:"Day 10",title:"Multisite Configuration",goal:"Understand Drupal's multisite feature for managing multiple sites from one codebase.",
reading:[
{title:"What multisite is",body:"Drupal can serve multiple sites from one codebase. Each site has its own database, files directory, and settings.php. The sites/sites.php file maps hostnames to site directories.",link:"https://www.drupal.org/docs/multisite-drupal"},
{title:"sites/sites.php",body:"Maps hostnames to site folder names: $sites['site2.example.com'] = 'site2'; Drupal reads settings from sites/site2/settings.php and uses site2's database.",link:null},
{title:"When to use multisite",body:"Use for: agency managing multiple client sites on one server, white-label product with shared features, franchise networks. Avoid if sites diverge significantly — separate codebases are cleaner long-term.",link:null},
],
activity:{type:"quiz",questions:[
{q:"You're running a Drupal multisite with 3 sites. Site A gets a security update to a custom module. What happens to sites B and C?",options:["Nothing — each site has its own module files","Since all sites share the same codebase, the update applies to all three immediately","You must update each site separately","Only Site A gets the update unless you manually copy files"],answer:1,explanation:"This is both the power and the risk of multisite. A codebase change affects all sites simultaneously. This means security patches deploy everywhere instantly — but it also means a breaking change breaks all sites. Test thoroughly before deploying to a multisite production environment."},
]}},
{day:"Day 11",title:"Acquia Certification Exam Prep",goal:"Map your learning to Acquia certification domains and identify gaps.",
reading:[
{title:"Certification path recap",body:"Site Builder: Phase 1-2 content. Developer: Phases 1-4. Front-end Specialist: Phases 1, 4. Back-end Specialist: Phases 1, 3, 5. Triple Expert: all three specialist certs (no extra exam).",link:"https://www.acquia.com/support/training-certification/acquia-certification"},
{title:"Exam format",body:"All exams are scenario-based multiple choice. Questions describe a situation and ask which approach is best. You need real project experience — the exams test judgment, not just knowledge.",link:null},
{title:"Free prep resources",body:"Acquia Academy (free tier), Drupalize.Me certification guides, the official study guides on docs.acquia.com, and the Drupal API reference for specific function knowledge.",link:null},
],
activity:{type:"ai_open",prompt:"Certification readiness self-assessment: Answer these five scenario-based questions as if you were in the actual exam. (1) A client's editorial team needs to manage events but should NOT be able to change the site's theme or install modules. How do you configure this in Drupal? (2) You need to display a list of the 5 most recent articles by the current user on their profile page. What combination of Drupal tools would you use? (3) A custom module's hook_node_presave is running but the changes to the node aren't persisting after save. What are two likely causes? (4) Your JSON:API endpoint for articles is returning all fields including sensitive internal notes. How do you restrict which fields are exposed? (5) A page is slow. You add Devel and see 150 database queries. What common Drupal anti-pattern causes this and how do you fix it?",checkGoal:"Evaluate certification readiness with scenario-based questions. Key answers: (1) custom role with editorial permissions, deny admin permissions; (2) Views with contextual filter for current user; (3) not calling $node->save() again (in presave you modify but don't save, Drupal saves after the hook) OR incorrect field API usage; (4) JSON:API field access control or disabling specific fields via resource type settings; (5) N+1 queries from loading entities in a loop — use entityQuery + loadMultiple instead. Score each answer 0-2 and give total out of 10."}},
{day:"Day 12",title:"Full Path Retrospective & Next Steps",goal:"Reflect on the complete learning journey and plan your certification path.",
reading:[
{title:"What you've built",body:"A complete foundation: local environment, custom modules, site building, custom theming, decoupled API, caching, deployment. This is the knowledge base for all five Acquia certifications.",link:null},
{title:"What comes next",body:"Real projects. The certifications reward experience with real-world scenarios. Take on 2-3 Drupal freelance or personal projects before sitting exams. Contribute to drupal.org. Join the Drupal Slack.",link:null},
{title:"Zero One Byte angle",body:"Drupal expertise is a strong differentiator for your agency. Enterprise clients (government, universities, large NGOs) actively seek Drupal developers. Acquia certifications signal professional credibility in those markets.",link:null},
],
activity:{type:"ai_open",prompt:"Final reflection — answer all four: (1) Which certification will you pursue first and why? Map your current knowledge gaps to the exam domains for that cert. (2) What are the three most important Drupal concepts you learned in this entire program, and why did each matter? (3) You're pitching Drupal to a potential Zero One Byte client who is currently on WordPress. What's your pitch? (4) Describe the architecture of the most complex Drupal site you'd feel confident building right now — content types, modules, theming approach, API strategy, and deployment.",checkGoal:"Evaluate the student's overall program completion and strategic thinking. Look for: realistic certification sequencing, genuine reflection on key concepts (not just listing topics), a compelling WP-to-Drupal pitch relevant to their agency context, and an ambitious but realistic site architecture. Give encouraging, specific, comprehensive feedback to close out the entire program. Acknowledge their achievement."}},
]},
]},
];;
